-- Poems batch 227
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('7c52e527-ebd2-47f2-a125-954a19423add','四用出郊韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','一望平湖萬頃連，恍如身在鷲峰前。',64,'全唐诗/poet.song.209000.json','["一望平湖萬頃連，恍如身在鷲峰前。", "築塗成宅能移地，疊石爲山欲奪天。", "綠萼枝方停曉鳳，白楊樹已咽寒蟬。", "達人大觀緣如此，萬事都來付且然。"]'),
('9d7198f8-dff1-437f-a656-360ab54b54f1','五用出郊韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','寄語頭銜水利官，隄防莫作等閑看。',64,'全唐诗/poet.song.209000.json','["寄語頭銜水利官，隄防莫作等閑看。", "田疇雖幸收成早，溝澮猶疑灌溉殘。", "勸課農桑心獨苦，丁寧父老吻應乾。", "米從布袋癡兒事，我輩須知稼穡難。"]'),
('72acab4b-71fa-4713-9197-73b7e8b9e746','五用出郊韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','看他南畝十分收，歸去來兮事尚悠。',64,'全唐诗/poet.song.209000.json','["看他南畝十分收，歸去來兮事尚悠。", "夢裏便尋青櫟社，生來幾過白蘋洲。", "向前七袠無多歲，更後三朝即半秋。", "如電如陰如幻境，還知生熟路頭不。"]'),
('d8ea371b-ecae-431c-92c1-143f7cb24c19','五用出郊韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','冥鴻本擬與雞連，一笑西風沆瀣前。',64,'全唐诗/poet.song.209000.json','["冥鴻本擬與雞連，一笑西風沆瀣前。", "放步退來元有地，從頭算去莫非天。", "可憐高舉摶風翮，爭似低飛飲露蟬。", "若使危機能徹底，盈虛消息豈其然。"]'),
('9c1a751a-ecf5-4abc-b7a0-b784a67c3804','劭農翠山賦唐律二首  其一','吳潛','宋','宋诗','song-poetry','','[]','小隊旌旗上翠巖，松風十里鎖禪關。',64,'全唐诗/poet.song.209000.json','["小隊旌旗上翠巖，松風十里鎖禪關。", "水深水淺高低澗，春淡春濃遠近山。", "鄉思猛隨蒼鳥去，客心暫與白雲閑。", "天公已是多情殺，特把淋頭雨放慳。"]'),
('6b38c0e8-3b7c-45e2-b857-c4d346c92b9c','劭農翠山賦唐律二首  其二','吳潛','宋','宋诗','song-poetry','','[]','老守憂民若己傷，三回奉詔勸耕桑。',64,'全唐诗/poet.song.209000.json','["老守憂民若己傷，三回奉詔勸耕桑。", "周家綿遠農開國，漢室興隆穀腐倉。", "麥緣少地鋤山種，水怕多流纍石防。", "田里熙熙知樂土，更祈四表共平康。"]'),
('09f38c55-b7cb-40c1-83f1-a478b2d1a114','梅花小吟','吳潛','宋','宋诗','song-poetry','','[]','難喚林逋伴客遊，占春亭畔獨夷猶。',64,'全唐诗/poet.song.209000.json','["難喚林逋伴客遊，占春亭畔獨夷猶。", "一花兩蘂意方遠，三島十洲香已浮。", "清曉園林霜似練，黄昏欄檻月如鈎。", "若還說著和羹事，只恐渠儂笑不休。"]'),
('ace8a49a-c6b2-428d-9e96-5e5269bef776','占春亭即事三首  其一','吳潛','宋','宋诗','song-poetry','','[]','桃花幾片隔牆飛，獨自危樓徙倚時。',32,'全唐诗/poet.song.209000.json','["桃花幾片隔牆飛，獨自危樓徙倚時。", "目送斷鴻雲外沒，東風吹淚落天涯。"]'),
('5b9fe3d4-d1e8-4d37-a2cd-16c0f7be1633','占春亭即事三首  其二','吳潛','宋','宋诗','song-poetry','','[]','見他門戶插垂楊，懊恨江南客子腸。',32,'全唐诗/poet.song.209000.json','["見他門戶插垂楊，懊恨江南客子腸。", "春夢誰云無準托，連宵合眼是家鄉。"]'),
('dcdd0ea0-595e-4ece-a3c4-4c768743f819','占春亭即事三首  其三','吳潛','宋','宋诗','song-poetry','','[]','薄霧輕煙柳際浮，階前細草綠初抽。',32,'全唐诗/poet.song.209000.json','["薄霧輕煙柳際浮，階前細草綠初抽。", "年年春事年年恨，一擔擔來是白頭。"]'),
('cc5a2615-92f0-4227-a6c0-6a166471d3ce','鄉舉鹿鳴勸駕','吳潛','宋','宋诗','song-poetry','','[]','上苑春光已探來，諸公逸駕莫遲回。',64,'全唐诗/poet.song.209000.json','["上苑春光已探來，諸公逸駕莫遲回。", "點頭定有文驚坐，燒尾何妨酒吸杯。", "自是功名難躲避，須知氣節要壅培。", "老夫親手傳衣鉢，來歲圖經用再開。"]'),
('014e2c96-dcda-4fe5-b5f7-66126411e165','諸路發解勸駕','吳潛','宋','宋诗','song-poetry','','[]','東郡衣冠盛，南宮牓帖新。',48,'全唐诗/poet.song.209000.json','["東郡衣冠盛，南宮牓帖新。", "諸科唐取士，數路漢得人。", "鳴鹿殷勤意，攀龍變化身。", "若爲明主獻，忠讜要披陳。"]'),
('fcaf5350-0779-4154-8e7a-62b858251888','和景回胡計院數字韻就送其行','吳潛','宋','宋诗','song-poetry','','[]','與君託鄉閭，東野連西墅。',120,'全唐诗/poet.song.209000.json','["與君託鄉閭，東野連西墅。", "誰知俯仰閒，各各歲年暮。", "當時同隊魚，十已九捐故。", "君抱珪璧姿，方獲展寸步。", "梁棟須羣材，榱桷共支拄。", "生從匠石園，一一居王所。", "何必效鷗鳬，江湖任來去。", "但須飽讀易，細翫奇耦數。", "問之何將迎，終然抱璞素。", "砥柱三門津，波瀾自流注。"]'),
('dafc521e-58ba-4092-858b-0530db876bd7','窺園','吳潛','宋','宋诗','song-poetry','','["\u897f\u6e56"]','後園梅樹老槎牙，初放枝頭一兩花。',64,'全唐诗/poet.song.209000.json','["後園梅樹老槎牙，初放枝頭一兩花。", "便是春光先漏洩，其如暮景已橫斜。", "西湖處士吟情在，東里先生心事賒。", "清足亭前無限好，五更魂夢定還家。"]'),
('98fedc34-f39b-4786-9d39-2d2da4858c00','小至三詩呈景回制幹并簡同官  其一','吳潛','宋','宋诗','song-poetry','','[]','六十三餘七十翁，頗從靜裏得些工。',64,'全唐诗/poet.song.209000.json','["六十三餘七十翁，頗從靜裏得些工。", "陰陽理向塵塵見，天地心於物物同。", "荔挺生來元不死，葭灰塞處自能通。", "古今宇宙渾如此，康節何煩企下風。"]'),
('a7c48291-da45-43de-851c-ab64019e460b','小至三詩呈景回制幹并簡同官  其二','吳潛','宋','宋诗','song-poetry','','[]','莫嫌一點稚陽微，化育工夫自此推。',64,'全唐诗/poet.song.209000.json','["莫嫌一點稚陽微，化育工夫自此推。", "履襪已無親可獻，黍羔猶與俗相宜。", "數千里外縈心事，四五更頭欹枕時。", "懇懇對天香一炷，定知人願必天隨。"]'),
('ccd69ad3-dd8f-4e4f-ad1b-5c5cdfabf5b6','小至三詩呈景回制幹并簡同官  其三','吳潛','宋','宋诗','song-poetry','','[]','勸君莫望楚雲飛，一片雲飛兩淚垂。',64,'全唐诗/poet.song.209000.json','["勸君莫望楚雲飛，一片雲飛兩淚垂。", "去歲尚傳鴻雁信，今年空念鶺鴒詩。", "大刀折處心尤苦，半臂添來體更羸。", "鼓笛謾將廳事聒，誰知裏面有人悲。"]'),
('e4885a18-3a50-4fb7-961a-ad748af1b4b7','喜雪用禁物體二首  其一','吳潛','宋','宋诗','song-poetry','','[]','傍海風癡翦水難，偷他瑞葉散雲端。',64,'全唐诗/poet.song.209000.json','["傍海風癡翦水難，偷他瑞葉散雲端。", "可須滕巽同宣力，坐使顓冥不曠官。", "衣被麥苗攙臘到，裝褫花樹借春看。", "明年定賽今年熟，野老心腴更體胖。"]'),
('029de3a2-6dec-4dde-a0be-c6f1159e9965','喜雪用禁物體二首  其二','吳潛','宋','宋诗','song-poetry','','[]','一帳誰將罩太虛，但憐雁字不堪書。',64,'全唐诗/poet.song.209000.json','["一帳誰將罩太虛，但憐雁字不堪書。", "江山盡在光華裏，宇宙真成渾沌初。", "險地豈容呈坎壈，荒林無復露空疎。", "休將入蔡功名詫，思播新聞却衆狙。"]'),
('6ca6265a-26a7-4856-ae87-6ddb55c6fb0f','再用前韻二首  其一','吳潛','宋','宋诗','song-poetry','','[]','翦水工夫入細難，篩塵屑末粲豪端。',64,'全唐诗/poet.song.209000.json','["翦水工夫入細難，篩塵屑末粲豪端。", "司寒便合修年譜，凌室何妨踐世官。", "惠可立時師受記，焦先卧處衆爭看。", "只緣一竅丹成熟，四體那拘瘠與胖。"]'),
('e3318778-757d-4736-a411-720d757e02bd','再用前韻二首  其二','吳潛','宋','宋诗','song-poetry','','[]','中夜懷歸夢趁虛，柰無黄耳寄家書。',64,'全唐诗/poet.song.209000.json','["中夜懷歸夢趁虛，柰無黄耳寄家書。", "高人不問閉門後，征士應思遣戍初。", "壓棟排簷能拉朽，穿簾入隙解乘疎。", "遥知山谷皆封路，食絕腸饑有怒狙。"]'),
('66c43bef-6ee6-43b0-9603-60fe04023f2a','三用喜雪韻呈同官諸丈不敢輟禁物之令也二首  其一','吳潛','宋','宋诗','song-poetry','','[]','不用憂他道路難，渾淪宇宙杳無端。',64,'全唐诗/poet.song.209000.json','["不用憂他道路難，渾淪宇宙杳無端。", "齊腰若未能逃佛，滅迹何妨且棄官。", "節士挺身松柏比，田翁滿眼稻粱看。", "明年飽喫宣州飯，管取便便此腹胖。"]'),
('9ed5a4e5-7051-481a-b0bb-40971f22e0ab','三用喜雪韻呈同官諸丈不敢輟禁物之令也二首  其二','吳潛','宋','宋诗','song-poetry','','[]','光浮暗室不因虛，凍筆難呵且罷書。',64,'全唐诗/poet.song.209000.json','["光浮暗室不因虛，凍筆難呵且罷書。", "可是羞明宜夜後，何妨等伴到春初。", "累茵合念閭閻苦，返棹非於故舊疎。", "堪笑老禪功用狹，但能分食飼猨狙。"]'),
('e18133bb-bc93-404b-970b-b458d45c34c3','四五用喜雪韻四首  其一','吳潛','宋','宋诗','song-poetry','','[]','不數玄真與木難，也休翦綵綴林端。',64,'全唐诗/poet.song.209000.json','["不數玄真與木難，也休翦綵綴林端。", "五車自有神朝闕，萬寶非因賈送官。", "老大已殘洄曲夢，推敲且作灞陵看。", "忍寒袖手青燈畔，解字閑書胖與胖。"]'),
('676abf83-fb93-49c4-96a4-ca7dded2c5db','四五用喜雪韻四首  其二','吳潛','宋','宋诗','song-poetry','','[]','富貴家家遣五虛，不須乞米效顔書。',64,'全唐诗/poet.song.209000.json','["富貴家家遣五虛，不須乞米效顔書。", "垢除與物重更始，朴散于今暫復初。", "狡兔迷藏罝謾設，游魚潛伏網應疎。", "此恩箇箇當沾被，莫逐林閒竊芋狙。"]'),
('f6ebd1ab-e026-4a22-bf9a-ce51b7a375a4','四五用喜雪韻四首  其三','吳潛','宋','宋诗','song-poetry','','[]','戰退妖狐是不難，飛毛散羽息爭端。',64,'全唐诗/poet.song.209000.json','["戰退妖狐是不難，飛毛散羽息爭端。", "甕眠但願爲逋客，靴沒何須慕大官。", "化化形形隨物付，平平坦坦與人看。", "閉門獨有袁夫子，窮餓難磨氣象胖。"]'),
('65899e1b-44b7-4d4d-bc54-7797c228fc21','四五用喜雪韻四首  其四','吳潛','宋','宋诗','song-poetry','','[]','覆蓋無分實與虛，太平有象史官書。',64,'全唐诗/poet.song.209000.json','["覆蓋無分實與虛，太平有象史官書。", "園林底用誇末至，山水惟應訪遂初。", "潤到青蔬尤脆美，老添蒼檜更扶疎。", "是中廣莫天同大，□□何妨有傲狙。"]'),
('e935d909-27f3-4169-b641-e096c3311ae9','六用喜雪韻二首  其一','吳潛','宋','宋诗','song-poetry','','[]','白戰從來號令難，不知此令孰抽端。',64,'全唐诗/poet.song.209000.json','["白戰從來號令難，不知此令孰抽端。", "開倉自有齊相國，排戶何煩漢縣官。", "坐覺閻浮塵世隔，便同佛度化成看。", "遥思蘇武囚深窖，氣力雖微志自胖。"]'),
('4fc5a0b9-d106-4d5d-9d51-d3294da0cd85','六用喜雪韻二首  其二','吳潛','宋','宋诗','song-poetry','','[]','梵宮樓閣正橫虛，俯瞰平疇一幅書。',64,'全唐诗/poet.song.209000.json','["梵宮樓閣正橫虛，俯瞰平疇一幅書。", "宿鳥投林迷所自，野貛尋穴失其初。", "茅柴熟處功非細，榾柮燒來計未疎。", "回首少年觀校獵，忽飛一騎射山狙。"]'),
('f6d5c98a-9547-4195-a9d6-f0573771b877','七八用喜雪韻四首  其一','吳潛','宋','宋诗','song-poetry','','[]','不持寸鐵事應難，何止空空竭兩端。',64,'全唐诗/poet.song.209000.json','["不持寸鐵事應難，何止空空竭兩端。", "遠麓遮藏山被檄，輕冰裁翦水能官。", "將梁兔苑瀛洲比，把蔡鶩池臺閣看。", "獨羨當年灰袋客，雪埋氣宇更充胖。"]'),
('a2b422da-1768-4b82-9244-c9e4582655fe','七八用喜雪韻四首  其二','吳潛','宋','宋诗','song-poetry','','[]','鏖戰邪川正瞰虛，庚牌裹雪發軍書。',64,'全唐诗/poet.song.209000.json','["鏖戰邪川正瞰虛，庚牌裹雪發軍書。", "光摇闕角更傳後，色眩觚稜月上初。", "大抵衣袽須早戒，莫教戶牖有時疎。", "喜聞庸蜀羣尨吠，辟易何分玃與狙。"]'),
('dc6531a4-fbf8-4b45-a7c0-6664efe6463e','七八用喜雪韻四首  其三','吳潛','宋','宋诗','song-poetry','','[]','也知天女散花難，束帛戔戔幾疋端。',64,'全唐诗/poet.song.209000.json','["也知天女散花難，束帛戔戔幾疋端。", "富貴何妨還白屋，繁華亦欲傲蒼官。", "梁山操裏聲愁聽，湘水圖中景喜看。", "爭似寒爐煨芋者，身心何處不休胖。"]'),
('7adf17d2-026a-4360-b1ab-1f360cbf9f96','七八用喜雪韻四首  其四','吳潛','宋','宋诗','song-poetry','','[]','有年呈瑞厭孤虛，不用東封更獻書。',64,'全唐诗/poet.song.209000.json','["有年呈瑞厭孤虛，不用東封更獻書。", "雁背嚴凝能備預，鵲搜儲蓄善謀初。", "併衣左伯情何厚，穿履東方計莫疎。", "聞說山林皆凍合，徧狙無處覓雄狙。"]'),
('ae80bcbd-6a0b-4f81-a486-0d1e5cf3fc6e','九十用喜雪韻四首  其一','吳潛','宋','宋诗','song-poetry','','[]','不用韓非騁說難，異同堅白謾多端。',64,'全唐诗/poet.song.209000.json','["不用韓非騁說難，異同堅白謾多端。", "恍迷千界現梵國，駢集萬妃驅女官。", "要得彘生將罟沒，恐他鼉怪作城看。", "道人宴坐蒲團上，外景常如內景胖。"]'),
('b7c94a9a-5e33-4670-89dc-c61a41bc6ca5','九十用喜雪韻四首  其二','吳潛','宋','宋诗','song-poetry','','[]','臘中三白瑞非虛，不慮無冰魯史書。',64,'全唐诗/poet.song.209000.json','["臘中三白瑞非虛，不慮無冰魯史書。", "薹長新蔬蒙賜後，根舒宿麥受恩初。", "憑陵敗絮寒能重，撲蔌斜窗曉漸疎。", "林杪窮猿應禁口，猢孫乞食向公狙。"]'),
('5dbbdc46-8c2a-4db7-a2e9-ecc7bfbfd066','九十用喜雪韻四首  其三','吳潛','宋','宋诗','song-poetry','','[]','今歲鏖寒亦大難，裁裘製褐費無端。',64,'全唐诗/poet.song.209000.json','["今歲鏖寒亦大難，裁裘製褐費無端。", "旋添酒興嫌工正，旁索詩材喜稗官。", "見晛未消亭午待，加霜更潔翌朝看。", "遥憐掃巷歡娛輩，大體何知小體胖。"]'),
('980e81d7-7fbd-4451-bd71-a4232679ab82','九十用喜雪韻四首  其四','吳潛','宋','宋诗','song-poetry','','[]','陳年古屋瓦浮虛，穿漏時將被覆書。',64,'全唐诗/poet.song.209000.json','["陳年古屋瓦浮虛，穿漏時將被覆書。", "集謝曾陪上相後，映孫難忘秀才初。", "磚花似鏤多奇異，簷柱如排少闊疎。", "吏卒報衙天未曉，老身牽强類冠狙。"]'),
('98a01132-4bdb-46ac-9245-6a0de241d877','十一二用喜雪韻四首  其一','吳潛','宋','宋诗','song-poetry','','[]','水潑衾裘夜卧難，也休暖足喚端端。',64,'全唐诗/poet.song.209000.json','["水潑衾裘夜卧難，也休暖足喚端端。", "平生自是冰爲氏，此際何妨火紀官。", "無色圖從天地展，有聲畫與古今看。", "忽思十萬邊兵冷，膚體相關豈獨胖。"]'),
('635544c5-14f9-445d-a232-c0028400ec14','十一二用喜雪韻四首  其二','吳潛','宋','宋诗','song-poetry','','[]','片片穿帷解擣虛，夜明細字亦堪書。',64,'全唐诗/poet.song.209000.json','["片片穿帷解擣虛，夜明細字亦堪書。", "五車現瑞從今後，一尺呈祥復古初。", "暖室溫軒人起晏，遠坊窮巷客來疎。", "茅山見說黄精熟，山友迷蹤饜黠狙。"]'),
('c049d68e-cec7-46a1-804d-cdc144f3843e','十一二用喜雪韻四首  其三','吳潛','宋','宋诗','song-poetry','','[]','長安貧者再炊難，臛肉蒼頭飫舌端。',64,'全唐诗/poet.song.209000.json','["長安貧者再炊難，臛肉蒼頭飫舌端。", "食雪自應還猛將，飲冰只合付清官。", "尚興塞外鳴弦想，賸欲江頭把釣看。", "只恐逢他吹鐵笛，骨寒股戰失吾胖。"]'),
('23917161-c0db-40e9-85d9-35f177673f1f','十一二用喜雪韻四首  其四','吳潛','宋','宋诗','song-poetry','','[]','只堪閉戶著潜虛，欲作遨頭畏簡書。',64,'全唐诗/poet.song.209000.json','["只堪閉戶著潜虛，欲作遨頭畏簡書。", "乍密乍稀雲凍後，半融半落雨收初。", "封條正恐觀梅錯，漬穀猶疑學稼疎。", "却喜明朝春稅駕，氣甦𥜿𥜿與狙狙。"]'),
('2676f069-5bf1-4397-8515-26ed38c8bb51','十三四用喜雪韻四首  其一','吳潛','宋','宋诗','song-poetry','','[]','安西都護肯辭難，不怕亡胡起怨端。',64,'全唐诗/poet.song.209000.json','["安西都護肯辭難，不怕亡胡起怨端。", "節義士知堪作使，神仙人豈戀爲官。", "寒肩此際如樓聳，眩眼當年似席看。", "百丈山中誰築室，是中非隘亦非胖。"]'),
('453f2d61-7112-4807-ae4b-6118c2adba1e','十三四用喜雪韻四首  其二','吳潛','宋','宋诗','song-poetry','','[]','瑞氣應纏牛女虛，坐令三白歷家書。',64,'全唐诗/poet.song.209000.json','["瑞氣應纏牛女虛，坐令三白歷家書。", "竹寒不用歌周末，粟腐行將紀漢初。", "蟠際混同能廣大，方圓成就更通疎。", "狐猿夜半疑天曉，叫起攀林掛樹狙。"]'),
('cbd41dd4-ef3d-4d1d-bb7c-ad91a1a459d4','十三四用喜雪韻四首  其三','吳潛','宋','宋诗','song-poetry','','[]','普博誰云仁道難，翦裁妙巧智之端。',64,'全唐诗/poet.song.209000.json','["普博誰云仁道難，翦裁妙巧智之端。", "都將凡物換英物，盡欲熱官成冷官。", "色即是空隨手滅，恩生於害轉頭看。", "大千界裏毫光徹，稽首惟應禮屈胖。"]'),
('b209e8ea-ffbb-439c-90df-5f700c250f66','十三四用喜雪韻四首  其四','吳潛','宋','宋诗','song-poetry','','[]','雪邊好景說涵虛，欲往從之掣簿書。',64,'全唐诗/poet.song.209000.json','["雪邊好景說涵虛，欲往從之掣簿書。", "王道平平須有象，皇風浩浩恐無初。", "舉遮正恐渠難耐，罷掃緣憂彼作疎。", "翠浪黄雲來歲事，已應癡望到毚狙。"]'),
('5a9c7bb2-85d0-4a3c-be96-e68f86f8c236','和史司直韻五首  其一','吳潛','宋','宋诗','song-poetry','','[]','南方一佛放圓光，散作閻浮薝蔔香。',64,'全唐诗/poet.song.209000.json','["南方一佛放圓光，散作閻浮薝蔔香。", "便把此花爲讚祝，更將何物獻休祥。", "建中聖主平平蕩，錫福明王簡簡穰。", "共喜太平今有象，新年好上萬年觴。"]'),
('c748a1d2-a25b-48b7-bad1-9018de938056','和史司直韻五首  其二','吳潛','宋','宋诗','song-poetry','','[]','疑怪虛窗徹夜明，曉看積雪與階平。',64,'全唐诗/poet.song.209000.json','["疑怪虛窗徹夜明，曉看積雪與階平。", "雖知樂歲無捐瘠，尚恐祁寒有怨情。", "天地渾淪方返朴，國家霈澤正哀惸。", "區區甚願祈三白，只怕人閒忌滿盈。"]'),
('29a11a87-d874-4eac-bc78-062ffe9ede91','和史司直韻五首  其三','吳潛','宋','宋诗','song-poetry','','[]','滕翁只道老非才，不料窮冬雪壯哉。',64,'全唐诗/poet.song.209000.json','["滕翁只道老非才，不料窮冬雪壯哉。", "擬撥寒蔬尋早韭，試尋玉樹索寒梅。", "孤汀錯認鷀爲鷺，四野偏宜牟與來。", "聞說廣鞮西北走，將軍已自播州回。"]'),
('ce611a96-f3dd-4cc1-9db3-ddf3ecae2856','和史司直韻五首  其四','吳潛','宋','宋诗','song-poetry','','[]','空中萬鶴舞盤旋，飛向西天祇樹園。',64,'全唐诗/poet.song.209000.json','["空中萬鶴舞盤旋，飛向西天祇樹園。", "一幅繒綃包宇宙，連城珪璧委郊原。", "冰笳莫弄兩三曲，鐵甲猶聯百萬屯。", "痛癢不知惟党二，至今浪有姓名存。"]'),
('e1ed2109-0ffe-44cc-b150-eef99020debf','和史司直韻五首  其五','吳潛','宋','宋诗','song-poetry','','[]','世閒傳假不傳真，丞相可曾城換銀。',64,'全唐诗/poet.song.209000.json','["世閒傳假不傳真，丞相可曾城換銀。", "巷掃他家難敵富，氅披之子未爲貧。", "也知東郡行春守，便作南溪釣雪人。", "指碔爲瑶慚興寄，恨無一縷引千鈞。"]'),
('6930edfc-1d9f-4897-83cc-c967df313b85','和袁尚書韻','吳潛','宋','宋诗','song-poetry','','[]','珠琲無煩費斗量，家家潑撒不珍藏。',64,'全唐诗/poet.song.209000.json','["珠琲無煩費斗量，家家潑撒不珍藏。", "渾疑入臘梅花放，已卜來年稻顆香。", "萬感固知由氣類，一根元只自心秧。", "天憐老子憂民切，將變荒州作富穰。"]'),
('b6c1ed45-66ec-4f4c-b799-3f0aa4e2eefb','同前','吳潛','宋','宋诗','song-poetry','','[]','寂喧相去幾由旬，禽戲何妨小屈伸。',64,'全唐诗/poet.song.209000.json','["寂喧相去幾由旬，禽戲何妨小屈伸。", "退步自應行步穩，識心安用捧心顰。", "又看桃板迎新歲，定是蒲輪訪舊人。", "粒粒金丹分二百，祝公丈六現金身。"]'),
('39a882b3-ca72-43fc-b48d-22ca0b0bffd0','和趙知錄韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','黑風吹海屑銀濤，莫辨秦瑰與楚瑶。',32,'全唐诗/poet.song.209000.json','["黑風吹海屑銀濤，莫辨秦瑰與楚瑶。", "煮水煎茶還我輩，竈煙文武火須調。"]'),
('4f9d86d7-c440-427f-83d4-3b451d333577','和趙知錄韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','甫能乞得六花飛，又要憂它褐與衣。',32,'全唐诗/poet.song.209000.json','["甫能乞得六花飛，又要憂它褐與衣。", "爭似煙江漁釣侶，賣魚沽酒唱歌歸。"]'),
('c09f87cc-5338-46f9-bbfe-9b6ad1d2f78e','和趙知錄韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','造物從來害是恩，由他珪璧委千門。',32,'全唐诗/poet.song.209000.json','["造物從來害是恩，由他珪璧委千門。", "梅梢已露春消息，小向涵虛駐客軒。"]'),
('55cd2d80-be97-498c-ac8a-8560c3f60b8c','再和趙知錄韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','妖蜃吹城帀海濤，也疑瀛島産琨瑶。',32,'全唐诗/poet.song.209000.json','["妖蜃吹城帀海濤，也疑瀛島産琨瑶。", "老滕解把真成妄，郢曲如今始再調。"]'),
('3d66120e-c015-4c65-88d6-7448faa3fbe4','再和趙知錄韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','只道梅花已亂飛，何須點綴謝莊衣。',32,'全唐诗/poet.song.209000.json','["只道梅花已亂飛，何須點綴謝莊衣。", "獨欣凍死安西虜，載取狐巴馬上歸。"]'),
('689c17cf-bcd2-49a4-bfd6-6624db06e4d4','再和趙知錄韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','何煩洛令市私恩，有客甘貧自閉門。',32,'全唐诗/poet.song.209000.json','["何煩洛令市私恩，有客甘貧自閉門。", "恰似明州前錄事，清高直可傲羲軒。"]'),
('b43d7601-d80a-4762-86b0-1cf1e5d7591e','餞趙物斛三首  其一','吳潛','宋','宋诗','song-poetry','','[]','九折羊腸路險巇，險巇過了始平夷。',64,'全唐诗/poet.song.209000.json','["九折羊腸路險巇，險巇過了始平夷。", "風霜雨露無非教，菌槿椒蘭各有時。", "退步元來天地闊，捫心自是鬼神知。", "莫嫌載月舟如洗，贏得清名滿海涯。"]'),
('43b6e7d9-619b-4434-9770-89968672c311','餞趙物斛三首  其二','吳潛','宋','宋诗','song-poetry','','[]','同寅兩載意何傾，不是人間兒女情。',64,'全唐诗/poet.song.209000.json','["同寅兩載意何傾，不是人間兒女情。", "嫉惡吾方欠隠忍，鉏姦君亦太分明。", "是非烈日秋霜勁，利害浮埃抹電輕。", "臨別一言何所贈，做人須做十分成。"]'),
('c91bfdba-c044-4939-9b34-69c99e8f592f','餞趙物斛三首  其三','吳潛','宋','宋诗','song-poetry','','[]','精義無窮在鄴籤，更須於易倍深拈。',64,'全唐诗/poet.song.209000.json','["精義無窮在鄴籤，更須於易倍深拈。", "陽奇陰偶機難測，往屈來伸理可占。", "有謂宣尼夫乃佞，或云仲子烏能廉。", "聖賢言行多參考，美疢猶應用石砭。"]'),
('4ccdc4ba-dc77-4cf0-939f-9e277016fb65','喜雨和趙右司','吳潛','宋','宋诗','song-poetry','','[]','車水耕田正閔農，夜來好雨一犁通。',64,'全唐诗/poet.song.209000.json','["車水耕田正閔農，夜來好雨一犁通。", "相近可是須羣望，陟降元來即上穹。", "擊壤何曾知帝力，觀風誰與達天聰。", "見他東作思南墅，愁殺江南桑苧翁。"]'),
('8bb64817-59f2-477c-a161-63721193c52d','喜雨和史司直二首  其一','吳潛','宋','宋诗','song-poetry','','[]','六丁海面揭封回，天上屯雲撮得來。',64,'全唐诗/poet.song.209000.json','["六丁海面揭封回，天上屯雲撮得來。", "連月不曾聽澍雨，今年方始見轟雷。", "定知水畎移秧插，底用泥塗把穀栽。", "聞說君王勤露禱，固應妖魃不能災。"]'),
('3bed964d-885c-43cf-9b13-b10e2ba7802e','喜雨和史司直二首  其二','吳潛','宋','宋诗','song-poetry','','[]','簷溜終宵稍慰心，更須三日始爲霖。',64,'全唐诗/poet.song.209000.json','["簷溜終宵稍慰心，更須三日始爲霖。", "雲雷尚覺經綸狹，暑雨猶疑咨怨深。", "不假溟鯤能激水，何須垤鸛解知陰。", "回頭谷口耕樵侶，辜負盟言愧斷金。"]'),
('9aee8be2-8c61-4584-9b56-f5ed3c44a83d','秋思一首寄方君遇','吳潛','宋','宋诗','song-poetry','','[]','西風黄葉墮階前，秋思撩人已可憐。',64,'全唐诗/poet.song.209000.json','["西風黄葉墮階前，秋思撩人已可憐。", "身漸衰來非一日，心都懶處是今年。", "愛憎毀譽何關我，消息盈虛要識天。", "六十四翁凡百足，只祈君相放歸田。"]'),
('dad2d937-142b-4bd7-84ef-118b036c4dd6','寄丁丞相','吳潛','宋','宋诗','song-poetry','','[]','今年快活好重陽，君相都俞盡主張。',64,'全唐诗/poet.song.209000.json','["今年快活好重陽，君相都俞盡主張。", "飛語不容輕點污，細書那更極揄揚。", "無風無雨稻粱熟，有酒有螯棖橘香。", "只待防冬平靜了，來春衣錦又還鄉。"]'),
('970f8647-09b4-4b4a-9848-c84b245faea2','喜雨預卜淮寇之遁口占小詩呈同官','吳潛','宋','宋诗','song-poetry','','[]','醜虜逋誅尚不庭，敢驅羊犬瞰邊城。',64,'全唐诗/poet.song.209000.json','["醜虜逋誅尚不庭，敢驅羊犬瞰邊城。", "滂沱無此十月雨，攘却過如百萬兵。", "狗帳縱氈淋易透，馬蹄雖澀滑難行。", "只願皇天相佑助，皇天佑助豈人情。"]'),
('8de02f51-47b6-42df-a1f4-ad00f23d5806','景回兄和篇甚佳信筆再用韻','吳潛','宋','宋诗','song-poetry','','[]','犂掃終當盡穴庭，將軍夫豈但嬰城。',64,'全唐诗/poet.song.209000.json','["犂掃終當盡穴庭，將軍夫豈但嬰城。", "何妨水潦威曹賊，應以風聲懾晉兵。", "中立運籌飛凱奏，昌黎吮筆草歌行。", "開年東作吾何在，野老相携話故情。"]'),
('f66b7051-5d2f-408f-a44a-803eab8ca6d9','昨日連晝夜之雨尤可喜再用前韻','吳潛','宋','宋诗','song-poetry','','[]','佛貍索死離龍庭，堪笑披猖欲背城。',64,'全唐诗/poet.song.209000.json','["佛貍索死離龍庭，堪笑披猖欲背城。", "釜爲水懸憂後爨，弓因雨弱失長兵。", "突三千人如電掃，誅兩萬戶若風行。", "又報廣南騰露布，太平從此慰皇情。"]'),
('9610745b-9ea3-4cba-a7a6-dba84b060691','和丁丞相','吳潛','宋','宋诗','song-poetry','','[]','夷狄爲陰中國陽，豈容羊犬更鴟張。',64,'全唐诗/poet.song.209000.json','["夷狄爲陰中國陽，豈容羊犬更鴟張。", "捷書一紙來從廣，凱奏連旗至自揚。", "盡瘁元臣食放箸，偷安老守寢凝香。", "但憐此土非吾土，歲晚天寒憶故鄉。"]'),
('be2fb377-da1e-4aee-8e0b-88bc4a067b39','和惠檢閲送胡計院韻','吳潛','宋','宋诗','song-poetry','','[]','小借園林一餉閒，相携送客上天關。',64,'全唐诗/poet.song.209000.json','["小借園林一餉閒，相携送客上天關。", "頺齡晚歲淒涼裏，今日明朝聚散閒。", "極目煙雲方渺渺，滿蹊桃李正斑斑。", "老來尚被冠裳縛，坐對漁舟亦厚顔。"]'),
('8362f295-89af-43e6-8cd0-57e0a2ff7b9a','行小圃偶成唐律呈直翁自昭叔夏','吳潛','宋','宋诗','song-poetry','','[]','今年花信已成空，白白紅紅苦雨中。',64,'全唐诗/poet.song.209000.json','["今年花信已成空，白白紅紅苦雨中。", "老境摧頹春更好，愁城高聳酒難攻。", "一生當號知非子，萬事都歸亡是公。", "巴得新晴天亦笑，東風吹夢過江東。"]'),
('6980b510-aba0-41ae-a376-6e9e53afcd82','和劉右司見寄六絕一律  其一','吳潛','宋','宋诗','song-poetry','','[]','老子誰知密度關，却支筇杖訪荒園。',32,'全唐诗/poet.song.209000.json','["老子誰知密度關，却支筇杖訪荒園。", "故應我輩鍾情別，佳話真堪詔子孫。"]'),
('c496c34a-6501-4711-bf3b-64ce628297d4','和劉右司見寄六絕一律  其二','吳潛','宋','宋诗','song-poetry','','[]','撩我歸心更欲歸，綠英已是換紅菲。',32,'全唐诗/poet.song.209000.json','["撩我歸心更欲歸，綠英已是換紅菲。", "分明不似高空鳥，無弋無矰到處飛。"]'),
('0e9f6400-bdc9-4847-9401-d34b4f1bd11e','和劉右司見寄六絕一律  其三','吳潛','宋','宋诗','song-poetry','','[]','鵲絆晴絲柳絮乾，金沙玉李鬭開顔。',32,'全唐诗/poet.song.209000.json','["鵲絆晴絲柳絮乾，金沙玉李鬭開顔。", "此時此景此中意，付與仙翁一餉閒。"]'),
('44295f56-574e-47e5-9567-77fa667e93c4','和劉右司見寄六絕一律  其四','吳潛','宋','宋诗','song-poetry','','[]','酴醾萬玉吐幽香，芍藥千紅護綠裳。',32,'全唐诗/poet.song.209000.json','["酴醾萬玉吐幽香，芍藥千紅護綠裳。", "好景只供人借看，尋思百計是歸强。"]'),
('6c3ce87e-2581-4134-87fb-d08adc584d95','和劉右司見寄六絕一律  其五','吳潛','宋','宋诗','song-poetry','','[]','小兒亦解挽公留，知有人閒第一流。',32,'全唐诗/poet.song.209000.json','["小兒亦解挽公留，知有人閒第一流。", "老我相思無盡藏，臨風一日幾搔頭。"]'),
('bb8cbff6-b266-435a-aa71-4f4f90998a97','和劉右司見寄六絕一律  其六','吳潛','宋','宋诗','song-poetry','','[]','愁來只是向無何，浮聖沈賢共一波。',32,'全唐诗/poet.song.209000.json','["愁來只是向無何，浮聖沈賢共一波。", "若見江南煙釣侶，寄言好與曬漁蓑。"]'),
('a1f9fb8b-a06e-443b-860f-eac027ea5519','和劉右司見寄六絕一律  其七','吳潛','宋','宋诗','song-poetry','','[]','我家碧雲畔，中有最高亭。',48,'全唐诗/poet.song.209000.json','["我家碧雲畔，中有最高亭。", "閲世已頭白，看山猶眼青。", "誰能環北轍，那更徙南溟。", "歸計天須許，煩占處士星。"]'),
('80880202-ade5-4b83-a473-641141db00ef','送十二知軍領郡澄江二首  其一','吳潛','宋','宋诗','song-poetry','','[]','門戶喜方興，送兒五馬行。',48,'全唐诗/poet.song.209000.json','["門戶喜方興，送兒五馬行。", "君恩天樣大，家法水能清。", "但務平平政，何須赫赫名。", "也休扳汝父，皂白太分明。"]'),
('a1aa9de2-2e02-464f-bc0d-d22cc6ea87c9','送十二知軍領郡澄江二首  其二','吳潛','宋','宋诗','song-poetry','','[]','老父如汝年，監州尚折旋。',48,'全唐诗/poet.song.209000.json','["老父如汝年，監州尚折旋。", "後生何聞望，小郡亦藩宣。", "申浦秋潮落，君山暮靄連。", "菊時吾去此，訪汝擊羣鮮。"]'),
('e3c3f86f-002f-45e3-ae03-507c84085e0b','古風一首送常明仲還里社','吳潛','宋','宋诗','song-poetry','','[]','韙軒吾石友，相從三十年。',216,'全唐诗/poet.song.209000.json','["韙軒吾石友，相從三十年。", "舌本多文獻，胸笥皆簡編。", "脊梁硬於鐵，雖貧不言錢。", "古井波愈靜，老榦骨尤堅。", "眨眼七十翁，酡顔映銀髯。", "辭我歸舊隠，從此將終焉。", "我懷雖惻楚，君意難棄捐。", "顧我亦歲徂，華髮蒙其顛。", "君王念帷蓋，高車會當懸。", "爾汝一蘧廬，日月雙彈圓。", "合離與聚散，暮景必復然。", "以茲强排遣，送君鄞水邊。", "空江漲夏潦，遠山生夕煙。", "野鳥投林飛，漁舟衝浦還。", "萬物各有適，人生且隨緣。", "江東企西浙，道里無半千。", "幸及身强健，尚可相周旋。", "所愧韓魏公，不能官老泉。"]'),
('5a0f6f29-d99f-4775-a7a5-87c062274846','明仲小姪歸江浙餞之西渡有感二首  其一','吳潛','宋','宋诗','song-poetry','','[]','韙軒從此入山深，阿阮同途反奮岑。',64,'全唐诗/poet.song.209000.json','["韙軒從此入山深，阿阮同途反奮岑。", "老大分携朋友意，死生契闊弟兄心。", "碧雲悵望家千里，白髮瓢零酒一斟。", "歲晚情懷易感觸，不堪衰淚忽霑襟。"]'),
('6f59c641-bab6-49a1-a602-b230350d16c2','明仲小姪歸江浙餞之西渡有感二首  其二','吳潛','宋','宋诗','song-poetry','','[]','宿秧青碧穉秧黄，長葉抽苗勢已張。',64,'全唐诗/poet.song.209000.json','["宿秧青碧穉秧黄，長葉抽苗勢已張。", "田就再耘秋有準，水收積潦旱無傷。", "老牛引犢挨籬卧，新燕將雛貼水翔。", "一壑一邱吾亦有，誰憐留滯尚他鄉。"]'),
('1eddde9c-c017-42cb-aa95-9da59e2ca89e','餞鄭宗丞','吳潛','宋','宋诗','song-poetry','','[]','煙靄晚將合，湖山景致嘉。',48,'全唐诗/poet.song.209000.json','["煙靄晚將合，湖山景致嘉。", "誰爲千里別，客負一年花。", "心事違春事，年華上鬢華。", "扁舟何日發，回首水雲賒。"]'),
('08029834-3f4f-46bf-b065-f64efb2e21a5','天寧長老新齋堂請轉語','吳潛','宋','宋诗','song-poetry','','[]','慧公幻出一齋堂，巨棟危梁壓十方。',32,'全唐诗/poet.song.209000.json','["慧公幻出一齋堂，巨棟危梁壓十方。", "更有心堂無量闊，闊中別有好思量。"]'),
('ff556644-5f70-44b4-8e43-596b67ea276f','因藏主持此稽首諸山如有小小寺院保明出世','吳潛','宋','宋诗','song-poetry','','[]','牛背牽來一牧兒，要從古道去揚輝。',32,'全唐诗/poet.song.209000.json','["牛背牽來一牧兒，要從古道去揚輝。", "莫學當年隻履客，無人秋采却西歸。"]'),
('8bbc1766-b71f-484b-8aef-5a296796c945','代爲大川重說偈言','吳潛','宋','宋诗','song-poetry','','[]','無流無派亦無源，糲食充饑衲禦寒。',32,'全唐诗/poet.song.209000.json','["無流無派亦無源，糲食充饑衲禦寒。", "直下承當直下了，有何佛祖有何傳。"]'),
('8c56bfa7-6ed9-4cc3-a112-1918a3d6c6e2','僧若珪求短偈','吳潛','宋','宋诗','song-poetry','','[]','黄連甜兮甘草苦，這些滋味許誰知。',32,'全唐诗/poet.song.209000.json','["黄連甜兮甘草苦，這些滋味許誰知。", "宰官具足端嚴相，畢竟元無病可醫。"]'),
('3e7c3ac7-9b94-49cd-8611-8450133f95c8','山偈寄無聲老師','吳潛','宋','宋诗','song-poetry','','[]','聞師遭遇善知識，布衲時聞羅綺香。',32,'全唐诗/poet.song.209000.json','["聞師遭遇善知識，布衲時聞羅綺香。", "照管爲他眼景轉，投胎託舍沒思量。"]'),
('cb4255af-f2d2-4be3-8f30-be25c8965e5e','又山偈就寄善知識','吳潛','宋','宋诗','song-poetry','','[]','傳語當年白侍郎，住行坐卧只尋常。',32,'全唐诗/poet.song.209000.json','["傳語當年白侍郎，住行坐卧只尋常。", "須彌山子才翻却，便是人天大法王。"]'),
('0c3f7785-e4be-4576-a829-f61aa504348d','題暗香疏影詞後用潘德久贈姜白石韻','吳潛','宋','宋诗','song-poetry','','["\u897f\u6e56"]','人生浮脆若菰蒲，四十年前此丈夫。',32,'全唐诗/poet.song.209000.json','["人生浮脆若菰蒲，四十年前此丈夫。", "擬向西湖酹孤魄，想應風月易招呼。"]'),
('56cc5341-3751-4e5e-a860-ab50b36606c8','苦雨吟十首呈同官諸丈  其一','吳潛','宋','宋诗','song-poetry','','[]','舊雨連今雨，南鳩喚北鳩。',48,'全唐诗/poet.song.209000.json','["舊雨連今雨，南鳩喚北鳩。", "聲聲腸寸斷，點點淚交流。", "歷耳風來處，凝眸天盡頭。", "衷情如此苦，造物亦憐不。"]'),
('2547b4f2-2a3c-46a8-995a-6c56b50a8d8e','苦雨吟十首呈同官諸丈  其二','吳潛','宋','宋诗','song-poetry','','[]','自春爰及夏，多雨少曾晴。',48,'全唐诗/poet.song.209000.json','["自春爰及夏，多雨少曾晴。", "積壓兼旬潦，瀰漫四澤盈。", "穉苗憂冒沒，矮岸恐頹傾。", "急遣洪賓佐，代余省爾氓。"]'),
('ae36d3f5-8f10-4ea1-a4d0-8d360941f448','苦雨吟十首呈同官諸丈  其三','吳潛','宋','宋诗','song-poetry','','[]','洪穴隄凡九，泄水注之江。',48,'全唐诗/poet.song.209000.json','["洪穴隄凡九，泄水注之江。", "荷鍤來如織，奔湍去若撞。", "雨聲雖斷續，潦勢已賓降。", "想見魚秧泛，沙汀白鳥雙。"]'),
('9037e774-ee98-4cf9-9fbc-432a0b44cc4b','苦雨吟十首呈同官諸丈  其四','吳潛','宋','宋诗','song-poetry','','[]','早晚遣長鬚，行田西北隅。',48,'全唐诗/poet.song.209000.json','["早晚遣長鬚，行田西北隅。", "稻禾都旺否，廬舍莫淹無。", "高仰爲何碶，低漥是某都。", "水痕如退落，分寸要相符。"]'),
('cce608a5-d068-4ecd-8b82-339fd53ceff7','苦雨吟十首呈同官諸丈  其五','吳潛','宋','宋诗','song-poetry','','[]','正直三神列，慈悲一佛尊。',48,'全唐诗/poet.song.209000.json','["正直三神列，慈悲一佛尊。", "須知真實念，是謂吉祥門。", "巨浸旋歸壑，頑雲漸散屯。", "更憑驅日馭，揮霍照乾坤。"]'),
('8522d53e-1a7b-4b50-86f1-bb43f9edfbd9','苦雨吟十首呈同官諸丈  其六','吳潛','宋','宋诗','song-poetry','','[]','田官决水歸，喜若潰重圍。',48,'全唐诗/poet.song.209000.json','["田官决水歸，喜若潰重圍。", "晚種禾頭出，新耘稻本肥。", "已如雲氣勃，只恨日光稀。", "安得驅夸父，搪開萬里輝。"]'),
('a8c4b4f8-8720-43b6-b149-2b5fc27009dd','苦雨吟十首呈同官諸丈  其七','吳潛','宋','宋诗','song-poetry','','[]','海鄉多下田，潢潦易纏綿。',48,'全唐诗/poet.song.209000.json','["海鄉多下田，潢潦易纏綿。", "雲脚晚希露，天心朝望穿。", "壤蚯方惡出，穴蟻又憂遷。", "翻覆陰晴證，愁腸日幾旋。"]'),
('3ec11f80-32de-4866-8709-5079c214c594','苦雨吟十首呈同官諸丈  其八','吳潛','宋','宋诗','song-poetry','','[]','連朝雨水淹，燕寢似窮閻。',48,'全唐诗/poet.song.209000.json','["連朝雨水淹，燕寢似窮閻。", "無處可就燥，何時得附炎。", "頻占季主卦，屢乞鮑君籤。", "千里人知否，心香日夜添。"]'),
('8c93b72c-eb81-4f6d-a0e3-63d23502c8e7','苦雨吟十首呈同官諸丈  其九','吳潛','宋','宋诗','song-poetry','','[]','五鼓立中庭，疎星一二明。',48,'全唐诗/poet.song.209000.json','["五鼓立中庭，疎星一二明。", "轉頭雲復合，移步雨還傾。", "感召雖人事，怨咨柰物情。", "號空猶未應，隠痛痛無聲。"]'),
('0f6fe86b-b0a3-4229-a8de-dfcacae6222a','苦雨吟十首呈同官諸丈  其一○','吳潛','宋','宋诗','song-poetry','','[]','老守最憂農，往來思慮忡。',51,'全唐诗/poet.song.209000.json','["老守最憂農，往來思慮忡。", "半時半刻裏，一飯一茶中。", "饑溺真猶己，恫{疒眾}在厥躬。", "天高元聽下，一念豈難通。"]'),
('5823491d-4335-4815-a1d9-da306e97c77f','久雨喜晴檢閲計院紀以舂容之篇敬用韻爲謝','吳潛','宋','宋诗','song-poetry','','[]','樂天何愛詠，堯夫非好吟。',168,'全唐诗/poet.song.209000.json','["樂天何愛詠，堯夫非好吟。", "愧乏康濟術，粗懷饑溺心。", "彌旬雨翻屋，耄倪泣蒼䫒。", "微臣職芻牧，癢痛入肌深。", "行若負刺芒，坐如隠氈鍼。", "再拜告神明，寸心秉堅金。", "蠲租還已債，議獄并弛刑。", "但求講實政，何暇競虛名。", "天威咫尺臨，昏翳忽開明。", "宿苗既豐碩，穉秧靡飄淫。", "阿香亦效靈，排陰吐洪音。", "推出太陽輝，天外旋收聲。", "老守寬近憂，濁醪呼客斟。", "客有勸翁歸，前身豈傅霖。"]'),
('1e7244db-0da9-4caa-a591-d4c3c1647054','賡劉自昭出郊佳什','吳潛','宋','宋诗','song-poetry','','[]','倦聽衙官報兩衙，出門山水即吾家。',64,'全唐诗/poet.song.209000.json','["倦聽衙官報兩衙，出門山水即吾家。", "淺深碧綠湖田稻，濃淡紅黄野岸花。", "草草人生知有限，悠悠客恨自無涯。", "凉颸特爲驅袢暑，白鳥青天萬里賒。"]'),
('37cce327-2223-4513-ad61-a2caa9c3f936','出郊偶賦','吳潛','宋','宋诗','song-poetry','','[]','聊驅小隊出郊圻，天遣凉風却午曦。',64,'全唐诗/poet.song.209000.json','["聊驅小隊出郊圻，天遣凉風却午曦。", "雨脚似披千疋練，山容如障數層帷。", "並岸低疇苗頷長，近坡高隴稻頭垂。", "因他景物思吾土，還是黄雞白酒時。"]'),
('8aec6bc9-2c31-4e7c-a754-2e1b3ced0c5a','高橋舟中二首  其一','吳潛','宋','宋诗','song-poetry','','[]','小隊旌旗西郭頭，筍輿緩步看農疇。',64,'全唐诗/poet.song.209000.json','["小隊旌旗西郭頭，筍輿緩步看農疇。", "十分田有九分闢，今歲人無去歲憂。", "貼水新秧頭欲起，連雲宿麥頷都收。", "天憐老子勤民瘼，賜與豐年不待求。"]'),
('b2449c6d-9d2c-48b7-9f54-bda5b289d5c6','高橋舟中二首  其二','吳潛','宋','宋诗','song-poetry','','[]','小麥青青大麥黄，海鄉風物亦江鄉。',64,'全唐诗/poet.song.209000.json','["小麥青青大麥黄，海鄉風物亦江鄉。", "籃鋪蠶種提歸急，肩夯牛犂出去忙。", "春漲半篙波瀲灩，曉山一带色微茫。", "東風客子思歸切，不待啼鵑也斷腸。"]'),
('c238a42c-11f0-4239-9550-c0cc5e47394f','水雲鄉和制機劉自昭韻三首  其一','吳潛','宋','宋诗','song-poetry','','[]','不禁歸夢五更長，出見寬閑若故鄉。',64,'全唐诗/poet.song.209000.json','["不禁歸夢五更長，出見寬閑若故鄉。", "天外慘舒雲黑白，隴頭大小麥青黄。", "水雖四澤無蘆葦，地不多山少柘桑。", "却有一般堪愛賞，虬髯老檜鬰蒼蒼。"]'),
('f8cfa756-f9f4-4ed5-b616-9d3c92884eb7','水雲鄉和制機劉自昭韻三首  其二','吳潛','宋','宋诗','song-poetry','','[]','問君身世欲如何，付與漁翁欵乃歌。',64,'全唐诗/poet.song.209000.json','["問君身世欲如何，付與漁翁欵乃歌。", "未酩酊時須酩酊，得磨駝處且磨駝。", "聲名草木知誰是，功業旂常在古多。", "百尺危樓聊弔往，薰風首夏正清和。"]'),
('51736e08-15b8-4fee-a399-b6100a4570c8','水雲鄉和制機劉自昭韻三首  其三','吳潛','宋','宋诗','song-poetry','','[]','水高只合汎歸舟，老大何須說壯猷。',64,'全唐诗/poet.song.209000.json','["水高只合汎歸舟，老大何須說壯猷。", "樂事尚堪葵麥候，豐年已兆黍禾秋。", "西曹久負平平考，東郡今稱上上州。", "不待子規相勸督，衰翁何止四宜休。"]'),
('cb8cb6b5-4321-454d-8bd9-7ecd48c6ce2b','和謝惠計院二首  其一','吳潛','宋','宋诗','song-poetry','','[]','插種如雲四月頭，代他田畯閲耕疇。',64,'全唐诗/poet.song.209000.json','["插種如雲四月頭，代他田畯閲耕疇。", "意行不敢煩君重，詩到偏能寫我憂。", "占穀喜看連歲熟，麗琛聞說十分收。", "各家官事隨宜了，尊酒相過莫外求。"]'),
('0da9abc8-f93a-4a2f-be2d-e7d907f46d71','和謝惠計院二首  其二','吳潛','宋','宋诗','song-poetry','','[]','千林新綠褪萎黄，人在它鄉某水鄉。',64,'全唐诗/poet.song.209000.json','["千林新綠褪萎黄，人在它鄉某水鄉。", "白鳥閑閑疑冷看，蒼鷹擾擾正乾忙。", "阿婆塗抹情何在，老子瞢騰視已茫。", "二頃良田元不欠，一聲布穀斷人腸。"]'),
('640fdcb6-357d-4d6d-b41e-fb018b0f47a3','寄樗寮張寺丞','吳潛','宋','宋诗','song-poetry','','[]','春來物物攪愁腸，排遣惟應闖醉鄉。',32,'全唐诗/poet.song.209000.json','["春來物物攪愁腸，排遣惟應闖醉鄉。", "無柰督郵風味惡，桃花流水願分嘗。"]'),
('82a68127-e715-4bc0-8d8c-33bbc45bc752','舟檥娥祠敬留二絕  其一','吳潛','宋','宋诗','song-poetry','','[]','孝娥何意要垂名，重在天倫一命輕。',32,'全唐诗/poet.song.209000.json','["孝娥何意要垂名，重在天倫一命輕。", "若訂漢家彤史傳，淳于公女尚偷生。"]'),
('1c6974e9-4a30-40a2-ade4-b77d1a758f3f','舟檥娥祠敬留二絕  其二','吳潛','宋','宋诗','song-poetry','','[]','雖然墟墓一拳土，泰華衡常未必侔。',32,'全唐诗/poet.song.209000.json','["雖然墟墓一拳土，泰華衡常未必侔。", "感動行人忠孝淚，滄江不斷水東流。"]'),
('1d017102-d230-4793-abde-27c3942bfafb','口占酬翁處靜','吳潛','宋','宋诗','song-poetry','','[]','年來戶外故人疎，慚愧新詞解起予。',32,'全唐诗/poet.song.209000.json','["年來戶外故人疎，慚愧新詞解起予。", "賀監本家明與越，扁舟來訪問何如。"]'),
('ccf6ddb9-c5b1-48ae-8af1-efffcfbd9d61','君異鄭兄出示舊詩蓋紹定初所信筆也俛仰三十年矣戲成口占復歸之','吳潛','宋','宋诗','song-poetry','','[]','彈指江湖三十年，淋漓舊墨尚依然。',32,'全唐诗/poet.song.209000.json','["彈指江湖三十年，淋漓舊墨尚依然。", "人生未必堅如紙，心事淒涼雪滿顛。"]'),
('46a9d101-7e95-41cd-a79f-317f99012932','和翁處靜賦木香','吳潛','宋','宋诗','song-poetry','','[]','黄蘂檀心襯綠衣，細成棋架四方齊。',32,'全唐诗/poet.song.209000.json','["黄蘂檀心襯綠衣，細成棋架四方齊。", "只緣鼻孔撩天去，特遣清香起自低。"]'),
('5a2d2c66-419c-4f09-bfac-269e6cf536ef','喜雨二解  其一','吳潛','宋','宋诗','song-poetry','','[]','烏{禾散}新春玉粒堆，齊頭{禾畕}{禾散}又相催。',73,'全唐诗/poet.song.209000.json','["烏{禾散}新春玉粒堆，齊頭{禾畕}{禾散}又相催。", "高田猶怕來秋旱，上界俄聞發水雷。", "幾日雲車停野外，今宵雨旆入城來。", "須臾簷溜如奔峽，枕上吟哦一快哉。"]'),
('4216d6ab-174b-435f-baab-50e508d5947c','喜雨二解  其二','吳潛','宋','宋诗','song-poetry','','[]','須知造化自心生，風雨雲雷特踐形。',64,'全唐诗/poet.song.209000.json','["須知造化自心生，風雨雲雷特踐形。", "人在兩閒元有事，天於萬類豈無情。", "焦枯蒙潤物蘇醒，昏悶得凉身泰平。", "昨夜桃笙時便背，定應收捲向金莖。"]'),
('1bfec85e-c5fe-4072-a177-1b18a8807285','中秋無月和曾儀吉制幹','吳潛','宋','宋诗','song-poetry','','[]','見說瓊樓忒煞寒，雲衣特地護霄端。',64,'全唐诗/poet.song.209000.json','["見說瓊樓忒煞寒，雲衣特地護霄端。", "也應齒髮十分老，自是嫦娥一笑難。", "此夜不妨留客醉，明年未卜共誰看。", "歸與丘壑無窮趣，何惜相從樂且盤。"]'),
('8b607488-e179-474f-99ba-11eb8ab82c2e','賦惠計院允堂','吳潛','宋','宋诗','song-poetry','','[]','荆溪惠子鬢鬅鬙，義理鑽研到粹精。',64,'全唐诗/poet.song.209000.json','["荆溪惠子鬢鬅鬙，義理鑽研到粹精。", "允以名堂由意實，漫云從仕但心亨。", "一窗春草無窮意，四壁秋蛩不斷聲。", "若向此中能領會，始知持敬造存誠。"]'),
('76d6dae5-e040-40af-81a4-34fc09dbcf2b','謝惠計院分餉新茶','吳潛','宋','宋诗','song-poetry','','[]','乾坤正氣清且勁，長挾春風作襟韻。',192,'全唐诗/poet.song.209000.json','["乾坤正氣清且勁，長挾春風作襟韻。", "不惟散滿詩人脾，還入靈根茁苕穎。", "顧山仙人曇滯家，带春蒐摘黄金芽。", "擣碎雲英琢蒼璧，旋瀉玉瓷浮白花。", "半甌和露沾喉吻，甘潤遶肌香貫頂。", "孔光賢處不脂韋，長孺直時無苦梗。", "平生腐儒湯餠腸，不堪八餠分頭綱。", "多君鄉味裹將送，謂我詩情應得嘗。", "分無蛾眉捧玉椀，亦乏撐腸五千卷。", "活火新泉點啜來，儼若少陽人覿面。", "飲散登臺嗅老香，却憶家山菊徑荒。", "明朝便作玉川子，兩腋乘風歸故鄉。"]'),
('d65ac054-df08-42ec-9319-beb98d93ba9f','示慧開禪師頌二首  其一','吳潛','宋','宋诗','song-poetry','','[]','手中拍板袖中槌，贏得逢場弄一回。',32,'全唐诗/poet.song.209000.json','["手中拍板袖中槌，贏得逢場弄一回。", "寄語無門開道者，挑包便好出山來。"]'),
('62dd9499-2345-4366-899c-bd1db35fb368','示慧開禪師頌二首  其二','吳潛','宋','宋诗','song-poetry','','[]','黑山心歷歷，金殿口巴巴。',24,'全唐诗/poet.song.209000.json','["黑山心歷歷，金殿口巴巴。", "不因漁父引，怎得見波查。"]'),
('93f86e5c-5998-4c98-83bb-2fea65f13ab8','竹','吳潛','宋','宋诗','song-poetry','','[]','編茅爲屋竹爲椽，屋上青山屋下泉。',32,'全唐诗/poet.song.209000.json','["編茅爲屋竹爲椽，屋上青山屋下泉。", "半掩柴門人不見，老牛將犢伴籬眠。"]'),
('c246ec3e-c8ee-47b9-99a1-77111bfadd2e','真如勸農二首  其一','吳潛','宋','宋诗','song-poetry','','[]','聖主垂衣坐九重，不才假守勸農功。',64,'全唐诗/poet.song.209000.json','["聖主垂衣坐九重，不才假守勸農功。", "周家永命由忠厚，湯后存心在困窮。", "安得田租成歲減，且將人事兆年豐。", "守宰監州民最近，相期清白紹家風。"]'),
('c4b51233-650a-4410-9d44-68cff9ac19f7','真如勸農二首  其二','吳潛','宋','宋诗','song-poetry','','[]','百尺高橋鎮古丘，乘閒莫惜小夷猶。',64,'全唐诗/poet.song.209000.json','["百尺高橋鎮古丘，乘閒莫惜小夷猶。", "新楊受日春無際，宿麥翻雲歲有瘳。", "鷹隼圖南天外意，江山遶北望中愁。", "世事難知人易老，一杯聊復寄沈浮。"]'),
('ba8a0cae-3701-4025-9834-7dfce62ebe33','謝世詩','吳潛','宋','宋诗','song-poetry','','[]','伶仃七十翁，間關四千里。',288,'全唐诗/poet.song.209000.json','["伶仃七十翁，間關四千里。", "縱非烟瘴窟，自無逃生理。", "去年三伏中，葉舟遡梅水。", "燥風扇烈日，熱喘乘毒氣。", "盤回七十灘，顛頓常驚悸。", "肌體若分裂，肝腸如擣碎。", "支持達循州，荒凉一墟市。", "託迹貢士闈，古屋已頹圮。", "地濕暗流泉，風雨上不庇。", "蛇鼠相交羅，螻蟈聲怪異。", "短垣逼閭閻，簷楹接尺咫。", "凡民多死喪，哭聲常四起。", "妻或哭其夫，父或哭其子。", "爾哭我傷懷，傷懷那可止。", "悲愁復悲愁，憔悴更憔悴。", "陰陽寇乘之，不覺入腠理。", "雙足先蹣跚，兩股更重膇。", "擁腫大如椽，何止患蹠盭。", "淫邪復入腹，喘促妨卧寐。", "脾神與食仇，入口即嘔噦。", "膏肓勢日危，和扁何爲計。", "人生固有終，蓋棺亦旋已。", "長兒在道塗，不及見吾斃。", "老妻對我啼，數僕環雪涕。"]'),
('1c4ed172-0101-4fa8-91da-a2db35f744b1','和人賦琴高魚','吳潛','宋','宋诗','song-poetry','','[]','仙人藥苗化爲魚，身雖纖細味豐腴。',128,'全唐诗/poet.song.209000.json','["仙人藥苗化爲魚，身雖纖細味豐腴。", "土人涉溪如採荇，以布爲網猶恐疏。", "不比吳王耽嗜鱠，松江千古留腥滓。", "好似春茶槍與旗，俯視銀條不足數。", "人生所樂在家鄉，何必定食河之魴。", "琴高仙游不可躡，自向崑崙朝玉皇。", "玉皇一笑倚天末，乞與五湖任囊括。", "扁舟煙雨歸去來，卧聽魚槎聲濊濊。"]'),
('05880984-d93e-4f34-b6c4-b0a8ae6de75a','送林明府','吳潛','宋','宋诗','song-poetry','','[]','擬續宣城志，難忘令尹賢。',48,'全唐诗/poet.song.209000.json','["擬續宣城志，難忘令尹賢。", "庭空無獄訟，齋靜有詩篇。", "心似秋雲遠，政如霜月懸。", "活人最多處，饑歲作豐年。"]'),
('5d73fd0a-690a-482c-8773-c38f32304f9f','泛湖次韵','吳潛','宋','宋诗','song-poetry','','["\u897f\u6e56"]','塵裏光陰夢裏殘，西湖莫厭白時看。',64,'全唐诗/poet.song.209000.json','["塵裏光陰夢裏殘，西湖莫厭白時看。", "落花飛絮將春去，斷雨零雲入暮寒。", "白髮催人愁遠道，青山笑我戀微官。", "浮生要足何緣足，枝上鷦鷯儘自安。"]'),
('fea79b75-67d3-4367-b048-30424b7adcd2','太平仙游山神祠','吳潛','宋','宋诗','song-poetry','','[]','仙遊杳不極，山夕景獨殊。',120,'全唐诗/poet.song.209000.json','["仙遊杳不極，山夕景獨殊。", "丹氣發空翠，天燈照連珠。", "下有神之宅，何年託蓬壺。", "想爭隋氏鹿，赫赫雄萬夫。", "提劍起草莽，搴旗護枌榆。", "奇功未盡賞，靈異終弗渝。", "祝釐賽田畯，撫節降楚巫。", "羽人孰可仍，我亦懷英圖。", "芬薌乍成霧，盃珓若合符。", "歌此謝冥貺，送迎神以娛。"]'),
('4156ace5-1d03-44e4-adaa-323b5b813ce2','邳州','吳潛','宋','宋诗','song-poetry','','[]','荒城十載路重經，暫艤扁舟坐驛亭。',64,'全唐诗/poet.song.209000.json','["荒城十載路重經，暫艤扁舟坐驛亭。", "春到梅花何處白，雪晴山色向人青。", "驚心家遠書難寄，迎面風寒酒易醒。", "莫憶牽衣兒女態，曉猿夜鶴笑林扃。"]'),
('970b7bc3-4a05-496a-a3a5-da61f160c879','龍溪道中','吳潛','宋','宋诗','song-poetry','','[]','潮痕初漲沒汀沙，隔岸青帘認酒家。',32,'全唐诗/poet.song.209000.json','["潮痕初漲沒汀沙，隔岸青帘認酒家。", "要識江鄉春事晚，東風吹盡野棠花。"]'),
('7f184411-8f9b-4f38-802c-669f64af2880','通州道中','吳潛','宋','宋诗','song-poetry','','[]','萬雉參差雲霧開，四千里外客重來。',64,'全唐诗/poet.song.209000.json','["萬雉參差雲霧開，四千里外客重來。", "平岡日出車牛喘，古道塵飛驛騎回。", "白玉至今傳楚璞，黄金自古說燕臺。", "高樓紅旆應如昨，莫遣新盃到酒盃。"]'),
('68e7e479-0b71-4e24-a8a4-09d8588ff0fa','平山堂','吳潛','宋','宋诗','song-poetry','','[]','盡日西風捲地狂，只堪吹雁過瀟湘。',64,'全唐诗/poet.song.209000.json','["盡日西風捲地狂，只堪吹雁過瀟湘。", "黄沙萬里暮天遠，白水一杯秋井香。", "楊柳年年人老大，江山處處客淒涼。", "朅來無限興亡事，淚落淮南古戰場。"]'),
('7acd0cf0-6204-4d17-90e0-4dfd20551bab','送魏時中胡才卿還城','吳潛','宋','宋诗','song-poetry','','[]','歲晏謝紛務，掩關慕幽居。',120,'全唐诗/poet.song.209000.json','["歲晏謝紛務，掩關慕幽居。", "於道良未親，養真聊自娛。", "孰謂雙彥來，南征千里餘。", "忻然肯相過，脩贄期讀居。", "媿無一日長，幸與斯文俱。", "溫溫石中玉，皎皎淵底珠。", "至瑶豈易求，欲速非良圖。", "雨餘浮新綠，風暖勾萌舒。", "閒齋對泮水，感物懷倚閭。", "即此悟明德，遠遊竟何如。"]'),
('daad4737-7398-467c-be34-d199465a455c','謝世詩二首  其一','吳潛','宋','宋诗','song-poetry','','[]','股肱十載竭丹心，諫草雖多禍亦深。',64,'全唐诗/poet.song.209000.json','["股肱十載竭丹心，諫草雖多禍亦深。", "補衮每思期仲甫，殺人未必是曾參。", "氈裘浩蕩紅塵滿，風雨淒涼紫殿陰。", "遥望諸陵荒草隔，不堪老淚灑衣襟。"]'),
('fea80f2b-e79c-417b-bbb9-a5057e2d1d9e','謝世詩二首  其二','吳潛','宋','宋诗','song-poetry','','[]','邊馬南來動北風，屢陳長策矢孤忠。',64,'全唐诗/poet.song.209000.json','["邊馬南來動北風，屢陳長策矢孤忠。", "群豺橫暴嘉謀遏，儀鳳高飛事業空。", "愁恨暗消榕樹綠，寸心漫擬荔枝紅。", "欲知千載英雄氣，盡在風雷一夜中。"]'),
('0a83780c-d76d-46a6-bfac-3e27734016cb','句  其一','吳潛','宋','宋诗','song-poetry','','[]','故園芳事無人管，到處梅花動客情。',16,'全唐诗/poet.song.209000.json','["故園芳事無人管，到處梅花動客情。"]'),
('4ff6380b-0f10-41f3-a207-69f52e4536f2','句  其二','吳潛','宋','宋诗','song-poetry','','[]','粲粲黄金裾，亭亭白玉膚。',36,'全唐诗/poet.song.209000.json','["粲粲黄金裾，亭亭白玉膚。", "極知時好異，擬與歲寒俱。", "墮地良不忍，抱枝寧自枯。"]'),
('d85a5660-48fb-4352-91c3-674e0f3fa7e0','句  其三','吳潛','宋','宋诗','song-poetry','','[]','可堪收拾歸屏枕，頗欲浮沈付酒杯。',16,'全唐诗/poet.song.209000.json','["可堪收拾歸屏枕，頗欲浮沈付酒杯。"]'),
('2d22980e-8bba-40fc-b22c-c2108e5e724a','句  其四','吳潛','宋','宋诗','song-poetry','','[]','邂逅一杯酒，東風柳絮天。',12,'全唐诗/poet.song.209000.json','["邂逅一杯酒，東風柳絮天。"]'),
('f07ea6c2-91c1-4307-be4d-cb4f8e2ac126','酬陳校書見寄','趙希邁','宋','宋诗','song-poetry','','[]','日長松院靜，孤坐對殘編。',48,'全唐诗/poet.song.209000.json','["日長松院靜，孤坐對殘編。", "雨久波平岸，山高燒接天。", "春酲茶可解，詩病藥難痊。", "獨喜君清政，南中客共傳。"]'),
('2a32f41d-63fb-451d-8bb9-ca70b9a088e1','白鶴關','趙希邁','宋','宋诗','song-poetry','','[]','危亭石作關，假道一躋攀。',48,'全唐诗/poet.song.209000.json','["危亭石作關，假道一躋攀。", "白鶴何年去，青松盡日閒。", "坐時聞遠水，望處小他山。", "衲子雲衣厚，寒猶宿此間。"]'),
('a0ffeb66-d9c0-4272-8912-72b1a081af43','贈劉隠居','趙希邁','宋','宋诗','song-poetry','','[]','幽居雜嶺雲，清過晉時人。',48,'全唐诗/poet.song.209000.json','["幽居雜嶺雲，清過晉時人。", "學苦常如病，家和不見貧。", "雪消崖溜急，春近燒痕新。", "寒燭半明滅，通宵語意真。"]'),
('4253587c-62ef-49ec-89dc-0b5babceab64','昆湖夜歸','趙希邁','宋','宋诗','song-poetry','','[]','渡湖歸古縣，一望水程賒。',48,'全唐诗/poet.song.209000.json','["渡湖歸古縣，一望水程賒。", "月正帆無影，風橫浪有花。", "寒更知戍屋，野火是漁家。", "擬待春洲暖，重來採荻芽。"]'),
('7139f9b9-e5d4-4110-a1b1-7fc43a7a4586','山縣','趙希邁','宋','宋诗','song-poetry','','[]','山縣渾如野客家，遊蜂數點趁朝衙。',32,'全唐诗/poet.song.209000.json','["山縣渾如野客家，遊蜂數點趁朝衙。", "簿書押了無公事，小吏呼來掃落花。"]'),
('c428bee9-8ed4-4bcc-8044-1025cdc0b406','五斗','趙希邁','宋','宋诗','song-poetry','','[]','五斗驅將五嶺來，蕭蕭老屋枕岩隈。',64,'全唐诗/poet.song.209000.json','["五斗驅將五嶺來，蕭蕭老屋枕岩隈。", "風高松子和釵落，地暖梅花带葉開。", "短鬢吟邊從似雪，壯心客裏漸成灰。", "官身縱使多塵事，亦許偷閑踏徑苔。"]'),
('25ad9961-d195-43c7-adc6-fbf11c2ff519','携家','趙希邁','宋','宋诗','song-poetry','','[]','携家經月尚羈程，隨處風光似有情。',64,'全唐诗/poet.song.209000.json','["携家經月尚羈程，隨處風光似有情。", "一石峭從平地起，數禽飛入半天鳴。", "春生草樹洲添綠，船載詩人水倍清。", "晚泊別無消遣處，自酤村酒對花傾。"]'),
('22d2852a-c87b-4472-a146-b758a95689a5','梧梅渡','趙希邁','宋','宋诗','song-poetry','','[]','鬰鬰棲鳳枝，青青止渴林。',60,'全唐诗/poet.song.209000.json','["鬰鬰棲鳳枝，青青止渴林。", "兩樹交江濆，敷爲十畝陰。", "朱光燦萬宇，喚渡人煩襟。", "一憇爽烏匼，方知樹德心。", "嘉哉建安子，繁衍徵在今。"]'),
('199012a4-b158-4a8d-af44-1e9c8e30e22c','王生山水歌','趙希邁','宋','宋诗','song-poetry','','[]','范寬山頭李成樹，百年二老皆仙去。',192,'全唐诗/poet.song.209000.json','["范寬山頭李成樹，百年二老皆仙去。", "如今尺素留人間，縱有千金無博處。", "後人筆底工一家，聲價隨可喧中華。", "王君二妙聚一手，參以吟思遊天涯。", "萬里江山纔數幅，東抹西塗意先足。", "蒼梢癩石相參差，風雨烟雲在覊束。", "近時目賤耳反真，畫圖重舊不重新。", "名家翰墨未必貴，塵漬贋本翻爲珍。", "君提健筆來海外，山若玉簪江爲带。", "朝昏變態焉可窮，筆未鋪張心已會。", "嶺南遊者多詩人，見君作畫應憐君。", "求我新詩寫君畫，終使李范聲名分。"]'),
('0865dde8-13b0-4a1a-9ec8-ebd9888c97e4','琴川精舍寄城中友人','趙希邁','宋','宋诗','song-poetry','','[]','客來僧已去，古屋靜蕭蕭。',48,'全唐诗/poet.song.209000.json','["客來僧已去，古屋靜蕭蕭。", "敲石引松火，對花懸酒瓢。", "窗櫺寒背日，柱礎潤通潮。", "君肯過幽寂，水程纔隔宵。"]'),
('b3fcee68-dd6e-470b-88dd-d39eb5065e9c','吳中中秋懷瓜廬諸友','趙希邁','宋','宋诗','song-poetry','','[]','凉分一半秋，此夜客吳州。',48,'全唐诗/poet.song.209000.json','["凉分一半秋，此夜客吳州。", "無侶共明月，喚僧同倚樓。", "天虛雲氣盡，風靜桂香浮。", "遥憶前年醉，狂吟滄海頭。"]'),
('71e5db0d-207f-42a9-946c-89302e626f5d','小泊毗陵西郊即事','趙希邁','宋','宋诗','song-poetry','','[]','臘盡客蕭蕭，繫船當遠郊。',48,'全唐诗/poet.song.209000.json','["臘盡客蕭蕭，繫船當遠郊。", "凍苔龜曝日，古樹鵲營巢。", "野老掃寒屋，騷人寄午庖。", "不知何所見，能索近詩抄。"]'),
('403b7297-9e31-4048-886f-3bfd42e35345','新夏','趙希邁','宋','宋诗','song-poetry','','[]','四月寒猶在，日高常掩扉。',48,'全唐诗/poet.song.209000.json','["四月寒猶在，日高常掩扉。", "縱收風外絮，難暖客中衣。", "新竹笋多瘦，殘梢花最肥。", "有情雙燕子，能認舊巢歸。"]'),
('efa905b8-ee2b-4ac2-bd57-65628159ddaa','小桃源','趙希邁','宋','宋诗','song-poetry','','[]','亂崖懸怪木，地勝絕纖塵。',48,'全唐诗/poet.song.209000.json','["亂崖懸怪木，地勝絕纖塵。", "曾有昇仙者，寧無避世人。", "湍流因過雨，啼鳥但如春。", "誰種桃千樹，荒碑記不真。"]'),
('ac5b9552-a7f3-452c-8d41-03a0ef6fc63c','宿溪村書齋','趙希邁','宋','宋诗','song-poetry','','[]','故人能下榻，爲喜客相過。',48,'全唐诗/poet.song.209000.json','["故人能下榻，爲喜客相過。", "不住夜泉滴，常疑春雨多。", "風來琴自響，冰合硯難磨。", "明日還分袂，覊吟誰共哦。"]'),
('0b47c1f0-895d-41f5-ab96-1794f9abcfcc','南臺徐靈暉徐靈淵皆有作','趙希邁','宋','宋诗','song-poetry','','[]','山峭石臺平，天低可摘星。',48,'全唐诗/poet.song.209000.json','["山峭石臺平，天低可摘星。", "岸回分水勢，城缺見州形。", "曉樹來孤鶴，春吟憶二靈。", "客行貪訪古，柳下一舟停。"]'),
('b981af6c-e4ae-4907-acc4-2ebcfe4fc2ba','慧力寺','趙希邁','宋','宋诗','song-poetry','','[]','出郭無多路，縈迴入翠微。',48,'全唐诗/poet.song.209000.json','["出郭無多路，縈迴入翠微。", "水邊寒艇泊，松下老僧歸。", "藏古神抄供，亭幽客掩扉。", "自來還自咏，不覺到斜暉。"]'),
('90fea566-44f1-49c1-b25f-6c5f55338200','贈沈兢','趙希邁','宋','宋诗','song-poetry','','[]','僦居初不惡，門巷接溪灣。',48,'全唐诗/poet.song.209000.json','["僦居初不惡，門巷接溪灣。", "有譜曾評菊，無錢可買山。", "吟驅生計拙，愁積鬢毛斑。", "遠示諸名作，閒題馹寄還。"]'),
('b96cdfee-1ce9-4cdd-af49-4e275d79d4be','黄姚灘','趙希邁','宋','宋诗','song-poetry','','[]','數客同吟棹，覊懷得少寬。',48,'全唐诗/poet.song.209000.json','["數客同吟棹，覊懷得少寬。", "山晴平眺遠，灘澀泝流難。", "饑鵲窺茶鼎，游魚識釣竿。", "天南風土別，晚歲未全寒。"]'),
('3f45bdc4-4950-41fc-885e-7d396ecc534b','瀟湘寺','趙希邁','宋','宋诗','song-poetry','','[]','古剎枕瀟湘，閑吟步墅廊。',48,'全唐诗/poet.song.209000.json','["古剎枕瀟湘，閑吟步墅廊。", "蘚封巖石老，松落井泉香。", "采蜜蜂歸晚，赴齋雀亦忙。", "主僧同里社，十歲已離鄉。"]'),
('44fdf7b1-a3df-494e-af1d-2b75985c83df','次昭城','趙希邁','宋','宋诗','song-poetry','','[]','郡小人烟密，來游契所聞。',48,'全唐诗/poet.song.209000.json','["郡小人烟密，來游契所聞。", "城因山勢築，江向廟頭分。", "凍葦聲如雨，春泉氣似雲。", "梅公堂上酒，客裏易成醺。"]'),
('40a1d697-7bdf-4c94-a0cf-f65a282cbe3c','夜分','趙希邁','宋','宋诗','song-poetry','','[]','夜分天籟寂，誰與共襟期。',48,'全唐诗/poet.song.209000.json','["夜分天籟寂，誰與共襟期。", "童子醉眠處，老夫吟苦時。", "雲黏蒼蘚石，月掛老松枝。", "一鶴來何處，相從立水湄。"]'),
('503a322e-c67b-429c-9e12-3f82a7eb75ba','深村','趙希邁','宋','宋诗','song-poetry','','[]','道傍無驛舍，投宿向深村。',48,'全唐诗/poet.song.209000.json','["道傍無驛舍，投宿向深村。", "閒喚鄰翁語，翛然古意存。", "半籬花隔水，數畝竹當門。", "傳說岡頭樹，時留虎爪痕。"]'),
('d9e42670-5e5d-4d2b-9e7a-e7353c7ab555','蕪','趙希邁','宋','宋诗','song-poetry','','[]','數間吟屋就，謝爾肯相依。',48,'全唐诗/poet.song.209000.json','["數間吟屋就，謝爾肯相依。", "巢穩迎人語，身輕掠水飛。", "漂流皆是客，來去兩忘機。", "何事拋珠箔，欣然戀竹扉。"]'),
('b5c126b4-f446-4a54-a0ba-c48db579e8eb','蛙','趙希邁','宋','宋诗','song-poetry','','[]','閒池草色青，蝌蚪自滋生。',48,'全唐诗/poet.song.209000.json','["閒池草色青，蝌蚪自滋生。", "尚覺窺天小，何因妬月明。", "通宵成樂部，過雨雜棋聲。", "靜者心無役，從君取意鳴。"]'),
('f63c8971-ed49-4c04-9c64-cef87e375152','晚立池上','趙希邁','宋','宋诗','song-poetry','','[]','身與沙鷗一樣閑，每來池上獨凭闌。',64,'全唐诗/poet.song.209000.json','["身與沙鷗一樣閑，每來池上獨凭闌。", "葯苗得雨侵苔綠，楮實逢秋似荔丹。", "酒欠好懷狂飲少，詩因多病苦思難。", "虛廊日晚人稀到，風約蜻蜓泊釣竿。"]'),
('9aa7e68a-d5fe-4817-a628-2556a4be6fa5','雪夜吟竹屋因約友人明日登楚臺','趙希邁','宋','宋诗','song-poetry','','[]','只許吟蹤向此來，逕無吟屐損蒼苔。',64,'全唐诗/poet.song.209000.json','["只許吟蹤向此來，逕無吟屐損蒼苔。", "雪明霜樹清於月，人滌茶甌瘦似梅。", "古瓦旋磨成硯璞，腐桐新琢作琴材。", "曉晴不管寒侵骨，儗看湘山上楚臺。"]'),
('aad82d24-16c2-43f6-a021-5d53202786ae','汀畔','趙希邁','宋','宋诗','song-poetry','','[]','墅梅汀畔客帆過，歲晚天南氣候和。',64,'全唐诗/poet.song.209000.json','["墅梅汀畔客帆過，歲晚天南氣候和。", "江合湘灕流水急，山藏洞壑吐雲多。", "村家釀酒連醅濁，小吏抄詩覺字訛。", "幾點白鷗清似畫，對人飛下泊寒莎。"]'),
('4ece44d7-86b5-43af-b618-38bd7553c7aa','偶得','趙希邁','宋','宋诗','song-poetry','','[]','村邑蕭條廨屋低，茆牆缺處補荆籬。',64,'全唐诗/poet.song.209000.json','["村邑蕭條廨屋低，茆牆缺處補荆籬。", "市添人語當墟日，田捲車筒漫種時。", "公事偶無封印早，小胥習懶赴衙遲。", "閑行摸索街頭石，尋得前朝一片碑。"]'),
('966d0134-d773-4e19-affa-458abe22ccf3','歲杪','趙希邁','宋','宋诗','song-poetry','','[]','歲杪携家客桂林，鄉山萬里楚雲深。',64,'全唐诗/poet.song.209000.json','["歲杪携家客桂林，鄉山萬里楚雲深。", "甕留臘水供春釀，梅著寒花伴晚吟。", "自笑老來貧不減，誰憐鬢底雪相侵。", "俸錢用處清無敵，半打崖碑半買琴。"]'),
('5f0dc548-102d-4b9f-aa88-67e3f639cdc1','到貴州','趙希邁','宋','宋诗','song-poetry','','[]','涉歷長亭復短亭，兼旬方抵貴州城。',64,'全唐诗/poet.song.209000.json','["涉歷長亭復短亭，兼旬方抵貴州城。", "江從白鷺飛邊轉，雲在青山缺處生。", "家務每因官事廢，詩篇多向客途成。", "耕桑儘自無榮辱，却悔當年事短檠。"]'),
('230dc657-a203-4b2b-9f10-f299d8fa33e4','漁人','趙希邁','宋','宋诗','song-poetry','','[]','問利問名總不知，生涯付與一輪絲。',64,'全唐诗/poet.song.209000.json','["問利問名總不知，生涯付與一輪絲。", "四時風月俱還我，萬頃烟波說向誰。", "霽後短簑和笠晒，醉來長笛倚篷吹。", "此懷惟有詩人識，除却詩人只楚詞。"]'),
('98633b9c-c484-4e4c-9e5e-6994967d72ee','萬頃田','趙希邁','宋','宋诗','song-poetry','','[]','萬頃平田一望中，獨乘瘦馬當吟筇。',64,'全唐诗/poet.song.209000.json','["萬頃平田一望中，獨乘瘦馬當吟筇。", "天連濁霧無非海，地少嚴寒不類冬。", "刺竹滿林生似蝟，古榕臨水卧如龍。", "村家米賤新醅熟，猶及停鞭問老農。"]'),
('695df5ba-4e76-4cf5-8704-30d95e81d1ef','秋風','趙希邁','宋','宋诗','song-poetry','','[]','縱使秋風滿道間，炎州且任客衣單。',64,'全唐诗/poet.song.209000.json','["縱使秋風滿道間，炎州且任客衣單。", "馬行峻嶺如雲度，鷺立枯楂似畫看。", "問盡地名猶跋涉，忽收家信喜平安。", "渡頭沽得茅柴酒，儘可吟邊作醉顔。"]'),
('9fa19c53-c3f0-4cb9-9277-a2fa37c152f1','真娘墓','趙希邁','宋','宋诗','song-poetry','','[]','松林際晚鶴飛回，一片荒碑卧草萊。',32,'全唐诗/poet.song.209000.json','["松林際晚鶴飛回，一片荒碑卧草萊。", "顔色不隨塵土化，澗邊猶有野棠開。"]'),
('7beff12e-1a83-4731-9bd6-3476ab78ad87','老叟','趙希邁','宋','宋诗','song-poetry','','[]','鬢髮如霜心未灰，尚營活計待將來。',32,'全唐诗/poet.song.209000.json','["鬢髮如霜心未灰，尚營活計待將來。", "嶺頭盡日敲松子，猶向山園空處栽。"]'),
('afcf315b-cebc-43f7-83ef-4f40afac444e','書山人居','趙希邁','宋','宋诗','song-poetry','','[]','溪叟山居不計年，半欹茅屋倚雲邊。',32,'全唐诗/poet.song.209000.json','["溪叟山居不計年，半欹茅屋倚雲邊。", "竹溝旋引高源水，灌得門前數畝田。"]'),
('855cee9f-a70e-4617-9af2-a9b3ba495714','山寺看桃','趙希邁','宋','宋诗','song-poetry','','[]','無數桃花傍水栽，水邊新架佛亭臺。',32,'全唐诗/poet.song.209000.json','["無數桃花傍水栽，水邊新架佛亭臺。", "不因橋畔僧相接，只道玄都觀裏來。"]'),
('96bd5bcd-76ac-41d7-bc9a-4f9fbcb03f58','亦文齋竹','趙希邁','宋','宋诗','song-poetry','','[]','疏竹牆邊筍漸添，况逢數日雨廉纖。',32,'全唐诗/poet.song.209000.json','["疏竹牆邊筍漸添，况逢數日雨廉纖。", "粉梢一夜拋寒籜，便有清陰拂短檐。"]'),
('62f772c2-06f2-48fc-8ccd-c1778caaddd9','涌金湯','趙希邁','宋','宋诗','song-poetry','','[]','官與民間一樣貧，空流江水凈如銀。',32,'全唐诗/poet.song.209000.json','["官與民間一樣貧，空流江水凈如銀。", "誰將山裏閒田地，喚作黄金誤世人。"]'),
('563f724c-90be-4b57-8744-7742aff9d7f3','偶得','趙希邁','宋','宋诗','song-poetry','','[]','舊日看山古渡頭，村深無馬但騎牛。',32,'全唐诗/poet.song.209000.json','["舊日看山古渡頭，村深無馬但騎牛。", "如今身被微官縛，欲要騎牛不自由。"]'),
('81306967-7a2a-407f-9d0c-9636c0e96ad3','楊妃井','趙希邁','宋','宋诗','song-poetry','','[]','妃子當年井尚存，誰栽石塔向雲根。',32,'全唐诗/poet.song.209000.json','["妃子當年井尚存，誰栽石塔向雲根。", "春泉不洗開元恨，空與黥兒洗字痕。"]'),
('7d509021-8eec-4aed-a5db-b5404860784c','玉川煎茗圖','趙希邁','宋','宋诗','song-poetry','','[]','一卷殘書自課兒，欹斜茅屋任風吹。',32,'全唐诗/poet.song.209000.json','["一卷殘書自課兒，欹斜茅屋任風吹。", "階頭石鼎煎茶熟，還咏當時月蝕詩。"]'),
('5ac7da4a-ce16-4141-b5ed-713d1b40aeaf','西風','趙希邁','宋','宋诗','song-poetry','','[]','西風溪上雨初收，數葉新紅點樹頭。',32,'全唐诗/poet.song.209000.json','["西風溪上雨初收，數葉新紅點樹頭。", "白鷺作成秋景致，背人飛過蓼花洲。"]'),
('c4fcaebd-ad08-44af-8f42-2cf3633cf169','路轉','趙希邁','宋','宋诗','song-poetry','','[]','路轉楓林積葉深，秋塘漲水綠沉沉。',32,'全唐诗/poet.song.209000.json','["路轉楓林積葉深，秋塘漲水綠沉沉。", "沙鷗却似曾相識，獨立莎汀伴醉吟。"]'),
('ef38aaf9-fb11-4c5f-876b-4e24dfc5838d','南山','李濤','宋','宋诗','song-poetry','','[]','南山思美人也',68,'全唐诗/poet.song.209000.json','["南山思美人也", "彼美人兮，在南山之陽。", "豈不爾思，道阻且長。", "彼美人兮，在南山之側。", "我不見兮，寤寐思服。", "彼美人兮，悠悠我思。", "何以予之，瓊瑰玉佩。"]'),
('e9893154-6f95-430e-b334-e40c4a732610','南山  其一','李濤','宋','宋诗','song-poetry','','[]','彼美人兮，在南山之陽。',21,'全唐诗/poet.song.209000.json','["彼美人兮，在南山之陽。", "豈不爾思，道阻且長。"]'),
('d1968708-d654-4fde-91ef-2da35f41d48b','南山  其二','李濤','宋','宋诗','song-poetry','','[]','彼美人兮，在南山之側。',21,'全唐诗/poet.song.209000.json','["彼美人兮，在南山之側。", "我不見兮，寤寐思服。"]'),
('52325d4e-1b75-4540-aa06-950b3a70e488','南山  其三','李濤','宋','宋诗','song-poetry','','[]','彼美人兮，悠悠我思。',20,'全唐诗/poet.song.209000.json','["彼美人兮，悠悠我思。", "何以予之，瓊瑰玉佩。"]'),
('e9ec3591-7396-478c-9f32-9b64627cce60','登高丘而望遠海','李濤','宋','宋诗','song-poetry','','[]','登高丘，望遠海，萬里長城今何在。',73,'全唐诗/poet.song.209000.json','["登高丘，望遠海，萬里長城今何在。", "坐使神州竟陸沉，夷甫諸人合葅醢。", "望遠海，登高丘。", "知我者謂我心憂，不知我者謂我何求。", "歸枕蓬萊漱弱水，大觀宇宙真蜉蝣。"]'),
('9210e253-1003-4506-8c47-8452f3ab7c09','讀阮籍詠懷十七首','李濤','宋','宋诗','song-poetry','','[]','人生天地間，如花開春時。',108,'全唐诗/poet.song.209000.json','["人生天地間，如花開春時。", "遇晴即欣榮，遇雨還離披。", "晴雨由上蒼，汝花何悲爲。", "顯允阮嗣宗，放達世所推。", "憂思獨傷心，作爲十七詩。", "感慨懷辛酸，似未達天理。", "既好王子喬，又惡輕薄子。", "善善又惡惡，好生而惡死。", "如何得徽稱，口不挂臧否。"]'),
('d9026444-acc7-4fa4-bbbf-16fbd38df153','處事','李濤','宋','宋诗','song-poetry','','[]','處事無心萬象春，任渠逆境自橫陳。',64,'全唐诗/poet.song.209000.json','["處事無心萬象春，任渠逆境自橫陳。", "籠中無療家貧藥，門外有催詩債人。", "酒盞闊疏瓶久卧，文書散亂案多塵。", "生前富貴非吾願，肯學癡人問大鈞。"]'),
('9cd64168-6d5d-42ad-a604-337f4e31e624','詩社中有赴補者','李濤','宋','宋诗','song-poetry','','[]','有詩千首可成名，萬戶侯封亦可輕。',64,'全唐诗/poet.song.209000.json','["有詩千首可成名，萬戶侯封亦可輕。", "自是高標凌富貴，肯隨餘子逐恩榮。", "君遊璧水甘芳餌，僕爲銓衡上玉京。", "水鏡蘭坡各求第，詩盟似未十分清。"]'),
('083d6e89-6e4d-43b7-bfcb-a461a45eeb17','新年開義館教族屬子姪作詩勉之','李濤','宋','宋诗','song-poetry','','[]','日與聖賢居，其中樂有餘。',48,'全唐诗/poet.song.209000.json','["日與聖賢居，其中樂有餘。", "但存三寸舌，讀盡五車書。", "學問勝金璧，功名特土苴。", "先當分義利，毋作小人儒。"]'),
('1549d236-b26c-4e94-9426-7feb76ac4bab','蘭坡過省','李濤','宋','宋诗','song-poetry','','[]','俯隨韁鎖就科名，可笑蘭坡未苦清。',64,'全唐诗/poet.song.209000.json','["俯隨韁鎖就科名，可笑蘭坡未苦清。", "不管北山怨猿鶴，竟從南海掣鰲鯨。", "賞延于世愧在我，思濟斯民同此情。", "軒冕儻來來則受，未來猶可以詩鳴。"]'),
('d73449de-ede0-42ea-afc6-df73261e8ba7','詩友作涉江采夫容觸撥鄙思亦成一首','李濤','宋','宋诗','song-poetry','','[]','涉江采夫容，江水濕我衣。',60,'全唐诗/poet.song.209000.json','["涉江采夫容，江水濕我衣。", "厲揭不敢憚，將以遺所思。", "所思不我見，持此將安歸。", "野花逞姿媚，衆好紛莫違。", "此物何足歎，但傷愛者稀。"]'),
('ac706ec3-3d39-4cbc-9848-077d7290404a','春晝回文一首','李濤','宋','宋诗','song-poetry','','["\u6625\u5929"]','茶餠嚼時香透齒，水沉燒處碧凝烟。',32,'全唐诗/poet.song.209000.json','["茶餠嚼時香透齒，水沉燒處碧凝烟。", "紗窗閉著猶慵起，極困新晴乍雨天。"]'),
('9fc41a04-f17f-4dac-a318-7bc145f0ab55','贈染花徐仲湘','李濤','宋','宋诗','song-poetry','','[]','頃刻花開奕葉光，花間奇字兆災祥。',32,'全唐诗/poet.song.209000.json','["頃刻花開奕葉光，花間奇字兆災祥。", "神仙幻術從來有，昔日韓湘今仲湘。"]'),
('b498dd5b-adf7-4a85-bba6-8ce4b3039c1d','雜詩十首  其一','李濤','宋','宋诗','song-poetry','','[]','滔滔東流水，赴海無歸期。',48,'全唐诗/poet.song.209000.json','["滔滔東流水，赴海無歸期。", "亭亭右轉日，今茲復來茲。", "人生寄天地，百年七十稀。", "思慮復營營，恐爲達者嗤。"]'),
('29267008-07fa-48bf-9b0d-523d40c841a8','雜詩十首  其二','李濤','宋','宋诗','song-poetry','','[]','燕雀賀厦屋，蟲蟻慕腥羶。',48,'全唐诗/poet.song.209000.json','["燕雀賀厦屋，蟲蟻慕腥羶。", "野花引飛蝶，古木來嘶蟬。", "秋天百蟲吟，春天百禽喧。", "翟公真闇事，喜慍見色言。"]'),
('3e1010ba-777b-4c18-8417-a962c47ddbc1','雜詩十首  其三','李濤','宋','宋诗','song-poetry','','[]','明主不棄士，我自志山林。',48,'全唐诗/poet.song.209000.json','["明主不棄士，我自志山林。", "爵服豈無華，才疏力難任。", "鳥向深山棲，魚由深淵沉。", "吾亦愛吾廬，高歌復微吟。"]'),
('04f3998a-4cf3-4cb1-af8b-964e22db4e6e','雜詩十首  其四','李濤','宋','宋诗','song-poetry','','[]','深巖有老翁，庬眉鬚鬢雪。',60,'全唐诗/poet.song.209000.json','["深巖有老翁，庬眉鬚鬢雪。", "夜半呼我名，授我微妙訣。", "字畫古籀樣，體勢訛復缺。", "雙眸忽烱烱，須臾竟披閲。", "至今得其傳，心會口難說。"]'),
('b9b10f29-60a7-4735-a685-2eb17093a403','琴書','李濤','宋','宋诗','song-poetry','','[]','琴書隨分足生涯，只灌園畦亦自佳。',64,'全唐诗/poet.song.209000.json','["琴書隨分足生涯，只灌園畦亦自佳。", "行狀是劉斯立記，門風似杜少陵家。", "添詩人瘦因中酒，解睡魔圍只上茶。", "無事出門覓詩料，巡檐指點數梅花。"]'),
('c86075ac-07dc-4e7f-b092-9c2f1620a4ff','寄范稅院倚衡','李濤','宋','宋诗','song-poetry','','[]','清敏當年宰寶唐，至今遺愛在甘棠。',64,'全唐诗/poet.song.209000.json','["清敏當年宰寶唐，至今遺愛在甘棠。", "稅苗有例分三等，吏卒無因下六鄉。", "時異事殊民尚憶，人亡政息事堪傷。", "如今白納重催吏，也坐先生對越堂。"]'),
('74e83fa7-12c7-4fec-b4cc-127f2fa4b428','次韻平埜王子厚登相山不及相過','李濤','宋','宋诗','song-poetry','','[]','兒童傳好語，王子去求仙。',48,'全唐诗/poet.song.209000.json','["兒童傳好語，王子去求仙。", "我住亦邇只，君胡不惠然。", "相望百里外，一別五年前。", "會聚渾閑事，鷺鷗盟要堅。"]'),
('ce3def3b-1b0b-4d0a-aa5d-674d42c7be3b','題袁恭父神心精舍','李濤','宋','宋诗','song-poetry','','[]','山川城郭同一形，市人鴉鵲同一聲。',67,'全唐诗/poet.song.209000.json','["山川城郭同一形，市人鴉鵲同一聲。", "吾身本自備萬物，萬物何有非吾身。", "此心虛徹公則明，事至能應物能名。", "君不見神心精舍袁主人，叱咤風雷呵鬼神。"]'),
('4cc6055d-2969-4334-af22-16a2683a043a','僧本均乞蒙泉稿','李濤','宋','宋诗','song-poetry','','[]','近聞甘子說，僧裏有翛然。',48,'全唐诗/poet.song.209000.json','["近聞甘子說，僧裏有翛然。", "詩學貫休體，心參馬祖禪。", "箇中真有得，名下豈虛傳。", "索我蒙泉稿，因風寄此篇。"]'),
('7070b915-0df9-40fa-b14c-8e5ac7824e3a','題旴江王章甫梅境','李濤','宋','宋诗','song-poetry','','[]','仙伯當年亭植梅，當今天子題品來。',160,'全唐诗/poet.song.209000.json','["仙伯當年亭植梅，當今天子題品來。", "梅花是我丈人行，見梅不賦梅應咍。", "王君結廬在梅境，日與梅兄相追陪。", "吟詩些起逋仙魂，索笑醉銜工部杯。", "吾聞梅乃萬木母，桃爲奴婢李輿臺。", "一陽生子萬物始，梅花獨先群卉開。", "一陰生午萬物成，梅實獨先群蘤胎。", "華實先天天不違，梅之時義大矣哉。", "紛紛餘子不知本，祗說百花頭上魁。", "此語聞之梅亭翁，錄以贈君君勿推。"]'),
('1b650209-bb1c-4845-8911-55b0491fc57e','爲廣壽長老文傑說嵩溪偈','李濤','宋','宋诗','song-poetry','','[]','隔江招手見高亭，來謁嵩溪聽水聲。',32,'全唐诗/poet.song.209000.json','["隔江招手見高亭，來謁嵩溪聽水聲。", "縱是遠公今不出，也須强起送淵明。"]'),
('bfc7572f-8777-4c08-9a7e-dba0b9be3b1c','爲能仁長老本端說無學偈','李濤','宋','宋诗','song-poetry','','[]','十二時中六不收，了然無一事爲頭。',64,'全唐诗/poet.song.209000.json','["十二時中六不收，了然無一事爲頭。", "禪河既寂無由浪，此岸已離那用舟。", "塵世榮枯真幻夢，涅槃生死是浮漚。", "要知無學用工處，十二時中六不收。"]'),
('3e80fc29-df63-45e2-ad93-7ee8ff2396f6','三月十六日西湖聞杜鵑','李濤','宋','宋诗','song-poetry','','["\u897f\u6e56"]','纔上蘇堤聞杜鵑，杜鵑怪我在天邊。',64,'全唐诗/poet.song.209000.json','["纔上蘇堤聞杜鵑，杜鵑怪我在天邊。", "平生不作功名想，今日胡爲富貴牽。", "辟穀未能那廢食，買山所欲尚無錢。", "但須兩事略如意，便占白雲深處眠。"]'),
('314df84c-833a-495d-b4e6-3870c47960ba','訪林龍發','李濤','宋','宋诗','song-poetry','','["\u897f\u6e56"]','車馬喧闐桃李村，誰人復識老梅尊。',32,'全唐诗/poet.song.209000.json','["車馬喧闐桃李村，誰人復識老梅尊。", "時中只有梅亭姪，來訪西湖處士孫。"]'),
('4f4e43e5-a03f-4dd6-88dc-16909a2e2c6b','大滌洞天留題','朱日新','宋','宋诗','song-poetry','','[]','十年欲到今纔到，九鎖山中稱策筇。',64,'全唐诗/poet.song.209000.json','["十年欲到今纔到，九鎖山中稱策筇。", "白日燃松遊兩洞，清晨洗眼看孤峯。", "心情老矣難爲節，景氣暄然不似冬。", "剩與仙翁有期約，從茲來往定從容。"]'),
('5521f104-dd41-44b7-8274-871c31bd0288','述懷','冷應澂','宋','宋诗','song-poetry','','[]','位列三台貴，旌旄障雨深。',48,'全唐诗/poet.song.209000.json','["位列三台貴，旌旄障雨深。", "仁廉兩個字，忠孝一生心。", "出省輕侯印，歸甯問俸金。", "携家半窗月，撐轉古榕陰。"]'),
('38e8a71d-26f8-4cec-af49-f2b91760f757','謝御賜紫金魚袋烏紗象簡','冷應澂','宋','宋诗','song-poetry','','[]','日映罦罳曉殿深，君恩稠疊駕親臨。',64,'全唐诗/poet.song.209000.json','["日映罦罳曉殿深，君恩稠疊駕親臨。", "褒衣紅濯天機錦，束带黄分內帑金。", "何幸清班容宦轍，自慚白髮點朝簪。", "撥亂致治平生學，消得君王念苦辛。"]'),
('3a17c244-0c92-4b1f-ac98-e7f4431ac2f5','聽月樓','冷應澂','宋','宋诗','song-poetry','','[]','聽月樓高接泰清，樓高聽月最分明。',64,'全唐诗/poet.song.209000.json','["聽月樓高接泰清，樓高聽月最分明。", "轉空軋軏冰輪響，擣藥叮噹玉杵鳴。", "樂奏廣寒音細細，斧侵丹桂韻丁丁。", "更須一派天風起，吹下嫦娥笑語聲。"]'),
('c4a1d6a7-c9a6-494b-bd2b-9ef94684983b','水西村','徐寶之','宋','宋诗','song-poetry','','[]','又過江頭黯淡時，野梅初見雪前枝。',64,'全唐诗/poet.song.209000.json','["又過江頭黯淡時，野梅初見雪前枝。", "水霞錯落書秦篆，煙樹凄迷畫楚辭。", "山店燈殘人亦睡，寒洲月上雁先知。", "自題秋葉尋前夢，薄酒殘蔬當夕炊。"]'),
('34847a33-8c40-46d6-8a18-34c86a69a894','寄李南金','徐寶之','宋','宋诗','song-poetry','','[]','野風摇枯荄，長夜山雨寒。',168,'全唐诗/poet.song.209000.json','["野風摇枯荄，長夜山雨寒。", "夢忽墮千里，扶胥黄木灣。", "美人秋水容，衆芳潔初服。", "海樹鳴騷騷，醉吟瘴雲宿。", "憶昔西窗眠，三谿月如水。", "忽作千日別，人生別能幾。", "有客從南來，說君新况好。", "升沉何足云，令德似爲寶。", "同袍澗谷友，掉臂青雲端。", "而我卧山阿，淡心如露蘭。", "手種麓下梅，半吐欲遲雪。", "再三拂霜紈，待君畫孤潔。", "寄書何時到，歲晚百念中。", "天涯一望斷，雁遠夕陽紅。"]'),
('47a5b479-ffac-4428-8fdf-fb1b3d43d80b','寄潘子善','徐寶之','宋','宋诗','song-poetry','','["\u897f\u6e56"]','少陽一疏折群姦，拂袖歸來日月閑。',64,'全唐诗/poet.song.209000.json','["少陽一疏折群姦，拂袖歸來日月閑。", "誤國小人猶法從，扣閽諸子自賢關。", "是非頗亦通千古，義利那能立兩間。", "若向西湖浮畫舫，好傾巵酒酹孤山。"]'),
('f1f9305a-0830-4bdc-af21-82b0035bb527','寄遠詞二首  其一','徐寶之','宋','宋诗','song-poetry','','[]','江頭風雨多，蘼蕪濕春香。',48,'全唐诗/poet.song.209000.json','["江頭風雨多，蘼蕪濕春香。", "皎皎千里心，閨中春夢長。", "曉城鼓聲發，寄書問河陽。", "君行紫騮老，君母白髮黄。"]'),
('5762bb54-da42-43c8-9335-0f7e6bcbe364','寄遠詞二首  其二','徐寶之','宋','宋诗','song-poetry','','[]','暮堂解羅衣，未洗別時淚。',48,'全唐诗/poet.song.209000.json','["暮堂解羅衣，未洗別時淚。", "燕子雨中歸，春寒門已閉。", "邊城想如此，草色入湖地。", "花前教小郎，已解識侯字。"]'),
('08fde60a-eda7-405e-b16a-473bbc5f907f','題荆公祠','徐寶之','宋','宋诗','song-poetry','','[]','草樹荒凉門半開，管祠人去不曾來。',64,'全唐诗/poet.song.209000.json','["草樹荒凉門半開，管祠人去不曾來。", "漫裝舒國簪貂坐，何似鍾山策蹇回。", "後世詩名高北斗，向時國論冷殘灰。", "近儒作記存東廡，一丈寒碑立翠苔。"]'),
('15d3980e-5dcd-4327-8b18-8ad377127bcf','長沙','徐寶之','宋','宋诗','song-poetry','','[]','冬迫水逾瘦，湘梅岸岸開。',48,'全唐诗/poet.song.209000.json','["冬迫水逾瘦，湘梅岸岸開。", "雲心岳麓樹，雪意定王臺。", "江晚船爭集，山寒使未來。", "漢廷難用少，流落賈生材。"]'),
('7ef54df3-6408-45c1-bc73-28d6188c5d8b','江漲','徐寶之','宋','宋诗','song-poetry','','[]','萬里吳江湘浦圖，一春摹在小村隅。',64,'全唐诗/poet.song.209000.json','["萬里吳江湘浦圖，一春摹在小村隅。", "南山欲霽北山雨，昨日平濤今日湖。", "荻岸出時知水減，桐花過後有寒無。", "老漁心在蒼茫外，夢破三更水鳥呼。"]'),
('fa0d4700-48cb-4381-80b7-b357c1a116e7','秋日溪上','徐寶之','宋','宋诗','song-poetry','','[]','行盡苔階碧甃長，早秋風味入思量。',64,'全唐诗/poet.song.209000.json','["行盡苔階碧甃長，早秋風味入思量。", "蕙香半在空堂夢，荷雨多於別岸凉。", "獨夜玉絃知寂寞，舊愁湘月記微茫。", "採江節晚秋心遠，一舸輕颸過夕陽。"]'),
('7790d39d-ef3c-4120-92e4-0e679b9fe7fa','秋風入我戶','徐寶之','宋','宋诗','song-poetry','','[]','秋風入我戶，翩翩動床帷。',36,'全唐诗/poet.song.209000.json','["秋風入我戶，翩翩動床帷。", "咄唶中夜起，奈何我心悲。", "四海豈不大，傷哉無己知。"]'),
('27b6ee46-8c69-445f-8883-73eb500acc4f','湖上客舍睡起','徐寶之','宋','宋诗','song-poetry','','[]','濕雲冉冉樹藏鴉，秋岸無人小艇斜。',32,'全唐诗/poet.song.209000.json','["濕雲冉冉樹藏鴉，秋岸無人小艇斜。", "細雨入簾新睡起，晚□吹落木犀花。"]'),
('4d321972-3484-40a7-8878-1c121447926b','續湖陰曲','徐寶之','宋','宋诗','song-poetry','','[]','巴滇之馬如游龍，寶鞭裊裊迴如風。',128,'全唐诗/poet.song.209000.json','["巴滇之馬如游龍，寶鞭裊裊迴如風。", "將軍夢斷忽心戰，五騎飛出尋無蹤。", "道旁客姥頭欲白，驚見歸韀如電擊。", "當時天子重丁寧，典午安危爭一刻。", "大寧王氣方中天，南陽青兖森戈鋋。", "金函詔下傳羽檄，狂奴喑死如寒蟬。", "老驥志欲千里伸，晉天不覆鬼蜮臣。", "草間悵望可人土，老却江潭種柳人。"]'),
('110e300a-6d7e-4e85-b19d-4a22e35ed742','句  其一','徐寶之','宋','宋诗','song-poetry','','[]','炊熟風瓢動，吟歸雪硯枯。',12,'全唐诗/poet.song.209000.json','["炊熟風瓢動，吟歸雪硯枯。"]'),
('da190e44-8613-4e1d-b2a4-4efd8102705c','句  其二','徐寶之','宋','宋诗','song-poetry','','[]','盡日飛花急，隔溪芳草深。',12,'全唐诗/poet.song.209000.json','["盡日飛花急，隔溪芳草深。"]'),
('a2a1462b-d5bf-41b1-875a-3041b49b5364','高齋桂窟','洪夢炎','宋','宋诗','song-poetry','','[]','植桂不在多，種德如種樹。',108,'全唐诗/poet.song.209000.json','["植桂不在多，種德如種樹。", "前人能種後人傳，自有清陰滿庭戶。", "高枝淩雲低覆闌，晴光翠色生晝寒。", "人家多愛種桃李，幾日春風紅滿地。", "何如此花開獨遲，蟾宮窟裏秋香細。", "課兒讀書書滿牀，更將幽興引壺觴。", "半酣獨卧高齋下，啼鳥數聲清晝長。"]'),
('847319a2-3bf6-4119-81b3-9e055fdd7802','句  其一','林興宗','宋','宋诗','song-poetry','','[]','最是北來詩料少，地寒難得見梅花。',16,'全唐诗/poet.song.209000.json','["最是北來詩料少，地寒難得見梅花。"]'),
('5f013d81-76e1-46d3-8984-961b0a8112dc','句  其二','林興宗','宋','宋诗','song-poetry','','[]','形容變盡頭如雪，不改當時一寸心。',16,'全唐诗/poet.song.209000.json','["形容變盡頭如雪，不改當時一寸心。"]'),
('5fd1a336-676d-459e-8560-934e44908196','雪後','史嵩之','宋','宋诗','song-poetry','','[]','同雲收萬里，斜日已三竿。',48,'全唐诗/poet.song.209000.json','["同雲收萬里，斜日已三竿。", "有鳥皆潛迹，無風尚送寒。", "晴檐如下雨，枯澗忽鳴湍。", "漸覺山河復，方知世界寬。"]'),
('5c7115ca-7450-4b9f-b12b-72d30e756268','中秋對月','史嵩之','宋','宋诗','song-poetry','','[]','一片瑶光萬里開，停杯追憶謫仙才。',64,'全唐诗/poet.song.209000.json','["一片瑶光萬里開，停杯追憶謫仙才。", "尋常明月不易見，如此中秋能幾來。", "零落故人非白社，登臨何地不瑶臺。", "欲招黄鶴臨風去，爲問霓裳安在哉。"]'),
('68a34371-15b6-45ba-ac72-4002d051694e','宴瓊林苑','史嵩之','宋','宋诗','song-poetry','','[]','鳴蹕高登秋暮天，西郊輦路直如弦。',32,'全唐诗/poet.song.209000.json','["鳴蹕高登秋暮天，西郊輦路直如弦。", "梨園花覆千官醉，愈覺君恩湛湛然。"]'),
('fc4a8b26-1875-45a9-9721-c3e91a6fb9d7','苦雪','薛師魯','宋','宋诗','song-poetry','','[]','六出夫何甚，經旬散野堂。',48,'全唐诗/poet.song.209000.json','["六出夫何甚，經旬散野堂。", "喜心翻作厭，瑞物恐爲殃。", "歲晚思新火，天寒望太陽。", "荒邨風雪裏，頼有隔年糧。"]'),
('efe56f4e-cf57-4b67-b3bb-5ff5832bb3f9','過王處士竹莊','薛師魯','宋','宋诗','song-poetry','','[]','臨流結屋植琅玕，中有高人詠考槃。',64,'全唐诗/poet.song.209000.json','["臨流結屋植琅玕，中有高人詠考槃。", "一曲秋煙青欲滴，滿林春雨翠堪看。", "山僧過乞歸雲杖，漁父來分釣月竿。", "千古王猷惟此癖，但知此外別無歡。"]'),
('ed776790-0f1b-4a55-a605-c3960d105e80','獨居外寢偶薄寒侵體遂賦一律','汪真','宋','宋诗','song-poetry','','[]','參差瓦上溥霜凝，釀得嚴寒漸漸增。',64,'全唐诗/poet.song.209000.json','["參差瓦上溥霜凝，釀得嚴寒漸漸增。", "布被多年渾似鐵，石牀連夜恰如冰。", "杯邀竹葉爲兄弟，帳伴梅花作友朋。", "酒醒依然眠不得，攬衣重整對青燈。"]'),
('d70b6906-d517-48e2-8c23-f3232701a37b','憶父母','汪真','宋','宋诗','song-poetry','','[]','屺岵登來步步悲，百年空有淚雙垂。',64,'全唐诗/poet.song.209000.json','["屺岵登來步步悲，百年空有淚雙垂。", "凄凄葉落秋風曉，寂寂燈昏夜雨時。", "庭院每驚携杖履，羹牆長見畫容儀。", "遥瞻檻外遺蹤在，料得尋常只自知。"]'),
('90cbd431-c9bf-4804-9bb0-5a098ebc8121','題琴書清隠圖','汪真','宋','宋诗','song-poetry','','[]','高人清隠處，不尚滿籝金。',48,'全唐诗/poet.song.209000.json','["高人清隠處，不尚滿籝金。", "一曲閒千古，三冬惜寸陰。", "嘲風神鬼泣，操月鳳凰吟。", "門外知音少，曾來立雪深。"]'),
('0cda939a-a2a3-40ef-8fbb-b601c67e7cdb','輓送縣令歸葬四明','汪真','宋','宋诗','song-poetry','','[]','桂籍青年壓俊英，橋門卒業已成名。',64,'全唐诗/poet.song.209000.json','["桂籍青年壓俊英，橋門卒業已成名。", "九章列秀銅章美，百里春風墨綬榮。", "德及桑麻猶有頌，夢遺琴鶴已無聲。", "故鄉歸去長眠夜，芳草斜陽伴墓銘。"]'),
('4358daee-2067-4aec-9508-9ede3ce132f8','中秋見月','汪真','宋','宋诗','song-poetry','','[]','萬里乾坤雨乍收，冰輪展出碧雲頭。',64,'全唐诗/poet.song.209000.json','["萬里乾坤雨乍收，冰輪展出碧雲頭。", "蟾宮皎潔分明見，桂子婆娑黯裏遊。", "照我獨成孤影客，忘形相占一天秋。", "長懷此夕風光好，不得袁安共泛舟。"]'),
('c0286ac4-4d07-433a-aa32-3c0e004ccddc','題姑婦巖','汪真','宋','宋诗','song-poetry','','[]','羨傳姑婦死爲神，化石真成不壞身。',32,'全唐诗/poet.song.209000.json','["羨傳姑婦死爲神，化石真成不壞身。", "千載兀然巖口立，舉頭指點往來人。"]'),
('1b2fffd6-a97d-4e44-8bcf-e3f2d06562f1','遊姑婦巖','汪真','宋','宋诗','song-poetry','','[]','玄武崖前啟洞天，登登轉望已超然。',64,'全唐诗/poet.song.209000.json','["玄武崖前啟洞天，登登轉望已超然。", "春工著地看如畫，水籟到山聽似弦。", "鳥駕高山呼飲酒，童衙平野舞鞦韆。", "自欣煙火仙都里，得意還來詩一篇。"]'),
('981ef3b1-ba85-4efe-9d41-de8607c930f6','仙都','汪真','宋','宋诗','song-poetry','','[]','萬山高下擅清都，烟火四開總版圖。',64,'全唐诗/poet.song.209000.json','["萬山高下擅清都，烟火四開總版圖。", "白日梯人天上走，青蓮載客水中浮。", "道超形妙稱仙釋，人尚耕桑見婦姑。", "干戈滿路川原靜，何物壺公更一壺。"]'),
('2bda768b-467f-4655-bb5d-c01801f9b1ac','及時行樂歌','汪真','宋','宋诗','song-poetry','','[]','長安今日多英賢，裘馬翩翩羨少年。',136,'全唐诗/poet.song.209000.json','["長安今日多英賢，裘馬翩翩羨少年。", "勳高名勒凌烟閣，霓裳歌舞畫堂前。", "君不見人生百年須曠達，莫負金樽贏白髮。", "又不見對景逢場須盡歡，轉眼光陰一指彈。", "春去春來人易老，今年花比去年好。", "等閒花下且豪吟，笑指乾坤憑潦倒。", "却看世上三萬六千場，幾人身赴蓬萊島。", "蓬萊之島在何方，莫將塵事縈懷抱。"]'),
('77da2884-a6d1-4242-9752-7eac376118ab','知廉州條上邊事落職主管台州崇道觀賦感','劉仕龍','宋','宋诗','song-poetry','','[]','人生百年中，窮通無定迹。',84,'全唐诗/poet.song.209000.json','["人生百年中，窮通無定迹。", "譬如風前花，榮謝亦頃刻。", "當時牧牛豎，尊貴誰與敵。", "顦顇種瓜翁，乃是封侯客。", "丈夫苟得時，糞土成拱璧。", "一朝恩寵衰，黄金失顔色。", "古今諒皆然，我今何歎息。"]'),
('4b5db9b1-ed20-40af-9f32-a54e9b638f2e','停雲軒','錢璧','宋','宋诗','song-poetry','','[]','插空軒檻扁停雲，雲本無心豈解停。',32,'全唐诗/poet.song.209000.json','["插空軒檻扁停雲，雲本無心豈解停。", "斂散卷舒渾在我，本來明月一天青。"]'),
('a708d2a0-aa15-4386-97b3-0d316ac76f7b','過羅首','湯中','宋','宋诗','song-poetry','','[]','山勢迢迢萬馬奔，就寬平處著祇園。',67,'全唐诗/poet.song.209000.json','["山勢迢迢萬馬奔，就寬平處著祇園。", "門無俗駕真堪隠，院有禪僧便不村。", "百頃霜黄收{禾羅}稏，一泓寒綠養蘭蓀。", "我來訪道連宵宿，共撥爐灰仔細論。"]'),
('2e77efe8-4e1f-4a94-9f8e-9996a43c033d','贈久軒提刑江東二首  其一','湯中','宋','宋诗','song-poetry','','[]','三年飲得大江中，更枉輶軒到里中。',64,'全唐诗/poet.song.209000.json','["三年飲得大江中，更枉輶軒到里中。", "訪舊不辭山路險，居今誰有古人風。", "漢胡隠遁藏清叟，瑞節歡迎走野童。", "頼有良朋共樽酒，雍容不與孫文同。"]'),
('54ccd0af-5bc8-49c4-a87c-00d13e09f34f','贈久軒提刑江東二首  其二','湯中','宋','宋诗','song-poetry','','[]','晨登鶴嶺俯平川，暫輟鳴騶看瀑泉。',64,'全唐诗/poet.song.209000.json','["晨登鶴嶺俯平川，暫輟鳴騶看瀑泉。", "自有此山無此客，愧非真隠枉真賢。", "精廬豈但榮三顧，憇木猶應咏百年。", "獨愧庵無煨芋老，鄴侯雖過莫留連。"]'),
('73668a89-1145-4686-8bfe-d8eb02c0195d','句','湯中','宋','宋诗','song-poetry','','[]','金堂玉室相掩映，珠簾翠箔誰褰開。',16,'全唐诗/poet.song.209000.json','["金堂玉室相掩映，珠簾翠箔誰褰開。"]'),
('9d878644-8297-4125-a22c-1656a0bba0a4','王荆公','羅大經','宋','宋诗','song-poetry','','[]','錯認蒼姬六典書，中原從此變蕭疏。',32,'全唐诗/poet.song.209000.json','["錯認蒼姬六典書，中原從此變蕭疏。", "幅巾投老鍾山日，辛苦區區活數魚。"]'),
('b645c039-dfdf-48b7-bfdd-07d16f5fb4ee','彤庭分帛','羅大經','宋','宋诗','song-poetry','','[]','赤子須摩撫，紅塵幾送迎。',48,'全唐诗/poet.song.209000.json','["赤子須摩撫，紅塵幾送迎。", "幕張雲匼匝，車列鑑鮮明。", "豈是朘民血，空教適宦情。", "忍聞分竹者，竭澤自求盈。"]'),
('02b64f36-b5f4-432b-be78-b190838af623','韓范用兵','羅大經','宋','宋诗','song-poetry','','[]','奮髯要斬高郵守，攘臂甘驅好水軍。',32,'全唐诗/poet.song.209000.json','["奮髯要斬高郵守，攘臂甘驅好水軍。", "到得繞牀停轡日，始知心服范希文。"]'),
('21ce5152-1999-448d-be62-edc5ef1d832f','博浪沙','羅大經','宋','宋诗','song-poetry','','[]','不惜黄金募鐵椎，祖龍身在魄先飛。',32,'全唐诗/poet.song.209000.json','["不惜黄金募鐵椎，祖龍身在魄先飛。", "齊田楚項紛紛起，輸與先生第一機。"]'),
('62932691-2d0f-4b7a-9bf5-6934f57f8773','題釣臺二首  其一','羅大經','宋','宋诗','song-poetry','','[]','平生謹敕劉文叔，却與狂奴意氣投。',32,'全唐诗/poet.song.209000.json','["平生謹敕劉文叔，却與狂奴意氣投。", "激發潛龍雲雨志，了知功跨鄧元侯。"]'),
('9b7529ac-b72c-4f4f-92a6-e30aaf7276ac','題釣臺二首  其二','羅大經','宋','宋诗','song-poetry','','[]','講磨潛佐漢中興，豈是空標處士名。',32,'全唐诗/poet.song.209000.json','["講磨潛佐漢中興，豈是空標處士名。", "堪笑史臣無卓識，却將周黨與同稱。"]'),
('5a448c89-40ed-462b-add5-0d82eb170064','貓捕鼠','羅大經','宋','宋诗','song-poetry','','[]','陋室偏遭黠鼠欺，狸奴雖小策勳奇。',32,'全唐诗/poet.song.209000.json','["陋室偏遭黠鼠欺，狸奴雖小策勳奇。", "扼喉莫訝無遺力，應記當年骨醉時。"]'),
('418e0453-d029-4767-9b76-852fba6d9d8d','和謝處厚','羅大經','宋','宋诗','song-poetry','','[]','殺胡快劍是清謳，牛渚依然一片秋。',32,'全唐诗/poet.song.209000.json','["殺胡快劍是清謳，牛渚依然一片秋。", "却恨荷花留玉輦，竟忘煙柳汴宮愁。"]'),
('cef25ceb-8ed6-4a5c-92f4-3d21701fc487','黄綿襖','羅大經','宋','宋诗','song-poetry','','[]','范叔綿袍暖一身，大裘只蓋洛陽人。',32,'全唐诗/poet.song.209000.json','["范叔綿袍暖一身，大裘只蓋洛陽人。", "九州四海黄綿襖，誰似天公賜予均。"]'),
('de947446-d10e-461c-a4b4-24cd1d15158a','濮議','羅大經','宋','宋诗','song-poetry','','[]','濮園議起沸烏臺，傳語歐公莫怨猜。',32,'全唐诗/poet.song.209000.json','["濮園議起沸烏臺，傳語歐公莫怨猜。", "須記上坡持橐日，也曾尋探好題來。"]'),
('00ddd0b7-8f0c-4522-9668-e9f4b8afae5c','茶聲','羅大經','宋','宋诗','song-poetry','','[]','松風檜雨到來初，急引銅瓶離竹爐。',32,'全唐诗/poet.song.209000.json','["松風檜雨到來初，急引銅瓶離竹爐。", "待得聲聞俱寂後，一甌春雪勝醍醐。"]'),
('4ca48a99-bc8b-4e4a-a394-cf51e0735937','酒有和勁','羅大經','宋','宋诗','song-poetry','','[]','小槽真珠太森嚴，兵厨玉友專甘醇。',192,'全唐诗/poet.song.209000.json','["小槽真珠太森嚴，兵厨玉友專甘醇。", "兩家風味欠商略，偏剛偏柔俱可憐。", "使君袖有轉物手，鸕鷀杓中平等分。", "更憑石髓媒妁之，混融併作一家春。", "季良不用笑伯高，張竦何必譏陳遵。", "時中便是尼父聖，孤竹柳下成一人。", "平雖有智難獨任，勃也未可嫌少文。", "黄龍丙魏要兼用，姚宋相濟成開元。", "試將此酒反觀我，胸中問學當日新。", "更將此酒達觀國，宇宙皆可歸經綸。", "書生觸處便饒舌，以一貫萬如斲輪。", "使君聞此却絕倒，罰以太白眠金尊。"]'),
('e7c31e3e-b7cf-4b73-a97e-2b3d54e138c0','陪桂林伯趙季仁遊桂林暗洞列炬數百隨以鼓吹市人從之者以千計巳而入申而出入自曾公巖出于棲霞洞入若深夜出乃白晝恍如隔宿異世季仁索余賦詩紀之','羅大經','宋','宋诗','song-poetry','','[]','瑰奇恣搜討，貝闕青瑶房。',144,'全唐诗/poet.song.209000.json','["瑰奇恣搜討，貝闕青瑶房。", "方隘疑永巷，俄敞如華堂。", "玉橋巧橫溪，瓊戶正當窗。", "仙佛肖彷彿，鐘鼓鏗擊撞。", "贔贔左顧龜，狺狺欲吠庬。", "丹竈儼亡恙，芝田藹生香。", "搏噬千怪聚，絢爛五色光。", "更無一塵涴，但覺六月凉。", "玲瓏穿數路，屈曲通三湘。", "神鬼工剜刻，乾坤真混茫。", "入如夜漆暗，出乃日珠光。", "隔世疑恍惚，異境難揣量。"]'),
('c5c0b5b9-2f4a-4e23-9af3-39ef9c8989bf','韓平原','羅大經','宋','宋诗','song-poetry','','[]','齋壇一鉞底須慳，坐見諸賢散似煙。',32,'全唐诗/poet.song.209000.json','["齋壇一鉞底須慳，坐見諸賢散似煙。", "不使慶元爲慶曆，也由人事也由天。"]'),
('f081c129-3d71-4e53-93ea-b3edf04c574c','從趙季仁游洞作','羅大經','宋','宋诗','song-poetry','','[]','瑰奇恣搜貝千趾，老仙遺祠邈誰始。',72,'全唐诗/poet.song.209000.json','["瑰奇恣搜貝千趾，老仙遺祠邈誰始。", "後繼述之□□李，異枝同根隆復祉。", "巨畫更鑱埒前美，紫氣臨關西未止。", "張留著書繄尹喜，末孫銘焉適當爾，附名崖端永不毀。"]'),
('16de9473-409d-4b0b-89b5-feb4f4ae85bf','舟行野景','羅大經','宋','宋诗','song-poetry','','[]','數間茅屋带烟雲，一片秋光惹翠蘋。',32,'全唐诗/poet.song.209000.json','["數間茅屋带烟雲，一片秋光惹翠蘋。", "鶴髮漁翁猶結網，世間何處有閑人。"]'),
('637b167a-b356-4982-92d9-d62a4b07eb56','句  其一','羅大經','宋','宋诗','song-poetry','','[]','日占出海時，月驗仰瓦體。',12,'全唐诗/poet.song.209000.json','["日占出海時，月驗仰瓦體。"]'),
('60b9714d-6aad-4e2c-aacb-ae3c37cb22d2','句  其二','羅大經','宋','宋诗','song-poetry','','[]','臭襪終須來塞口，枉收八百斛胡椒。',16,'全唐诗/poet.song.209000.json','["臭襪終須來塞口，枉收八百斛胡椒。"]'),
('93e3b703-5f5a-491e-8d14-734f2d2c5c52','池鷗','太學生','宋','宋诗','song-poetry','','[]','朝來池上有斯事，火急報教同舍知。',32,'全唐诗/poet.song.209000.json','["朝來池上有斯事，火急報教同舍知。", "昨夜雨餘春水滿，白鷗飛下立多時。"]'),
('524e840b-e904-4ac1-af1a-0c652d3a2fc0','詩一首','住山僧','宋','宋诗','song-poetry','','[]','方丈前頭掛草鞋，流行坎止任安排。',32,'全唐诗/poet.song.209000.json','["方丈前頭掛草鞋，流行坎止任安排。", "老僧脚底從來闊，未必枯髏就此埋。"]'),
('63d711b7-eeda-4638-9012-9fff51224e66','句','陳顯伯','宋','宋诗','song-poetry','','[]','分明貯秋汀一角。',8,'全唐诗/poet.song.209000.json','["分明貯秋汀一角。"]'),
('5a3325e2-5f30-4903-be74-2e7c51d739bd','葵花','吳子良','宋','宋诗','song-poetry','','[]','花生初咫尺，意思已尋丈。',24,'全唐诗/poet.song.209000.json','["花生初咫尺，意思已尋丈。", "一日復一日，看看衆花上。"]'),
('2801802d-08d2-418e-b826-b8b248050e02','林和靖祠','吳子良','宋','宋诗','song-poetry','','[]','松樹高低逐徑斜，祠堂牢落鎖煙霞。',32,'全唐诗/poet.song.209000.json','["松樹高低逐徑斜，祠堂牢落鎖煙霞。", "我來閒詠梅花句，想見此翁如此花。"]'),
('a145e942-6b08-41c8-8b8f-9b85fab978b6','句','吳子良','宋','宋诗','song-poetry','','[]','問花何事人偏愛，會遇淵明把玩來。',16,'全唐诗/poet.song.209000.json','["問花何事人偏愛，會遇淵明把玩來。"]'),
('a8da6020-0a15-466c-9225-2d567a45b64e','寬民堂','顔耆仲','宋','宋诗','song-poetry','','[]','聖訓昭垂本至仁，此堂取義立名新。',64,'全唐诗/poet.song.209000.json','["聖訓昭垂本至仁，此堂取義立名新。", "通商有道能徠遠，計利無心蓋爲民。", "寬賜一分皆德意，奉行兩字屬微臣。", "年年寶貨千般集，好是熙臺到處春。"]'),
('43840c38-581c-4166-9d5d-28654d350ff6','喜雨軒','顔耆仲','宋','宋诗','song-poetry','','[]','六月炎炎苦旱災，斯民何罪守非材。',64,'全唐诗/poet.song.209000.json','["六月炎炎苦旱災，斯民何罪守非材。", "爐煙未斷濃雲合，神物潜驅好雨來。", "苗槁復蘇青易見，鬢愁雖喜白難回。", "也知慰我三農望，膏澤應須徧九垓。"]'),
('016ce3d1-b607-471c-b470-eb651969c987','同友人訪石室','趙彥鈕','宋','宋诗','song-poetry','','[]','怪石嵯峨勢若擎，天成斗室一蓬瀛。',64,'全唐诗/poet.song.209000.json','["怪石嵯峨勢若擎，天成斗室一蓬瀛。", "掃門常得風爲帚，照夜從教月作燈。", "三伏人於冰上立，四時鳥在洞中鳴。", "來茲欲避人間世，嘯傲煙霞豁性靈。"]'),
('41c92bc5-ccd4-4b88-90f9-33cdc3b488be','見日庵舊址','師顯行','宋','宋诗','song-poetry','','[]','跨鶴驂鸞訪穉川，松風吹散鐵橋煙。',64,'全唐诗/poet.song.209000.json','["跨鶴驂鸞訪穉川，松風吹散鐵橋煙。", "聯登百步眼萬里，長嘯一聲身九天。", "倚大石樓敲竹杖，躡飛雲頂著吟鞭。", "而今飽挹羅浮秀，未服靈丹亦是仙。"]'),
('f9036e32-df37-4692-9164-1517328aa3ba','題武夷  其一','馮端榮','宋','宋诗','song-poetry','','[]','繰得春蠶不值錢，幾時南畝解豐年。',32,'全唐诗/poet.song.209000.json','["繰得春蠶不值錢，幾時南畝解豐年。", "小臣無計紓民力，稽首虛皇一炷烟。"]'),
('50a78ecc-61c9-431f-8e77-0339dbeaee3d','題武夷  其二','馮端榮','宋','宋诗','song-poetry','','[]','花滿晴烟樹滿雲，我來寧是學仙人。',32,'全唐诗/poet.song.209000.json','["花滿晴烟樹滿雲，我來寧是學仙人。", "願將九曲溪頭水，散作年年百里春。"]'),
('4a16538c-891d-406f-8a4d-75323b9fddce','句','洪天錫','宋','宋诗','song-poetry','','[]','平生要識瓊崖面，到此當堅鐵石心。',16,'全唐诗/poet.song.209000.json','["平生要識瓊崖面，到此當堅鐵石心。"]'),
('cf35f6a5-f89d-49f3-af05-19505d2f3ce3','送韓時齋赴京湖幕','章琰','宋','宋诗','song-poetry','','[]','凄其秋已晚，塞草青欲黄。',132,'全唐诗/poet.song.209000.json','["凄其秋已晚，塞草青欲黄。", "出門褰君衣，問君何遑遑。", "捷書來古峴，談笑復古疆。", "功名有斯會，寧計道路長。", "思昔君之祖，尺箠笞西羌。", "當時軍中謠，豈在甲兵强。", "慷慨懷前烈，膏秣趣晨裝。", "掀髯作遠役，匪爲官爵忙。", "淚碑吊叔子，草廬訪南陽。", "世豈無若人，君豈問老龐。", "吾能送君去，不能共君航。"]'),
('2837e257-7683-4811-8537-7eaee0209b45','登第後畫師以冠裳寫真戲題','李南金','宋','宋诗','song-poetry','','[]','落魄江湖十二年，布衫闊袖裹風烟。',32,'全唐诗/poet.song.209000.json','["落魄江湖十二年，布衫闊袖裹風烟。", "如今各樣新裝束，典却清狂賣却顛。"]'),
('d54c38f4-c479-468f-835b-11b8653b6ec1','江頭吟','李南金','宋','宋诗','song-poetry','','[]','兒時盛氣高於山，不信壯士有饑寒。',145,'全唐诗/poet.song.209000.json','["兒時盛氣高於山，不信壯士有饑寒。", "如今一杯零落酒，風雨蝕盡征袍單。", "側立崑奴面鐵色，楚客不言未吹笛。", "關山有月無人聲，自是江頭渚花發。", "渚花春少未得妍，凝立青山圍水天。", "杜鵑故態不解事，盡情叫入青楓烟。", "壯士未握邊頭槊，旄頭如月幾時落。", "如今世界不愛賢，看取青峰白雲角。", "嗚呼一歌兮歌已怨，壺中無酒可續嚥。"]'),
('b9b3e495-074c-4349-b8c5-6058451abaa6','茶聲','李南金','宋','宋诗','song-poetry','','[]','砌蟲唧唧萬蟬催，忽有千車捆載來。',32,'全唐诗/poet.song.209000.json','["砌蟲唧唧萬蟬催，忽有千車捆載來。", "聽得松風并澗水，急呼縹色綠瓷杯。"]'),
('804fa896-cdbf-414b-9f06-599f4a517b73','汴京','姚望之','宋','宋诗','song-poetry','','[]','蛇豕腥膻經幾年，故都宮闕尚巍然。',64,'全唐诗/poet.song.209000.json','["蛇豕腥膻經幾年，故都宮闕尚巍然。", "八陵蒼莽知何地，九廟英靈如在天。", "重整六軍嚴宿衛，旋興百堵慰氓編。", "微臣董役慚無補，擬繪新圖獻榻前。"]'),
('ecd29260-f168-4a3c-9af4-87560be8a607','龜山禪寺','姚望之','宋','宋诗','song-poetry','','[]','萬山深處遠輪蹄，古寺雍熙詔賜題。',64,'全唐诗/poet.song.209000.json','["萬山深處遠輪蹄，古寺雍熙詔賜題。", "坐望竺乾諸佛近，徙憑菌閣十方低。", "靈岩頻見玄猿度，琪樹應招白鶴棲。", "不覺勝游天已晚，一痕新月印前溪。"]'),
('ce13b21e-a1e0-4fed-8fde-0b74eec3f9f9','贈桂琴隠先生傅子雲韻','桂柔夫','宋','宋诗','song-poetry','','[]','君是軼羣者，當知不可覊。',48,'全唐诗/poet.song.209000.json','["君是軼羣者，當知不可覊。", "淵源象山學，聲價鯉庭詩。", "要路足將策，高雲翅肯垂。", "餘波幸沾丐，活我出污池。"]'),
('6bbe0d5d-99d9-46b8-8440-163ee4a74dfd','遊石臺寺遇雪','梅均','宋','宋诗','song-poetry','','[]','人言十月小春回，誰釀寒雲作雪醅。',64,'全唐诗/poet.song.209000.json','["人言十月小春回，誰釀寒雲作雪醅。", "天女戲拋羣玉珮，風姨吹散萬銀杯。", "竹非爲米腰皆折，山不因愁髮盡皚。", "凍合詩肩不成句，六花時入轎窗來。"]'),
('b08243c7-16ac-4f68-9488-f230782c882f','再遊石臺','梅均','宋','宋诗','song-poetry','','[]','憶昔經行處，如今兩見秋。',48,'全唐诗/poet.song.209000.json','["憶昔經行處，如今兩見秋。", "山川舊相識，泉石記曾遊。", "槐國未爲守，醉鄉先拜侯。", "擁爐聽僧話，忘却客中愁。"]'),
('55d7a5d5-bd0e-4727-8aa9-3058308e12c9','寄林可山','趙瑻夫','宋','宋诗','song-poetry','','[]','好春虛度三之一，滿架荼䕷取次開。',32,'全唐诗/poet.song.209000.json','["好春虛度三之一，滿架荼䕷取次開。", "有客相看無可設，數枝带雨摘將來。"]'),
('4914ef2a-80fe-488d-bb42-48b41d5149f7','暮春晚酌','趙汝普','宋','宋诗','song-poetry','','[]','春去夏來雨雪花，飛入隔窗點絳紗。',32,'全唐诗/poet.song.209000.json','["春去夏來雨雪花，飛入隔窗點絳紗。", "呼童掇取尊前酒，看景哦詩醉落霞。"]'),
('eef87624-5e66-4218-a0fc-16bdd18c53f7','題舜帝廟','趙汝普','宋','宋诗','song-poetry','','[]','蒼梧雲斷帝升遐，奇石江邊自古誇。',32,'全唐诗/poet.song.209000.json','["蒼梧雲斷帝升遐，奇石江邊自古誇。", "莫道薰絃無逸響，雞鳴寸念亦重華。"]'),
('7d6a8064-d631-40ae-820a-e14d8205c52b','秋日謁清臣宗叔紀洞霄景二首  其一','趙汝普','宋','宋诗','song-poetry','','[]','欲揮塵事訪名山，更羨吾宗吏事閒。',32,'全唐诗/poet.song.209000.json','["欲揮塵事訪名山，更羨吾宗吏事閒。", "龍穴藏身空世慮，源泉撫掌傲人寰。"]'),
('8e80e83b-c2a3-4758-bbd2-aacf0f05fa78','秋日謁清臣宗叔紀洞霄景二首  其二','趙汝普','宋','宋诗','song-poetry','','[]','大滌山頭一振衣，仙人曾向此幽棲。',32,'全唐诗/poet.song.209000.json','["大滌山頭一振衣，仙人曾向此幽棲。", "至今翠箬丹砂隠，夜半浮光古洞飛。"]'),
('5c306960-a40e-4c36-8bf1-42732d893ec8','探釣臺','趙汝普','宋','宋诗','song-poetry','','[]','先生道足師天子，豈爲劉郎作諫官。',64,'全唐诗/poet.song.209000.json','["先生道足師天子，豈爲劉郎作諫官。", "一線不期貪懦法，兩臺自受水雲寬。", "忘機故把直鈎釣，適志何嫌高揭竿。", "千載尚留真蹟在，客星炯炯照相灘。"]'),
('1bbef965-25af-48d4-b937-7e4c0e891efa','鶴林寺','趙汝楳','宋','宋诗','song-poetry','','[]','仙去當年尋舊迹，傳來此日尚名山。',32,'全唐诗/poet.song.209000.json','["仙去當年尋舊迹，傳來此日尚名山。", "花開花落朝昏事，唯有春風歲歲閑。"]'),
('25a54f39-e508-4411-89d5-bcaeafba81a1','次龍吟寺壁間韻','趙汝育','宋','宋诗','song-poetry','','[]','解鞍遊古寺，夕照滿疎林。',48,'全唐诗/poet.song.209000.json','["解鞍遊古寺，夕照滿疎林。", "雨過山如畫，風生竹解吟。", "龍眠秋水靜，豹隠暮雲深。", "喚醒遊僊夢，數聲何處碪。"]'),
('21c8ed25-c018-4f48-af1b-b42431c8b9cf','浮丘壇','趙汝育','宋','宋诗','song-poetry','','[]','臨陽僊窟宅，遺跡在巖扉。',48,'全唐诗/poet.song.209000.json','["臨陽僊窟宅，遺跡在巖扉。", "丹就泉如舊，壇空人已非。", "碧峰千古在，黄鶴幾時歸。", "乞我刀圭惠，從君隠翠微。"]'),
('21796cf6-edaf-4fd8-b1f9-03e3ea9d5f08','海棠次蘇子瞻韻','趙汄夫','宋','宋诗','song-poetry','','[]','海棠別得一風光，恨不生香轉曲廊。',32,'全唐诗/poet.song.209000.json','["海棠別得一風光，恨不生香轉曲廊。", "春睡太真困未足，胭脂露冷濕紅妝。"]'),
('182a453f-e1a4-4e5c-9c7c-b78959076d42','山行二絕  其一','趙希玣','宋','宋诗','song-poetry','','[]','侵晨命僕起隨行，滴滴流泉聒耳鳴。',32,'全唐诗/poet.song.209000.json','["侵晨命僕起隨行，滴滴流泉聒耳鳴。", "遥望君家何處是，白雲溪上小橋橫。"]'),
('09ee9934-328c-4595-bc93-036d3f0f9e7a','山行二絕  其二','趙希玣','宋','宋诗','song-poetry','','[]','柴門寂寂傍林泉，古木陰森不染烟。',32,'全唐诗/poet.song.209000.json','["柴門寂寂傍林泉，古木陰森不染烟。", "陣陣落花鋪滿徑，呼童漫掃夕陽邊。"]'),
('7a02e20d-0078-4fc7-b44d-4a29e00e1b93','迎享送神','馬光祖','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江兮淙淙，踞虎兮蟠龍。',348,'全唐诗/poet.song.209000.json','["長江兮淙淙，踞虎兮蟠龍。", "秀羣英兮禮樂，覽千古兮焉窮。", "蹇誰留兮青溪，穆將愉兮壽宮。", "思至德兮肇蒼姬，避聖嗣兮興句吳。", "竟長干兮游五湖，燁客星兮隠東廬。", "坐根石兮定吳都，懷仲父兮秦淮隅。", "燎赤壁兮偉北圖，憶尚書兮西明居。", "孝感兮冰魚，鹿苑兮儒書。", "起烏衣兮見夷吾，運百甓兮恢宏橅。", "忠孝兮父子，將相兮叔姪。", "登冶城兮想高世，酌貪泉兮徒西壁。", "興文兮雷劉，著書兮陶蕭。", "大節兮霜凜凜，謫仙兮風飄飄。", "雲龍上下兮東野，桃花流水兮致堯。", "肆滎陽兮忠憤，相先民兮迢迢。", "天昌宋兮將有曹，平江南兮斧不膏。", "德乖崖兮桑本袤，美中丞兮蓉幕高。", "神明兮待制，忠恕兮膚使。", "春風兮壽元氣，圖繪兮回天意。", "出師門兮道與南，建留都兮垂萬世。", "仗征鉞兮江無波，死封疆兮人知義。", "采石兮功之奇，紫陽兮道之繼。", "佐乃翁兮南軒，開厥後兮壹是。", "澤斯民兮西山，儼元凱兮是似。"]'),
('c9678004-35d1-4f94-8300-8d33fb91bb5b','青溪','馬光祖','宋','宋诗','song-poetry','','[]','人道青溪有九曲，如今一曲僅能存。',64,'全唐诗/poet.song.209000.json','["人道青溪有九曲，如今一曲僅能存。", "江家宅畔成花圃，東府門前作菜園。", "登閣自堪觀疊嶂，汎舟猶可醉芳樽。", "料應當日皆無恙，苕霅瀟湘不足言。"]'),
('dc1db238-b938-4e8d-988e-0b6204866f86','汝南灣','馬光祖','宋','宋诗','song-poetry','','[]','當時只號汝南灣，後有三人住此間。',64,'全唐诗/poet.song.209000.json','["當時只號汝南灣，後有三人住此間。", "自謂逸民須隠約，並稱賢士想高閑。", "祗緣水味都殊異，且欲鄰居數往還。", "好事有時相就飲，不妨鐺脚對青山。"]'),
('74f1a7ef-7516-4f62-ac4d-8c0a7dba21ed','贈李端履  其一','馬光祖','宋','宋诗','song-poetry','','[]','太守憂民只寸心，按行安得百其身。',32,'全唐诗/poet.song.209000.json','["太守憂民只寸心，按行安得百其身。", "煩君爲我家家問，要使重崖處處春。"]'),
('39316c37-4131-4fa1-a93c-abf4c670b94d','贈李端履  其二','馬光祖','宋','宋诗','song-poetry','','[]','倚門稚子竈頭妻，有米無錢相對啼。',32,'全唐诗/poet.song.209000.json','["倚門稚子竈頭妻，有米無錢相對啼。", "爲把青蚨濟艱苦，莫教窮谷有饑黎。"]'),
('2e71098e-463a-476d-956b-3c0171a02f81','贈李端履  其三','馬光祖','宋','宋诗','song-poetry','','[]','辦得錢來直是難，錢錢要使及煢鰥。',32,'全唐诗/poet.song.209000.json','["辦得錢來直是難，錢錢要使及煢鰥。", "莫教散入他人手，減百抽分或細奸。"]'),
('229fc78e-aa03-427b-bcaa-6e566f6174ca','贈李端履  其四','馬光祖','宋','宋诗','song-poetry','','[]','闤闠通衢散不難，最艱難處是深山。',32,'全唐诗/poet.song.209000.json','["闤闠通衢散不難，最艱難處是深山。", "涉溪渡嶺須周遍，莫憚芒鞋一往還。"]'),
('009ef325-fa71-4f1b-8083-5cbc8575fb43','贈李端履  其五','馬光祖','宋','宋诗','song-poetry','','[]','從來難察是奸欺，莫索心頭只自知。',32,'全唐诗/poet.song.209000.json','["從來難察是奸欺，莫索心頭只自知。", "惟有老夫呼得應，他年禍福更關誰。"]'),
('9bbdc7a7-9f2a-4e23-918a-7a6de0a0ada4','任公仙臺祠堂','陳鑄','宋','宋诗','song-poetry','','[]','任公何代此昇仙，萬仞仙臺倚翠巔。',64,'全唐诗/poet.song.209000.json','["任公何代此昇仙，萬仞仙臺倚翠巔。", "石徑層層封綠蘚，松蘿步步拂青烟。", "海中島嶼分諸國，野外雲霞萃一川。", "賢守乘秋縱登賞，不妨吟到夕陽天。"]'),
('1cd65ef2-0685-4d54-ba75-b87bba30f677','句','陳鑄','宋','宋诗','song-poetry','','[]','雲頭落日半規明，林際炊煙一抹橫。',16,'全唐诗/poet.song.209000.json','["雲頭落日半規明，林際炊煙一抹橫。"]'),
('028c0b1b-edf1-4b40-bf0a-514e93e91ddf','壽友人','周申','宋','宋诗','song-poetry','','[]','蕤賓紀月蓂初開，斗杓直指午位回。',147,'全唐诗/poet.song.209000.json','["蕤賓紀月蓂初開，斗杓直指午位回。", "家家粧點垂門艾，兒童報道端午來。", "仙風偠{亻裊}溫瓊室，幔亭秀氣重胚胎。", "夜來忽叶熊夢吉，凌晨果見生真才。", "光風霽月和可掬，天上鸑鷟真奇哉。", "五枝丹桂推獨秀，滿堂却更金玉堆。", "新帥問友尤篤意，慶動慈闈戲老萊。", "青氈舊物須還復，香羅細葛好事催。", "年年記取蒲切玉，瑶池醉泛蟠桃杯。"]'),
('f781f53e-1d35-4bbf-a29b-242c486897bb','九日','翁甫','宋','宋诗','song-poetry','','[]','秋風兩度身爲客，已見重陽未到家。',32,'全唐诗/poet.song.209000.json','["秋風兩度身爲客，已見重陽未到家。", "村酒不堪供節事，祗將青眼看黄花。"]'),
('f9ee938d-2295-4f51-9625-195871f07539','贈孫花翁','翁甫','宋','宋诗','song-poetry','','[]','我生頭髮未燥時，花間已歌花翁詩。',48,'全唐诗/poet.song.209000.json','["我生頭髮未燥時，花間已歌花翁詩。", "我髮既長今漸白，猶見花翁好顔色。", "舉酒祝翁壽百年，我爲詩孫戲翁邊。"]'),
('bc0dcbc5-39ed-417b-8436-fff821783971','題朱文公唐石墳庵','鄭宅','宋','宋诗','song-poetry','','[]','雲谷高風挽不留，尚餘書澤賁松楸。',64,'全唐诗/poet.song.209000.json','["雲谷高風挽不留，尚餘書澤賁松楸。", "山瞻泰華巖巖聳，水接濂伊混混流。", "千古爲渠開日月，百年知我有春秋。", "自憐晚學無仙骨，空把遺編記話頭。"]'),
('338d2325-b2ec-4a7e-a815-21d468f7b94f','越問 篇引','孫因','宋','宋诗','song-poetry','','[]','典午氏之盛時兮，余鼻祖曰子荆。',328,'全唐诗/poet.song.209000.json','["典午氏之盛時兮，余鼻祖曰子荆。", "謀樂郊以隠居兮，颺潄石之清名。", "有聞孫曰承公兮，嘗令鄞與餘姚。", "愛會稽之山水兮，爰徙家於茲城。", "當永和之九年兮，惠風暢夫莫春。", "偕王謝之諸公兮，會修禊於蘭亭。", "賦臨流之五言兮，寄幽尋之逸興。", "泛迴沼倚脩竹兮，松風落而冷冷。", "維興公尤好事兮，作流觴之後序。", "助逸少之高致兮，齊芳譽於難兄。", "既乃登陸而游兮，歷天台與四明。", "潄飛瀑於筆端兮，遺擲地之金聲。", "余自句章徙姚兮，倏綿歷乎十稔。", "慨風流之浸邈兮，幸猶爲夫越氓。", "掬清泉之潺湲兮，友過雲之溶洩。", "訪樊榭之杳靄兮，栖石窗之玲瓏。", "客有過余兮，謂余博覽而好古。", "世爲越人兮，胡不志夫越之風土。", "余謝不能兮，傴余指而縷數。", "前有靈符之記兮，後有龜齡之賦。", "嗟彼皆已爲陳迹兮，時亦隨夫所遇。", "儻含毫而不斷兮，將羞余之鼻祖。"]'),
('98d3fa61-87a9-431a-ac70-3fcea2a19b0c','越問 封疆','孫因','宋','宋诗','song-poetry','','[]','九州皆有山鎮兮，職方氏獨先會稽。',304,'全唐诗/poet.song.209000.json','["九州皆有山鎮兮，職方氏獨先會稽。", "射祥光於斗分兮，占星紀於天倪。", "牽牛炳其初躔兮，屆須女之七度。", "少陽當其正位兮，爲萬物之潔齊。", "南控引乎閩粵兮，北連亙乎鉅海。", "日出扶桑之東兮，風行浙河之西。", "八山蜿其中蟠兮，羅千嵒以爲鄣。", "三江匯而旁注兮，渺萬壑以爲谿。", "洞天㟏岈以連雲兮，俯九垠其如芥。", "洪濤沸渭以拍天兮，轟三軍之鼓鼙。", "宅卧龍之岧嶢兮，蠡城屹其環繚。", "带平湖之浩㵿兮，雲鏡鑄而天低。", "闢陵門而四達兮，八風颯其遞至。", "飛翼樓而舞空兮，天門沈其可梯。", "提封方數千里兮，運甌吳於掌上。", "七郡四十餘縣兮，歸中權之總提。", "茲古今之大都會兮，爲九牧之冠冕。", "諒天地之設險兮，他郡寧得而攀躋。", "客曰偉哉山川兮，信美矣其無慊。", "然吾聞固國兮，不以山溪之險。"]'),
('9a4ef3fb-f73a-4f9b-957f-ec703799ad3f','越問 金錫','孫因','宋','宋诗','song-poetry','','[]','觀地産之所宜兮，惟金錫之最良。',304,'全唐诗/poet.song.209000.json','["觀地産之所宜兮，惟金錫之最良。", "貢品肇於有姒兮，暨蒼姬而加詳。", "雖歷代之所珍兮，凜英氣其猶祕。", "歐冶子之神奇兮，爰採取而鍊淬。", "剖赤堇而出錫兮，山色變而無雲。", "涸若耶之銅液兮，俯不見夫潛鱗。", "鑄嶺岌其插天兮，冶井浸而寒冽。", "前豐霳爲擊橐兮，後雨師爲灑塵。", "發銅牛之藏屑兮，赭林麓以炊炭。", "棄右冶之餘滓兮，草木爲之焦爛。", "炎煙漲乎銅孤兮，寒光浮乎鍊塘。", "越砥妥其斂鍔兮，鑄浦沸其若湯。", "合衆靈而成器兮，爲寶劍凡有五。", "曰湛盧與巨闕兮，蓋珍名之最著。", "既屬之善相之薛燭兮，復謀之南林之處女。", "水試則斷蛟螭兮，陸用而剸犀虎。", "掃攙槍使澌滅兮，伏蚩尤使奔怖。", "豈吳鉤之敢抗兮，非燕函之能禦。", "客曰偉哉利器兮，誠爲越國之珍。", "斯劍客之喜談兮，非文種之願聞。"]'),
('09cdba36-c79b-40e0-9253-753c07d0e224','越問 竹箭','孫因','宋','宋诗','song-poetry','','[]','維苗山之竹箭兮，稟勁氣於乾坤。',187,'全唐诗/poet.song.209000.json','["維苗山之竹箭兮，稟勁氣於乾坤。", "實東南之美材兮，聲價等乎瑶琨。", "良工相夫陰陽兮，加利鏃以爲矢。", "習國人於射瀆兮，震電激而星奔。", "挾之以六千之君子兮，從之以八千之子弟。", "可以償方張之闔閭兮，走善射之樓煩。", "彼羣仙之會聚兮，亦以射而爲樂。", "登石室之射堂兮，射東峯而的白。", "丁令威爲拾箭兮，山上下以求索。", "獲遺鏃於樵夫兮，償以樵風之南北。", "客曰異哉斯事兮，誠振古之怪奇。", "然越人之彎弓兮，則談笑而道之。"]'),
('d063e216-21b1-43f5-a5de-5916f7382e23','越問 魚鹽','孫因','宋','宋诗','song-poetry','','[]','百川會同滄海兮，浩不知夫津涯。',305,'全唐诗/poet.song.209000.json','["百川會同滄海兮，浩不知夫津涯。", "吐雲濤以瀾汗兮，沃日御而渺瀰。", "藏巨靈之贔屓兮，見天吳之惚怳。", "戴五山之嶪峨兮，涵百怪之陸離。", "巨魚出沒其中兮，不知其幾千里。", "鼓浪沫以成霧兮，噓雲氣以成霓。", "任公子之投竿而釣兮，五十犗以爲餌。", "閲期年而得魚兮，牽巨鈎而下之。", "鬐鬛怒而刺天兮，白波湧而山立。", "膏流溢而爲淵兮，顱骨積而成坻。", "自浙水以東兮，無不饜若魚之肉。", "彼赤鱔黄顙何足數兮，又況梅魚與桃鯔。", "維天地之寶藏兮，有煮海之鹺鹽。", "曝曜靈以摝涉兮，浮蓮的以試滷。", "編篔簹以爲槃兮，處烈焰而不灼。", "霜鉛倏其凝沍兮，霜花颯其的皪。", "茲海若之不愛寶兮，豐功被乎天下。", "抑造化之自然兮，詎人爲之力假。", "客曰富哉魚鹽兮，此越國之寶也。", "是特以利言兮，吾願聞其上者。"]'),
('6a964e7f-52e2-4167-8020-5b9269b3c62f','越問 舟楫','孫因','宋','宋诗','song-poetry','','[]','越人生長澤國兮，其操舟也若神。',236,'全唐诗/poet.song.209000.json','["越人生長澤國兮，其操舟也若神。", "有習流之二千兮，以沼吳而策勳。", "尋笠澤以潛涉兮，北渡淮而會盟。", "擅航烏之長技兮，水犀爲之逡巡。", "浮海救東甌兮，有握節之嚴助。", "治船習水戰兮，榮衣錦於買臣。", "渡浙江而誓衆兮，會稽之內史。", "率水棹以拒戰兮，凌江之將軍。", "坐大船若山兮，公苗山陰之傑。", "汎波襲番禺兮，季高永興之人。", "想萬艘之竝進兮，紛青龍與赤雀。", "風帆儵忽千里兮，駕巨浪如飛雲。", "今競渡其遺俗兮，習便駊以捷疾。", "觀者動心駭目兮，相雜襲如魚鱗。", "客曰盛哉舟楫兮，他郡孰加於越。", "然同濟或不同心兮，請置此而新其說。"]'),
('bf5d261e-5508-467c-99aa-59f885297c27','越問 越釀','孫因','宋','宋诗','song-poetry','','[]','揚州之種宜稻兮，越土最其所宜。',216,'全唐诗/poet.song.209000.json','["揚州之種宜稻兮，越土最其所宜。", "稬種居其十六兮，又稻品之最奇。", "自海上以漂來兮，伊仙公之遺育。", "別黄秈與金釵兮，紫珠貫而纍纍。", "酒人取以爲釀兮，辨五齊以致用。", "湑鏡流之香潔兮，貯祕色之新甕。", "助知章之高興兮，眼花眩乎水底。", "侑謝傅之雅遊兮，陶丹府而哦詩。", "集羣賢以觴詠兮，浮罰觥乎子敬。", "指鳴蛙爲鼓吹兮，暢獨酌於稚珪。", "斯越酒之醖藉兮，非宜城中山之比。", "矧投醪之醇德兮，能使勇氣百倍於熊羆。", "客曰旨哉越釀兮，固越俗之所怡。", "然自征榷之法行兮，安得薛戎而蠲之。"]'),
('f31b3965-579b-4942-8eab-196b16397c95','越問 越茶','孫因','宋','宋诗','song-poetry','','[]','日鑄山之英氣兮，既發越於鏌鎁。',240,'全唐诗/poet.song.209000.json','["日鑄山之英氣兮，既發越於鏌鎁。", "地靈洩而不盡兮，復薰蒸於草芽。", "雖名出之最晚兮，爲江南之第一。", "視紫筍若奴臺兮，又何論乎石花。", "維瑞龍之爲品兮，與此山以相亞。", "意山脈之通貫兮，仙種同乎一家。", "汲西岩之清泉兮，松風生乎石鼎。", "滋芳液於靈襟兮，沆瀣集乎齒牙。", "歐公錄之歸田兮，蘇仙流諸佳詠。", "伯玉註於詩版兮，文正賞其甘華。", "至鴈塔與花塢兮，固郡志之所載。", "若餘姚之瀑布兮，尤茶經之所誇。", "嗟陸羽之不逢兮，宜鑑味之絕少。", "世方貴夫建茗兮，孰有知夫越茶。", "客曰世非不知兮，顧茗禁之已苛。", "亦幸其不盡知兮，姑舍是而言他。"]'),
('bef573ec-6dd9-4acc-99d5-98260cad531a','越問 越紙','孫因','宋','宋诗','song-poetry','','[]','繄剡藤之爲紙兮，品居上者有三。',210,'全唐诗/poet.song.209000.json','["繄剡藤之爲紙兮，品居上者有三。", "蓋篠簜之變化兮，非藤楮之可參。", "在晉而名側理兮，儲郡庫以九萬。", "曰姚黄今最顯兮，蒙詩翁之賞談。", "加越石以萬杵兮，光色透於金版。", "近不數夫杭由兮，遠孰稱夫池繭。", "半山愛其短樣兮，東坡耆夫竹展。", "薛君封以千戶兮，元章用司筆硯。", "數其德有五兮，以縝滑而爲首。", "發墨養筆鋒兮，性不蠹而耐久。", "惜昌黎之未見兮，姓先生而爲楮。", "使元輿之及知兮，又何悲剡藤之有。", "客曰媺哉越紙兮，有大造於斯文。", "然世方好紙而玉兮，又烏知乎此君。"]'),
('7e7ba077-67cb-490a-b7cb-4573b0600c74','越問 神仙','孫因','宋','宋诗','song-poetry','','[]','陽明太元之天兮，乃羣仙之所游。',271,'全唐诗/poet.song.209000.json','["陽明太元之天兮，乃羣仙之所游。", "有金堂與玉室兮，挹方丈與瀛洲。", "伯經得道□泉兮，乘雲氣於木杪。", "仙公韜光丹井兮，發函書於船頭。", "騎青騾以入市兮，薊子訓之賣藥。", "切鯔魚以作膾兮，介元則之垂鈎。", "弘景寄跡釣槎兮，隠吏栖於梅市。", "廣信駕龍白日兮，羽人萃於丹丘。", "擷芝草以爲侶兮，左元放之金液。", "餐桂屑而飲水兮，范少伯之扁舟。", "煉日精以回形兮，虞翁色若嬰孺。", "位上清而標籍兮，思玄跡混俗流。", "嚴青能服石髓兮，終斷穀而輕舉。", "伯陽煉成神丹兮，雖蛻形而不留。", "御天風而上征兮，與日月以齊壽。", "皆地勝之所招兮，舉塵寰而少仇。", "客曰神仙信有兮，特祕怪而難求。", "吾聞越多隠君子兮，試詳言而旁搜。"]'),
('b50f1c2b-4402-49cd-8cd0-833194f5c2c0','越問 隠逸','孫因','宋','宋诗','song-poetry','','[]','謝隠士當少微兮，精神見乎天文。',301,'全唐诗/poet.song.209000.json','["謝隠士當少微兮，精神見乎天文。", "嚴子陵應客星兮，光芒動夫至尊。", "居剡下以高潔兮，戴安道之父子。", "游嵩嶽以偕隠兮，孔述睿之弟昆。", "却米餉而不受兮，朱百年之夫婦。", "受肥遁以就閑兮，阮萬齡之祖孫。", "閉蓬戶以觀書兮，淳之棲於窮岫。", "輕白璧而不盼兮，景齊隠於日門。", "扣藥船而引聲兮，歌競傳於仲御。", "漁鏡湖以賦詩兮，島尚號於方干。", "黄公列乎四皓兮，成定儲之羽翼。", "嵇康儕於七賢兮，著養生之至言。", "王子猷詠招隠兮，愛山陰之竹種。", "謝靈運賦山居兮，采地黄爲溪蓀。", "著貂裘坐岩石兮，弘之志不在釣。", "袘豹席與椶橋兮，志和豈羨回軒。", "彼皆不事王侯兮，以高尚而辟世。", "亦地氣之所鍾兮，多秀水與名山。", "客曰士各有志兮，斯固古之逸民。", "夫何欲潔其身兮，弗念君臣之大倫。"]'),
('989e0335-8698-469b-8829-a21d18c4ef57','越問 句踐','孫因','宋','宋诗','song-poetry','','[]','昔句踐兮思報吳，問國政兮五大夫。',164,'全唐诗/poet.song.209000.json','["昔句踐兮思報吳，問國政兮五大夫。", "辟田野兮實倉府，訪疾苦兮字幼孤。", "抱冰兮握火，置膽兮坐卧。", "采蕺兮與葛，側席兮閭左。", "觴酒豆肉兮必均其施，樂不盡聲兮食不致味。", "鷙鳥匿形兮踰一十祀，吳無稻蟹兮越有地利。", "一朝興師兮三戰得志，姑蘇既墟兮橫行淮泗。", "伯東諸侯兮賀貢畢致，赫然雋功兮又何可議。", "客曰，異哉兮彼長頸而烏喙。", "如其可與其樂兮，何鴟夷之遠避。"]'),
('d7cbbf74-2056-4ec4-a465-9404fcbfd9dd','越問 舜禹','孫因','宋','宋诗','song-poetry','','[]','帝舜生於姚丘兮，地近夷而居東。',213,'全唐诗/poet.song.209000.json','["帝舜生於姚丘兮，地近夷而居東。", "母握登感天瑞兮，漾祥光於大虹。", "歷山其所耕稼兮，陶漁皆有遺跡。", "二女降於媯汭兮，百官備而景從。", "大禹巡於鬴山兮，會羣臣而計功。", "執玉帛者萬國兮，戮後至之防風。", "託菲飲以名泉兮，鑿了溪而宅土。", "發金簡於石匱兮，藏祕圖於山中。", "望邑名夫虞姚兮，山靈護夫禹穴。", "儼廟貌於千古兮，遺化被於無窮。", "繄帝王之所在兮，宜風俗之近古。", "習孝悌與勤儉兮，亦好遜而上忠。", "客曰於戲大哉兮，又何可以比隆。", "然有爲者亦若是兮，豈無與舜禹之事同。"]'),
('f3477d53-8e21-4619-b9d9-afcdfe2b372c','越問 駐蹕','孫因','宋','宋诗','song-poetry','','[]','維六飛之南渡兮，潢濤江以東歷。',244,'全唐诗/poet.song.209000.json','["維六飛之南渡兮，潢濤江以東歷。", "後舜禹三千年兮，履舜禹之遺迹。", "駐翠蹕以彌年兮，因改元而頒詔。", "爰陞州而爲府兮，冠紹興之大號。", "舉大享之上儀兮，即行闕而蕆祀。", "視總章與重屋兮，亦庶幾其遺意。", "登堂而望稽嶺兮，懷克勤之令德。", "留建炎之御製兮，彰復古之素志。", "采上虞之囊封兮，終然法乎舜禪。", "山鬰葱以蜿蜒兮，鍾禹陵之佳氣。", "御香四時來下兮，道冠蓋以相望。", "拱觚稜於雲闕兮，儼威顔而天咫。", "繄百年之父老兮，及親逢乎盛事。", "想天民之視阜兮，與虞夏而同治。", "客曰幸游舜禹之邦兮，復逢舜禹之君。", "然儻無舜禹之臣兮，孰能牧舜禹之民。"]'),
('9454ba13-2bc2-4300-bca6-91c2f022ff23','越問 良牧','孫因','宋','宋诗','song-poetry','','[]','自大駕之西幸兮，府遂爲於近藩。',359,'全唐诗/poet.song.209000.json','["自大駕之西幸兮，府遂爲於近藩。", "賜行殿爲府治兮，暨澤牧之惟艱。", "張毘陵首當是選兮，實股肱之舊弼。", "仍土階之素規兮，因舊宇以爲安。", "朱忠靖繼剖符兮，屹具瞻於岩石。", "趙忠簡亦相望兮，凜清風而獨寒。", "忠定王之來鎮兮，當乾道之四禩。", "捐帑以置義租兮，闢宮而祠先賢。", "諒棠陰之蔽芾兮，思召伯其如憩。", "宜大封於是邦兮，良天道之好還。", "後五十餘年兮，誰儷美以增飾。", "維我新安公兮，騖逸駕而獨攀。", "剖滯訟如澌流兮，召雨暘如應響。", "使百城俱按堵兮，令滄海無驚瀾。", "立吏膽於秋霜兮，洽民氣於春澤。", "出干將於寶匣兮，照沆瀣於銅盤。", "圜扉鞠爲茂草兮，麥岐藹其連秀。", "令修戶庭之內兮，民樂湖山之閒。", "既修政而人悅兮，文書省於幙府。", "新百廢以具興兮，聳輪奐之偉觀。", "八邑不知有役兮，一道不知有費。", "若天造而神設兮，豈民力之或煩。", "化榛莽爲宏麗兮，敞隘敝爲爽塏。", "革蠹撓而雄疊兮，易朽腐而堊丹。"]'),
('41fecc74-6963-4ff9-9be0-a965add4d561','秋聲','趙彥鏜','宋','宋诗','song-poetry','','[]','紛紛敗葉撲西風，嚦嚦征鴻度碧空。',64,'全唐诗/poet.song.209000.json','["紛紛敗葉撲西風，嚦嚦征鴻度碧空。", "咿咿菱歌煙暝外，丁丁衣杵月明中。", "瀟瀟細滴蕉窗雨，唧唧悲鳴草砌蛩。", "忽忽有懷如宋玉，行行搔首思沖沖。"]'),
('3bf9b4db-5e30-4ab4-9472-901e191fff18','游虎丘山  其一','吳從善','宋','宋诗','song-poetry','','[]','樂聲隨轉闔閭城，檣杪無風水自平。',32,'全唐诗/poet.song.209000.json','["樂聲隨轉闔閭城，檣杪無風水自平。", "不待尊前催畫燭，落霞明月送船行。"]'),
('adf01922-7ee4-495e-9f78-6dd2ed257ec3','游虎丘山  其二','吳從善','宋','宋诗','song-poetry','','[]','兩岸黄堆罷亞香，月波金瀉亂波光。',32,'全唐诗/poet.song.209000.json','["兩岸黄堆罷亞香，月波金瀉亂波光。", "不驅風露歸囊錦，安得新詩鬰鬯凉。"]'),
('3d6a62ca-7d32-46ea-812a-c2a1aeca9186','江心長句','葛紹體','宋','宋诗','song-poetry','','[]','問津城西市，呼渡江南岸。',192,'全唐诗/poet.song.209000.json','["問津城西市，呼渡江南岸。", "棹穩當潮生，帆輕趁風便。", "龍翔古招提，鳥革今輪奐。", "回合列翠屏，周遭鋪素練。", "邀行嫩篁竿，勸坐老木榦。", "沿壁覽新題，吹塵認舊篆。", "一隅看不足，兩塔窮未見。", "陽光爍崗頂，飆陣掠波面。", "郛郭聚拱伏，烟雲散呈獻。", "俯拜肅御邸，仰瞻粲宸翰。", "皇帝南巡意，生靈北望眼。", "書千古清輝，爲萬世偉觀。", "樓臺明月讌，鐘鼓朝暮飯。", "徒見一時近，孰念百年遠。", "江濤常摏撞，帝澤共流轉。", "遊子感詩歌，居人思日勉。"]'),
('d4ab9553-2053-4120-b639-5e1b3ccf87f7','太湖吟','葛紹體','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','只飲太湖水，不鱠松江鱸。',132,'全唐诗/poet.song.209000.json','["只飲太湖水，不鱠松江鱸。", "鱸雜魚蝦腥，水涵天地初。", "千里開鏡奩，一色包冰壺。", "日月遞吐吞，蛟龍相蟄舒。", "上接河漢高，下連溟渤虛。", "中有洞庭山，雲氣相縈紆。", "我來風雪天，修綆汲自如。", "一飲塵涴清，再飲澆詩書。", "三飲毛髮寒，胸次包寰區。", "大禹果至神，彷彿來前除。", "萬古不盡流，禹功常與俱。"]'),
('be84dd15-037c-4479-9803-7d6e32eda614','分水嶺','葛紹體','宋','宋诗','song-poetry','','[]','岐路東西分，閩浙自茲異。',84,'全唐诗/poet.song.209000.json','["岐路東西分，閩浙自茲異。", "平波翼藂篠，荒丘带深隧。", "漸聞新蠻音，不見舊朋類。", "悽然獨含情，誰與話幽意。", "滿空霜氣橫，鴻影過一二。", "回首良不堪，歸期數長至。", "茫茫宇宙大，人生本如寄。"]'),
('64e45d11-09c4-4f08-94f8-32644dbe8ea3','飯溪石','葛紹體','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','一石類古鐘，範模昔誰製。',108,'全唐诗/poet.song.209000.json','["一石類古鐘，範模昔誰製。", "開闢幾歲月，蘿蔓疑篆隸。", "老木上婆娑，清泉下溶㵝。", "左右亂石列，拱若朝玉帝。", "惜在道路傍，倦客謾凝睇。", "倘立泰山巔，爰遇封禪代。", "萬乘躬巡幸，想像羲皇際。", "銘德刻雋功，表裏千萬世。", "願言勿輕鑿，天意或有待。"]'),
('40f3da95-2624-4168-b208-20e6616e2a42','頭陀嶺','葛紹體','宋','宋诗','song-poetry','','[]','峭絕不可步，肩輿屢顛覆。',108,'全唐诗/poet.song.209000.json','["峭絕不可步，肩輿屢顛覆。", "南北三十里，上下九回曲。", "兩畔沿古松，虬枝亂相續。", "根迸石齒裂，葉密雲氣宿。", "或一蓋高張，或萬蛇奔促。", "或魑魅隠見，或虎豹躑躅。", "縱無遊子悲，遇此亦慘目。", "鼠梯側將崩，鳥逕深更蹙。", "吾道豈終窮，朅來意何欲。"]'),
('b004df8d-17da-4a50-9170-dfe346ca7f46','袁從道山廬三首  其一','葛紹體','宋','宋诗','song-poetry','','[]','人生盡馳騖，忙裏換烏兔。',84,'全唐诗/poet.song.209000.json','["人生盡馳騖，忙裏換烏兔。", "白髮忽相侵，紅顔若何駐。", "豈如向丘壑，味此閑中趣。", "鶬鶊啼春風，鳲鳩喚時雨。", "煙林上笋蕨，晴川下鷗鷺。", "好景滿眼前，興來可以賦。", "貧賤與富貴，願言履其素。"]'),
('98282224-f464-438c-83fd-9237db319463','袁從道山廬三首  其二','葛紹體','宋','宋诗','song-poetry','','[]','竹屋已三間，花逕旋一新。',48,'全唐诗/poet.song.209000.json','["竹屋已三間，花逕旋一新。", "芳苞束碎錦，細草鋪柔茵。", "曾悟順動豫，豈歎雲雷屯。", "箇中足俛仰，世上誰經綸。"]'),
('9eea67fa-a88d-41e6-89a5-fe1dd7ef0518','袁從道山廬三首  其三','葛紹體','宋','宋诗','song-poetry','','[]','日月久棲遲，姓名誰得知。',96,'全唐诗/poet.song.209000.json','["日月久棲遲，姓名誰得知。", "頭戴世儒冠，身著山人衣。", "峻頷带薄髭，瘦骨撐疎眉。", "青編口能誦，白飯手自炊。", "苦茗一兩碗，濁醪三兩巵。", "琴彈多舊曲，窗題少新詩。", "別去動經年，坐來愁語離。", "幽齋早葺罷，借榻重歸時。"]'),
('5246317c-a431-40db-b365-447338c5e289','渭南考室','葛紹體','宋','宋诗','song-poetry','','[]','丞郎昔躬耕，懷野壟上宅。',228,'全唐诗/poet.song.209000.json','["丞郎昔躬耕，懷野壟上宅。", "東湖一棹近，南畝耦夫百。", "風交苗懷新，雲鋪稼敷澤。", "疎櫺翼虛堂，時焉此憩息。", "殷勤左氏語，銀鈎掛簷壁。", "新居匾鍾慶，金字照於赫。", "水竹带左右，春秋燕晨夕。", "鼎鼎百年間，相望屹咫尺。", "寧知笙歌地，一旦灰燼迹。", "人事定誰訛，毋乃數當革。", "以彼而易此，倉卒有良策。", "丁丁斤舊材，介介繩新畫。", "美哉輪奐焉，不負肯堂責。", "父基貽厥子，子構孫更闢。", "笙歌且置之，詩禮日探索。", "軌涂馳霜蹄，霄衢展雲翮。", "放我方寸寬，笑彼宇宙窄。", "益亹澶淵功，永壽元祐脈。", "力穡乃有秋，先難而後獲。"]'),
('d3fb9e52-a4d7-4c4d-915a-aaa9ff56be1b','入竹西道院','葛紹體','宋','宋诗','song-poetry','','[]','雙檜老虬榦，萬竹蒼龍枝。',84,'全唐诗/poet.song.209000.json','["雙檜老虬榦，萬竹蒼龍枝。", "道院傍西築，書窗下南帷。", "笑談清燈暈，坐起白麈揮。", "天低月初挂，河澹星欲垂。", "醉生筆硯妍，卧籌民物規。", "蟋蟀喚鄉夢，莎雞引秋思。", "客身休自疑，古人以爲期。"]'),
('0ad0a0b6-5528-46a2-b040-ad56dac7a58e','謝蒙齋王子文寄文卷','葛紹體','宋','宋诗','song-poetry','','[]','已聞掛風帆，寧知掣其肘。',120,'全唐诗/poet.song.209000.json','["已聞掛風帆，寧知掣其肘。", "緘自春山雲，吟轉秋夜斗。", "文友有新錄，筆之自吾手。", "惓言桂山君，到死意愈厚。", "夜半十一字，龍蛇尚驚走。", "悠悠浙東西，客路霜中柳。", "巍峨讀書堂，珍重夫人壽。", "弟兄自答問，進學以虛受。", "所期躡層霄，斷金真皓首。", "樓崎歸去來，相忘如此酒。"]'),
('2107a549-9066-4213-aa4f-601d232e3ced','送陳良卿','葛紹體','宋','宋诗','song-poetry','','[]','持我五字句，送子千里別。',48,'全唐诗/poet.song.209000.json','["持我五字句，送子千里別。", "蕪菁滿地花，柳絮漫天雪。", "去去當何之，苕川賸風月。", "風月還相思，江山豈相越。"]'),
('8e65bbd8-72ff-42ef-a823-f5c975227e19','嘉興尉府教閲即事','葛紹體','宋','宋诗','song-poetry','','[]','輕風盪宿氛，薄日籠曉晴。',288,'全唐诗/poet.song.209000.json','["輕風盪宿氛，薄日籠曉晴。", "草嫩芟鋤易，沙軟蹙踏輕。", "軍容壯而肅，兵器老以剛。", "震動擊鼓鼙，節止鳴鐃鉦。", "前行萃白旗，後隊隨紅旌。", "閃閃雲霧披，閴閴煙塵凝。", "放箭羽鮮新，張弓角光晶。", "麫絲搭飯玉，赭衫坐盈庭。", "犒激券楮疊，簇結巾带橫。", "叉手最健武，驍勢殊掀騰。", "跳梁勇投擲，呼喝驕憑陵。", "左旋忽右轉，此伏俄彼升。", "路分尋丈鬭，鋒合毫釐爭。", "目與手不謀，須臾懸死生。", "儻非教之素，何以所習精。", "豫章太史氏，家世冰雪清。", "早傳師律嚴，遂識戎陣明。", "坐言二十年，不見此憲程。", "教場沮洳地，漬雨幾浮傾。", "荒池倒枯荷，腐水飄亂萍。", "舊觀喜再還，徒曰練弓兵。", "公宇昔零落，華屋今崢嶸。", "昔也一槩廢，今也百度興。", "今昔同此時，人有能不能。"]'),
('cc233a78-28c4-4bee-b017-f402e70b4e98','送黄尉制司稟議','葛紹體','宋','宋诗','song-poetry','','[]','四海指掌上，西浙復制置。',252,'全唐诗/poet.song.209000.json','["四海指掌上，西浙復制置。", "機張要省括，萬里發中祕。", "制劄天邊來，奪我嘉興尉。", "風流誰後人，太史山谷氏。", "老成負大才，初筮僅小試。", "雷行換風采，鼓作起憔悴。", "遊刃綽有餘，走筆浩無愧。", "青青歲寒姿，松柏森勁氣。", "層冰幾重重，堅可敵陽熂。", "置之籌幄中，秉心端不二。", "討賊先正名，逆順有大義。", "晝夜運日月，東生定西墜。", "終古大明照，不照此醜類。", "送死須臾爾，清寧一天地。", "公在誰相知，郡守股肱寄。", "公去誰相思，邦民共相企。", "白髮我獨悲，青雲公自喜。", "顧此金蘭心，終始永同味。", "去住路兩岐，別酒重三喟。", "江湖年華晚，萬物回春意。", "吟邊一籌先，寄我空中字。"]'),
('37b66c18-20a6-45e1-ab52-44c90336485f','送仙居令','葛紹體','宋','宋诗','song-poetry','','[]','邑稱仙之居，山水開畫圖。',96,'全唐诗/poet.song.209000.json','["邑稱仙之居，山水開畫圖。", "著我老仙子，少試胸中書。", "視印秋風前，觀化冬日初。", "琴調待平絃，髮稠借輕梳。", "豈必三年期，朞月亦可乎。", "赤城勢連越，朱溪流通吳。", "人限地百里，而滯天一隅。", "俄然乘雲翔，邑人空歎吁。"]'),
('ce31b377-3e56-43b0-bfb7-c5d6c894074b','送竹洲葉成之歸省後參學','葛紹體','宋','宋诗','song-poetry','','[]','禾興望金華，東西渺天涯。',180,'全唐诗/poet.song.209000.json','["禾興望金華，東西渺天涯。", "西園堂上翁，鬢影霜欲欺。", "如何二十年，晝夜夢見之。", "歸榮豈不樂，旅瑣寧頻歸。", "我來惠而好，鷗浪相追隨。", "青燈幾言話，白雲每翻思。", "昊天鑑中扃，少愜平生期。", "貢幃秋揚舲，監學春舞旗。", "趨庭問先及，喜色開霜眉。", "壽日長至初，百拜迎春祺。", "香罍金翠行，畫燭舞繡圍。", "桂枝茂紛紛，椿樹陰遲遲。", "君才天下選，一日千里馳。", "八詠賦平遠，雙溪照清漪。", "來來快著鞭，了此一段奇。"]'),
('a94a9e65-fa9e-4233-8f92-1cba130f1745','喜聞韓時齋捷書','葛紹體','宋','宋诗','song-poetry','','[]','焦桐有良材，函彼太古音。',96,'全唐诗/poet.song.209000.json','["焦桐有良材，函彼太古音。", "良工巧斲之，可歌南風琴。", "隠居掛空壁，不受埃塵侵。", "虛中閟清響，靜參萬籟吟。", "一朝絃素絲，徽星粲黄金。", "玉軫圓更齊，鼓之大廷陰。", "斡回天地春，山水自高深。", "匪藉伯牙手，能開子期心。"]'),
('1fc6e60d-11ba-4062-bc03-c9f172fee1b5','王深道別酒走筆次韻','葛紹體','宋','宋诗','song-poetry','','[]','取友但聞道，不問年先後。',48,'全唐诗/poet.song.209000.json','["取友但聞道，不問年先後。", "西澗吾世交，豈在接杯酒。", "言歸復言歸，光怪願袖手。", "樓崎靈泉山，松柏歲寒友。"]'),
('1aa19c44-3bdb-4009-9424-a7f6be26651a','對月簡松廬','葛紹體','宋','宋诗','song-poetry','','[]','但愛秋月明，不厭秋夜永。',60,'全唐诗/poet.song.209000.json','["但愛秋月明，不厭秋夜永。", "掀髯立長風，舞手弄孤影。", "天浄神宇清，露重衣袂冷。", "隠約辨山河，分明認奎井。", "一笑震九霄，喚起迷者省。"]'),
('67b907b2-bc9a-4cc7-9587-994423e464a4','送高文父上柏省墳','葛紹體','宋','宋诗','song-poetry','','[]','走騎引征鞍，鳴榔趁行舶。',156,'全唐诗/poet.song.209000.json','["走騎引征鞍，鳴榔趁行舶。", "下唐三百里，棹穩波如席。", "霜晴天宇清，日暖带春色。", "髻梳粲新粧，羅襦照澄碧。", "怡怡兄弟情，亹亹僕馭力。", "豈爲詫遊觀，肝腸孝思激。", "嵯峨上柏山，丞郎舊形魄。", "松臺夜漫漫，竹塢風索索。", "聲容弗云遠，肅雝對巾幘。", "追惟起家難，飽適敢笑劇。", "於昭萬古魂，伊嘏願無斁。", "嗟嗟天涯客，青燈延永夕。", "君有霜露感，我念雲水隔。"]'),
('0cf8e0df-f70d-4a52-b7c9-f8c631ab93f4','送余直卿廷對','葛紹體','宋','宋诗','song-poetry','','[]','吟卷閑晚窗，捷音鬨春郵。',132,'全唐诗/poet.song.209000.json','["吟卷閑晚窗，捷音鬨春郵。", "推几舞影急，踏門步蹤稠。", "黄冊幾載傳，青衫今日酬。", "學舍丈人行，文場少年儔。", "倚天仰泰華，行地輸驊騮。", "暑清庭陰闊，風香御煙浮。", "龍飛屈親策，虎帥登先籌。", "力深一代源，聲匝四海流。", "朝陽孤鳳凰，曙陰羣蜉蝣。", "端爲砥柱基，非干稻粱謀。", "百鍊要愈剛，萬折空自柔。"]'),
('8322ab69-9047-40c9-8dd9-d8c7a07990f9','惜春長句','葛紹體','宋','宋诗','song-poetry','','[]','去年花開春日和，行嗅香蕊攀柔柯。',144,'全唐诗/poet.song.209000.json','["去年花開春日和，行嗅香蕊攀柔柯。", "今年花開煙雨愁，坐見落英填污溝。", "世事翻覆故應爾，天工卷舒亦如此。", "曷不長教四時好，却令二月春草草。", "牆頭錦紅一花梢，人間雪白幾鬢毛。", "東家兒女喜鬭妍，西鄰老婦羞頺顔。", "亦有對酒高陽徒，零落山丘空畫圖。", "悲來乎，悲來乎，花開花落胡爲乎。", "把住東風聊自娛，明年晴雨知何如。"]'),
('5a343e7b-86d9-4ebb-88df-dfa1a64e2d21','中秋後二夜對月','葛紹體','宋','宋诗','song-poetry','','[]','中秋竟夕佳月色，萬里光芒霜雪白。',128,'全唐诗/poet.song.209000.json','["中秋竟夕佳月色，萬里光芒霜雪白。", "人言陰晴一瞬易，不料清輝連永夕。", "有情傍我書几多，書中今古舊應識。", "玉華嬋娟徹鬢眉，冰澌的皪瑩肝膈。", "風流似與仙娥俱，縞衣練裳新灑滌。", "酒酣顛倒欲結交，燈火希微疑避席。", "出門露氣已半銷，輕風西來盪虛碧。", "中天鏡懸見本真，一點靈明透八極。"]'),
('910118fa-738c-4209-8095-10d9fefa458f','宣公泉歌','葛紹體','宋','宋诗','song-poetry','','[]','幾年廢井城東衙，甃石缺裂洿淖多，奈此宣公初鑿何。',216,'全唐诗/poet.song.209000.json','["幾年廢井城東衙，甃石缺裂洿淖多，奈此宣公初鑿何。", "宣公浩氣輩孟軻，論諫仁義永不磨，炳炳丹衷史所誇。", "當時芟薙開藤蘿，細穿地脈泉源過，暗引雲氣通天河。", "誰知荒蕪日冥冥，泥舍不食羸其瓶，谷射甕漏汲莫升。", "舊跡契君懷古情，一朝渫治翻光晶，百丈修綆轆轤聲。", "乳泉溶溶早夜生，寒冽不改徹底清，靜養日月印列星。", "君欲著亭泉之側，味良高風夢想覿，釀泉爲酒觴佳客。", "舂來香秫珠的皪，玉缸方糵化醇醳，蟻蜉槽牀春滴滴。", "宣公在天酹可索，宣公之泉带神識，濱湖一嘯暮天碧。"]'),
('76ebe0b2-8f6a-40f9-adc1-bca10b7d4304','和水心先生寄越帥汪煥章得雨韻','葛紹體','宋','宋诗','song-poetry','','[]','步虛影裏雲璈舉，精誠上對東皇語。',64,'全唐诗/poet.song.209000.json','["步虛影裏雲璈舉，精誠上對東皇語。", "蓬萊拂檻多飛雲，西風吹作人間雨。", "田家誰不知公勤，千里歡聲公亦聞。", "早禾登場晚禾實，公庭如水清無塵。"]'),
('2dafb9b4-a578-4012-be9a-7a80f139b3f5','次韻','葛紹體','宋','宋诗','song-poetry','','[]','吟邊逡巡風雨催，秋空蕭索聲隠雷。',64,'全唐诗/poet.song.209000.json','["吟邊逡巡風雨催，秋空蕭索聲隠雷。", "老松相應發清響，疑伴吹簫仙子來。", "當年作樓遠塵務，坊僧執籌工執鋸。", "愛他欄檻看雲山，不肯怱怱下樓去。"]'),
('2a823cc7-19ba-4d19-aaa7-65436f2b68a3','雪中月波即事','葛紹體','宋','宋诗','song-poetry','','[]','天地黯淡疑古初，遠近依約垂冰壺。',216,'全唐诗/poet.song.209000.json','["天地黯淡疑古初，遠近依約垂冰壺。", "樓閣突兀撐蘧廬，林阜參差自縈紆。", "極目似接滄溟虛，流水迤邐隨城隅。", "客舟飄颻帆影孤，紫幕半罩推蓬圖。", "須臾四面雲糢糊，舞風片片細和麤。", "带雨點點密更疎，陣復一陣低勻鋪。", "梅腮破紅笑卷舒，柳眼含赤窺榮枯。", "水鴨飛去投平蕪，野雁鳴來落寒蘆。", "巷嫗追逐携雙姝，巧花入時壓鬢梳。", "艷歌逸響龡笙竽，酒酣意氣高陽徒。", "蓴盤快斫松江鱸，茶鼎漸融女牆酥。", "駕言旋返日已晡，馬驕不羨灞橋馿。", "人言雪瑞慶農夫，况此連雪祥可符，黄土耕桑拱行都。"]'),
('6e4a07bb-c94b-42c1-b7f6-cd61420dd13b','春曉訪客','葛紹體','宋','宋诗','song-poetry','','[]','述作當經綸，孤燈坐到晨。',48,'全唐诗/poet.song.209000.json','["述作當經綸，孤燈坐到晨。", "笑迎東海日，喚起北窗人。", "露滴煙梢靜，鳥啼花逕春。", "自憐身是客，與客謾相親。"]'),
('91d03046-35c6-4792-95db-19b8e4de34ce','重陽後五日再和叔愚','葛紹體','宋','宋诗','song-poetry','','[]','不對黄花酒，還添白苧衣。',48,'全唐诗/poet.song.209000.json','["不對黄花酒，還添白苧衣。", "沼鱗空細泳，林翼奮高飛。", "氣槩今誰是，才華昔已非。", "最憐多病後，衣带褪重圍。"]'),
('560d42e4-424a-4834-824f-80fa0b71510e','送趙獻可福州撫幹','葛紹體','宋','宋诗','song-poetry','','[]','往歲南閩路，曾知幕府崇。',48,'全唐诗/poet.song.209000.json','["往歲南閩路，曾知幕府崇。", "已先多士列，不與衆人同。", "紅透荔枝日，香傳茉莉風。", "還應飛詔急，催向道山中。"]'),
('4333dfd4-dc5a-4ad4-aa8c-dbf1ada13e2f','青堅即事','葛紹體','宋','宋诗','song-poetry','','[]','老檜依庭下，青堅自舊名。',48,'全唐诗/poet.song.209000.json','["老檜依庭下，青堅自舊名。", "林深便靜坐，徑淺却幽深。", "逗日分松色，迎風和竹聲。", "相韓親匾字，相對有餘清。"]'),
('a1e747fd-6d44-4dfe-bf42-c5f36935286f','韓氏與閑即事','葛紹體','宋','宋诗','song-poetry','','[]','堂深暑不到，閑意一爐香。',48,'全唐诗/poet.song.209000.json','["堂深暑不到，閑意一爐香。", "棋鬭過河急，琴彈流水長。", "古瓶疎牖下，怪石小池旁。", "忠獻畫圖在，英聲不可忘。"]'),
('9c086308-a8bc-4362-a4df-83211e79a86c','洵上人房','葛紹體','宋','宋诗','song-poetry','','[]','自占一窗明，小爐春意生。',48,'全唐诗/poet.song.209000.json','["自占一窗明，小爐春意生。", "茶分香味薄，梅插小枝橫。", "有意探禪學，無心了世情。", "不知清夜坐，知得若爲清。"]'),
('1695d068-6662-41cc-979d-91b14758bcd2','遊本覺寺','葛紹體','宋','宋诗','song-poetry','','[]','招提俯秋水，畫手借王維。',48,'全唐诗/poet.song.209000.json','["招提俯秋水，畫手借王維。", "清磬遞風韻，曉霜翻露姿。", "茶煙邀客竚，帆影喚舟移。", "他日成歸夢，來興楚子悲。"]'),
('a0deaa1e-d79e-4eb0-8d36-5d995fbddfff','謝韓次公趙獻可踐西湖約','葛紹體','宋','宋诗','song-poetry','','["\u897f\u6e56"]','渺渺錢塘路，相携秋色新。',48,'全唐诗/poet.song.209000.json','["渺渺錢塘路，相携秋色新。", "馬蹄沙尾雨，舟楫渡頭雲。", "世道已非古，交情此是真。", "覊棲正愁絕，得爾張吾軍。"]'),
('1f8dab75-31cc-48a4-a333-373de264625f','留別永嘉文友','葛紹體','宋','宋诗','song-poetry','','[]','歸去是明朝，多應趁早朝。',48,'全唐诗/poet.song.209000.json','["歸去是明朝，多應趁早朝。", "雖然鄰邑近，亦似客程遥。", "村社酒三杓，山家水一瓢。", "吟邊如得句，共語在元宵。"]'),
('745197d4-703b-4c0e-860b-1cd9aa23a33e','送上蔡謝悔齋赴召','葛紹體','宋','宋诗','song-poetry','','["\u897f\u6e56"]','詔趣朝天去，春風半月程。',48,'全唐诗/poet.song.209000.json','["詔趣朝天去，春風半月程。", "西湖花錦重，東越柳綿輕。", "趨走輸年少，謀猷讓老成。", "邊烽半明滅，𤱶畝一關情。"]'),
('92f03555-61a6-4d7f-92e0-f6896bdbd66b','早發西城即景','葛紹體','宋','宋诗','song-poetry','','[]','天台今日去，步步紫雲鄉。',48,'全唐诗/poet.song.209000.json','["天台今日去，步步紫雲鄉。", "麥浪漲新綠，花風吹舊香。", "屏開千嶂遠，带遶一溪長。", "遊冶誰家子，酣歌古道傍。"]'),
('4efbc3e6-6f30-4a60-afdc-dd73dadc522d','道傍酒家','葛紹體','宋','宋诗','song-poetry','','[]','門當海嶠開，籬脚破新苔。',48,'全唐诗/poet.song.209000.json','["門當海嶠開，籬脚破新苔。", "梅影落寒井，漁歌近酒杯。", "客帆雲外過，沙鳥雨中迴。", "多少風煙趣，從今入夢來。"]'),
('065b944e-3798-44b7-8d86-032796f8f77b','新昌道中','葛紹體','宋','宋诗','song-poetry','','[]','歸路忘羈思，邛枝第共携。',48,'全唐诗/poet.song.209000.json','["歸路忘羈思，邛枝第共携。", "江船閑載鶴，山店靜聞雞。", "晚稻新收歛，秋花舊品題。", "明朝行幾里，應近赤城西。"]'),
('9ef8b3c1-62c1-4d91-9c52-3025925c3990','寄三衢趙希遠','葛紹體','宋','宋诗','song-poetry','','[]','同是他鄉客，分携二月初。',48,'全唐诗/poet.song.209000.json','["同是他鄉客，分携二月初。", "如何近流火，曾不寄來書。", "夜雨青燈暗，晨風黄卷舒。", "相思五字句，惠好莫相疎。"]'),
('2c14e29d-7fdb-4e8d-a6ce-ed44297b53f3','寄越中文友','葛紹體','宋','宋诗','song-poetry','','[]','客情無處著，身事定何如。',48,'全唐诗/poet.song.209000.json','["客情無處著，身事定何如。", "秀水且停棹，蕺山終結廬。", "秋風一杯酒，夜雨半繙書。", "把手蓬萊頂，梅花臘月初。"]'),
('b75af57d-ca2f-41f0-a248-16c45d3b3db1','卧病','葛紹體','宋','宋诗','song-poetry','','[]','欹枕小春雨，虛屏半夜風。',48,'全唐诗/poet.song.209000.json','["欹枕小春雨，虛屏半夜風。", "病驚身是客，愁恐鬢成翁。", "窗曙逗微白，燈寒带淺紅。", "歸期倩誰卜，心挂浙江東。"]'),
('18ed2bdb-f9be-4cd6-b2fb-2051afee6c0d','送林子柄縉雲令','葛紹體','宋','宋诗','song-poetry','','[]','交情苦疎闊，君復是行人。',48,'全唐诗/poet.song.209000.json','["交情苦疎闊，君復是行人。", "燈火誰同坐，詩書只自親。", "丹楓蒼嶺曉，黄菊好溪春。", "一別三年遠，相思入夢頻。"]'),
('6ab382c4-6c99-4ed6-ac27-e0781cdda014','送王伯逢泰興令','葛紹體','宋','宋诗','song-poetry','','[]','揚子江頭路，龜池草色新。',48,'全唐诗/poet.song.209000.json','["揚子江頭路，龜池草色新。", "細調絃上曲，閑拂馬前塵。", "遠塞秋風靜，平疇夜雨勻。", "遥知報嘉政，笑我苦吟身。"]'),
('01a5da6a-a55a-4965-bdb1-9ea5aa316b5f','送趙紫芝入金陵幕','葛紹體','宋','宋诗','song-poetry','','[]','會面難如此，人生祇自憐。',48,'全唐诗/poet.song.209000.json','["會面難如此，人生祇自憐。", "笑言無一日，離別有三年。", "故國带秋色，長淮起暮煙。", "官閑足登眺，吟滿菊花天。"]'),
('21012ad2-8c18-4a3b-9176-f67fef35586e','送王秀才同謝德慶行','葛紹體','宋','宋诗','song-poetry','','[]','三千八百里，何自遽成行。',48,'全唐诗/poet.song.209000.json','["三千八百里，何自遽成行。", "只重新知己，都忘逆旅情。", "瘴煙隨處合，庾嶺際天橫。", "應有相思淚，清宵夢裏驚。"]'),
('f43e96d4-387c-4e67-896b-80f1515a4cc3','送翁靈舒','葛紹體','宋','宋诗','song-poetry','','[]','尋常居異所，客路得同行。',48,'全唐诗/poet.song.209000.json','["尋常居異所，客路得同行。", "別久話難盡，路長愁易生。", "湘江春自綠，衡嶽古來青。", "何似歸休好，西巖深處耕。"]'),
('3c7b2545-8661-4175-b6a6-afdc17d722e5','送高仲發赴銓  其一','葛紹體','宋','宋诗','song-poetry','','[]','不記京華路，西行有幾程。',48,'全唐诗/poet.song.209000.json','["不記京華路，西行有幾程。", "因君一言別，動我十年情。", "野水涵天碧，山花照眼明。", "春風馬蹄急，得意向東城。"]'),
('96827473-5410-4d97-9184-3a0283102805','送高仲發赴銓  其二','葛紹體','宋','宋诗','song-poetry','','[]','多應無旅思，天氣正春暄。',48,'全唐诗/poet.song.209000.json','["多應無旅思，天氣正春暄。", "柳送行時路，花迎到處村。", "捷書新得意，詩句舊曾論。", "獨坐相思日，東風靜掃門。"]'),
('37b904ce-2a70-4818-95f1-080f38e5dba9','送薛子舒華亭造船場','葛紹體','宋','宋诗','song-poetry','','[]','此日携家去，休言惜遠離。',48,'全唐诗/poet.song.209000.json','["此日携家去，休言惜遠離。", "江天雖雨意，客路正花時。", "擊楫漫長嘯，把書常自隨。", "爲官閑亦好，竹外鶴偏宜。"]'),
('5e54bcc2-ae70-40dc-b816-589a0318854d','浸碧亭月夜','葛紹體','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夜半橫空一片雲，雲邊明月带疎星。',64,'全唐诗/poet.song.209000.json','["夜半橫空一片雲，雲邊明月带疎星。", "松關露重驚飛鵲，荷渚風輕低度螢。", "粟綴嫩黄懷老圃，酒篘新綠見虛亭。", "秋吟不作相思調，許我西湖伴醉醒。"]'),
('91e474a4-617e-4468-aa0c-686df74bf40d','九日登真如閣','葛紹體','宋','宋诗','song-poetry','','[]','雲閣憑高起暮愁，西風吹作帽簷秋。',64,'全唐诗/poet.song.209000.json','["雲閣憑高起暮愁，西風吹作帽簷秋。", "煙林回薄地欲轉，水國蒼茫天共浮。", "富貴從來聯後乘，行藏何處借前籌。", "東籬又負黄花約，新月光中一獻酬。"]'),
('5e25ec46-a650-49f5-86c6-3a7b82330bbd','韓吏部竹隠亭','葛紹體','宋','宋诗','song-poetry','','[]','秋浦星郎舊隠居，石巢長伴竹蕭疎。',64,'全唐诗/poet.song.209000.json','["秋浦星郎舊隠居，石巢長伴竹蕭疎。", "寒窗細酌月來往，暑檻殘編風卷舒。", "硯滴凈涵天地祕，爐煙閑接水雲虛。", "風流格調今猶在，有子挑燈讀父書。"]'),
('0e64606b-1b98-47ca-b5b9-13d9fdf763fc','水陸寺','葛紹體','宋','宋诗','song-poetry','','[]','松柏蒼蒼蔭碧瀾，碧瀾深處有龍蟠。',64,'全唐诗/poet.song.209000.json','["松柏蒼蒼蔭碧瀾，碧瀾深處有龍蟠。", "清閑日月長廊靜，慘澹雲烟畫閣寒。", "林鳥忽鳴疑悟道，石磯危坐似逃禪。", "天台行客東嘉友，一笑春風共倚欄。"]'),
('a8aca621-7ea8-4410-be0b-0f7489460a3a','寄謝周西麓國博','葛紹體','宋','宋诗','song-poetry','','[]','三年涕血漬槃蔬，蓬首春風未欲梳。',64,'全唐诗/poet.song.209000.json','["三年涕血漬槃蔬，蓬首春風未欲梳。", "客病屢驚幾死去，母慈常念有生初。", "乞文西麓標銘墓，立石東山伴倚廬。", "恩到九原那可答，近來和淚看除書。"]'),
('fb53f1f2-dc6b-4ed3-bc89-7314bb91c263','次韻杜十三丈','葛紹體','宋','宋诗','song-poetry','','[]','雙溪風月只當年，客夢尋君屢慨然。',64,'全唐诗/poet.song.209000.json','["雙溪風月只當年，客夢尋君屢慨然。", "萬里青雲誰覽鏡，一窗黄卷自鳴鞭。", "病餘念此懷憂樂，醉裏從其號聖賢。", "多少離情那寫似，排空煙柳綠無邊。"]'),
('4e67fbec-6cec-48b0-83fb-4b8946edbb8a','太師汪煥章社日勸農余出湖曲  其一','葛紹體','宋','宋诗','song-poetry','','[]','飛旆行春沐雨天，風光一陣雜晴煙。',32,'全唐诗/poet.song.209000.json','["飛旆行春沐雨天，風光一陣雜晴煙。", "麥苗綠潤秧芽嫩，鼓吹聲中卜有年。"]'),
('a95dc1a2-5041-4714-87b2-0d37048096b8','太師汪煥章社日勸農余出湖曲  其二','葛紹體','宋','宋诗','song-poetry','','[]','春勸老農誇歲歲，晚飛新燕賀年年。',32,'全唐诗/poet.song.209000.json','["春勸老農誇歲歲，晚飛新燕賀年年。", "鑑湖一棹煙波客，燕舞農歌伴醉眠。"]'),
('d1cca83a-db51-4360-9b84-1d19856be6d4','春曉散步','葛紹體','宋','宋诗','song-poetry','','[]','書滿曉窗看不暇，推書起步略尋閑。',32,'全唐诗/poet.song.209000.json','["書滿曉窗看不暇，推書起步略尋閑。", "春酣風日生光怪，不在煙村花柳間。"]'),
('4701907a-00f6-4eb4-a696-106ea67471c9','春日即事二首  其一','葛紹體','宋','宋诗','song-poetry','','[]','地僻人稀春日長，小池波暖浴鴛鴦。',32,'全唐诗/poet.song.209000.json','["地僻人稀春日長，小池波暖浴鴛鴦。", "閑拈藜杖歸來晚，簾幙風微花氣香。"]'),
('f8ce0576-3749-4bd1-9d2d-cff4c59815c4','春日即事二首  其二','葛紹體','宋','宋诗','song-poetry','','[]','一带青煙護白溪，溪流橫截路東西。',32,'全唐诗/poet.song.209000.json','["一带青煙護白溪，溪流橫截路東西。", "早春晴日自風度，嶺樹數聲春鳥啼。"]'),
('11b00b46-46bf-49ce-be09-4287b2d7410c','惜春二首  其一','葛紹體','宋','宋诗','song-poetry','','[]','晴日無多雨日多，春藏花底暗消磨。',32,'全唐诗/poet.song.209000.json','["晴日無多雨日多，春藏花底暗消磨。", "一年尚有幾春色，花若飄零春奈何。"]'),
('cdb0d4e9-e710-4e55-bb83-2bc15c3da0b2','惜春二首  其二','葛紹體','宋','宋诗','song-poetry','','[]','桐角聲中春欲歸，一番桃李又空枝。',32,'全唐诗/poet.song.209000.json','["桐角聲中春欲歸，一番桃李又空枝。", "楊花好與春將息，莫被東風容易吹。"]'),
('31996465-5c97-4fd7-9432-743af359328d','春懷','葛紹體','宋','宋诗','song-poetry','','[]','春衫曾著淚痕斑，才到年時怕倚欄。',32,'全唐诗/poet.song.209000.json','["春衫曾著淚痕斑，才到年時怕倚欄。", "何處飛來雙燕子，傍人還欲訴春寒。"]'),
('32f78e12-6d02-4ee3-8dc6-27a582bd2dd1','晚春','葛紹體','宋','宋诗','song-poetry','','[]','過了紅芳又綠陰，綠陰多處覺春深。',32,'全唐诗/poet.song.209000.json','["過了紅芳又綠陰，綠陰多處覺春深。", "東皇自是成功早，取次南風入舜琴。"]'),
('79db30dd-5907-4524-adb7-41891fc17dd5','暑雨','葛紹體','宋','宋诗','song-poetry','','[]','連日霏霏濕夕陽，灑衣沾席碎聲長。',32,'全唐诗/poet.song.209000.json','["連日霏霏濕夕陽，灑衣沾席碎聲長。", "暑天不是苦多雨，愛與人間生晚凉。"]'),
('fbf94623-a67a-41c7-8614-293ead9e180c','雨夜','葛紹體','宋','宋诗','song-poetry','','[]','風雨無情斷送春，牡丹誰與伴黄昏。',32,'全唐诗/poet.song.209000.json','["風雨無情斷送春，牡丹誰與伴黄昏。", "枕書睡去覺來晚，庭鶴一聲驚旅魂。"]'),
('b1e6f979-e971-46ca-83c1-ddb7b7ccfb62','晚晴','葛紹體','宋','宋诗','song-poetry','','[]','風頭雨歇靜簷花，渡口人稀解釣蓑。',32,'全唐诗/poet.song.209000.json','["風頭雨歇靜簷花，渡口人稀解釣蓑。", "零落斷雲無處著，滿湖秋水夕陽多。"]'),
('b9583ec4-2625-4505-8fb2-9b2fc5f65cb5','十五夜聽雨','葛紹體','宋','宋诗','song-poetry','','[]','斷續寒聲落晚紅，擁爐閑對逗香風。',32,'全唐诗/poet.song.209000.json','["斷續寒聲落晚紅，擁爐閑對逗香風。", "醉迷客思醒依舊，不在芭蕉點滴中。"]'),
('dfa445a7-fad8-4437-9d63-ed91f595928b','城中月夜','葛紹體','宋','宋诗','song-poetry','','[]','霜天如洗月鮮明，少醉街南取次行。',32,'全唐诗/poet.song.209000.json','["霜天如洗月鮮明，少醉街南取次行。", "閑聽梅花引吹徹，滿樓槌鼓報初更。"]'),
('2f8c0f09-a9c6-49c5-a3e8-9be73274bb06','九日','葛紹體','宋','宋诗','song-poetry','','[]','不管西風吹帽紗，出門閑步夕陽斜。',32,'全唐诗/poet.song.209000.json','["不管西風吹帽紗，出門閑步夕陽斜。", "平湖水落蒼黄處，一段風煙蘆荻花。"]'),
('67f38d82-890e-4616-8831-6bcb84f643a3','九日寄渭南文友','葛紹體','宋','宋诗','song-poetry','','[]','自古吳興山水窟，只今杖屨幾人閑。',32,'全唐诗/poet.song.209000.json','["自古吳興山水窟，只今杖屨幾人閑。", "懷君九日登臨處，知向何山向道山。"]'),
('a1134769-2c1b-4575-9400-f0687849bf69','重陽前三日和叔愚縣尉','葛紹體','宋','宋诗','song-poetry','','[]','年年客路即爲家，多病謀生未有涯。',32,'全唐诗/poet.song.209000.json','["年年客路即爲家，多病謀生未有涯。", "料得重陽好風日，自無情緒對黄花。"]'),
('45df2ba1-287b-46cd-9b03-71c4a5ffbf9f','煙雨館立冬前一日','葛紹體','宋','宋诗','song-poetry','','[]','已過重陽種菊花，留連秋色带霜華。',32,'全唐诗/poet.song.209000.json','["已過重陽種菊花，留連秋色带霜華。", "休言明日朔風起，腸斷天涯人憶家。"]'),
('fb1e58bf-c6a0-4540-a9c2-61b114005109','觀雪','葛紹體','宋','宋诗','song-poetry','','[]','只是尋常雲雨曉，歲寒然後見天真。',32,'全唐诗/poet.song.209000.json','["只是尋常雲雨曉，歲寒然後見天真。", "人間莫作寒愁想，一片飛來一片春。"]'),
('d0b76160-e7ea-4b59-9d8f-efe567b19527','早起','葛紹體','宋','宋诗','song-poetry','','[]','竹聲枕上報平安，曙色依稀隔幌寒。',32,'全唐诗/poet.song.209000.json','["竹聲枕上報平安，曙色依稀隔幌寒。", "風雨滿庭人未起，蛛絲斜挂碎珠團。"]'),
('55021d7e-1c1c-45f5-b9fe-9097f6b76130','睡起','葛紹體','宋','宋诗','song-poetry','','[]','西風攪雨十分秋，誰駕秋濤汗漫遊。',32,'全唐诗/poet.song.209000.json','["西風攪雨十分秋，誰駕秋濤汗漫遊。", "日午小窗初睡起，一回魂夢到滄洲。"]'),
