('2a5bfb4c-4b68-42d0-9ee2-0b93115bb09b','臘月二日煙雨館','葛紹體','宋','宋诗','song-poetry','','[]','天上飛花報歲寒，西風相挾引欄干。',32,'全唐诗/poet.song.209000.json','["天上飛花報歲寒，西風相挾引欄干。", "平湖不認花多少，只作尋常煙雨看。"]'),
('2f352c1b-80fd-424e-a9e1-af897a85a001','三日雪後飲煙雨館  其一','葛紹體','宋','宋诗','song-poetry','','[]','傍湖千樹玉參差，湖面輕風落釣絲。',32,'全唐诗/poet.song.209000.json','["傍湖千樹玉參差，湖面輕風落釣絲。", "晚色晴陰正商略，斷雲來去半猶癡。"]'),
('4143afa9-8926-4ece-857e-63730c28bae4','三日雪後飲煙雨館  其二','葛紹體','宋','宋诗','song-poetry','','[]','旋融殘雪點團茶，碧凈紅鮮朵上花。',32,'全唐诗/poet.song.209000.json','["旋融殘雪點團茶，碧凈紅鮮朵上花。", "客散亭閑半湖水，月梳斜掠晚晴霞。"]'),
('491b9efe-63b3-4f03-9566-1b9db003e1b3','煙雨館晚對','葛紹體','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一片斜陽天北角，半痕初月水東彎。',32,'全唐诗/poet.song.209000.json','["一片斜陽天北角，半痕初月水東彎。", "浮煙更擁雲峰起，全似西湖遠近山。"]'),
('149e3da6-c46c-4cc2-90b0-107339c4d9d5','保應廟','陳東之','宋','宋诗','song-poetry','','[]','投迹空山計已非，江都消息亂來稀。',32,'全唐诗/poet.song.209000.json','["投迹空山計已非，江都消息亂來稀。", "廟前幾種春香草，錯怪王孫去不歸。"]'),
('009e8214-d08c-43c4-8bd0-5951a5b8d10c','游沃洲山','陳東之','宋','宋诗','song-poetry','','[]','我本名山人，屢作名山興。',386,'全唐诗/poet.song.209000.json','["我本名山人，屢作名山興。", "天台一住三十年，盡日捫蘿陟雲磴。", "上攬四萬八千丈之高秋，參差明河兩肩並。", "下瞰三百六十度之朝暾，滅沒飛烟八荒浄。", "或隨仙氣得丹牀，雙闕夜深看斗柄。", "今年積雨天地晴，一策快作西南征。", "沃洲最佳天姥勝，連山直下秋崢嶸。", "竹萌修纖會稽箭，芝莖菌蠢商山英。", "秋陽不碎空翠影，絕壑倒瀉銀河聲。", "山腰細路如絲直，三兩漁樵行落日。", "炊烟暝色小茅屋，松子秋聲斷崖石。", "溪流飯屑胡麻香，土軟春膏霜朮白。", "送書松際有猿公，問酒磵陰多木客。", "青冥樓閣仙人家，鬰藍流光瀉晴碧。", "霓旌隊下鶴萬群，絳節朝回雲五色。", "人間但有桃花源，桃花春香流水渾。", "三生凡骨不得到，兩耳夜半空聽猿。", "李白尋真不得返，支遁卜築遠費錢。", "至今山靈護光怪，石蘿山薜餘秋妍。", "陳郎故宅更深閟，雞犬林塘隔塵世。", "清秋著屐一登之，路僻夕陰門半箇。", "盤陀石在長楠陰，脫略塵纓換秋意。", "晴窗示我兩山圖，老眼摩挲觀一二。", "便揮健筆寫我詩，惜哉賞音今絕稀。"]'),
('8070f6a9-f232-4349-9a66-fc5a80b6b53c','遊虎丘','蔣孝言','宋','宋诗','song-poetry','','[]','秀色回環眼倍明，醒餘灑面竹風清。',32,'全唐诗/poet.song.209000.json','["秀色回環眼倍明，醒餘灑面竹風清。", "快哉氣且吞雲夢，便欲飄然上玉京。"]'),
('07c1a7b9-e95f-4dd0-b792-f5c78f2af4a3','青霞谷','鄭有年','宋','宋诗','song-poetry','','[]','少室隠居空索價，北山俗駕費移文。',32,'全唐诗/poet.song.209000.json','["少室隠居空索價，北山俗駕費移文。", "道人笑破世間事，去住身心如白雲。"]'),
('eaf9ba7d-d4a6-4a10-ad1d-3b4ef2f9c73e','賀喬丞相  其一','厲寺正','宋','宋诗','song-poetry','','[]','喬年國同永，壽星秋見丙。',48,'全唐诗/poet.song.209000.json','["喬年國同永，壽星秋見丙。", "社稷資夾扶，乾坤頼重整。", "善勝在不爭，鎮浮惟以靜。", "金鑑上千秋，愛君時戒警。"]'),
('01c77d93-b73e-41a9-9519-d3238a8d4e4b','賀喬丞相  其二','厲寺正','宋','宋诗','song-poetry','','[]','孔山民具瞻，位高心愈謙。',48,'全唐诗/poet.song.209000.json','["孔山民具瞻，位高心愈謙。", "待人冬日暖，持己曉霜嚴。", "善類藉培植，賢材無滯淹。", "更栽椿百本，歲歲綠陰添。"]'),
('6fb8c4b4-b05c-4ba1-9861-339e61c5405c','賀喬丞相  其三','厲寺正','宋','宋诗','song-poetry','','[]','天下達尊三，加之量海涵。',48,'全唐诗/poet.song.209000.json','["天下達尊三，加之量海涵。", "忠言今稷契，眉壽古彭聃。", "渭水功猶小，汾陽考欲參。", "料應宣勸處，花不數優曇。"]'),
('c5c0f078-57ea-468c-9dc3-f6b29a506859','賀喬丞相  其四','厲寺正','宋','宋诗','song-poetry','','[]','相公一身兼，爵德齒俱全。',48,'全唐诗/poet.song.209000.json','["相公一身兼，爵德齒俱全。", "劍履登金殿，山川錫土田。", "龜遊蓮葉露，蟻泛菊花天。", "白鷺洲邊守，重賡綠竹篇。"]'),
('7137a1ac-aa66-499e-8e5b-500c9470b0e1','賀鄭丞相  其一','厲寺正','宋','宋诗','song-poetry','','[]','天地鍾奇在鄞鄮，代産真儒傅衮繡。',32,'全唐诗/poet.song.209000.json','["天地鍾奇在鄞鄮，代産真儒傅衮繡。", "明良千載會風雲，虎拜萬年同國壽。"]'),
('f65bd9d1-2f85-445a-83d5-f58fe3da9b90','賀鄭丞相  其二','厲寺正','宋','宋诗','song-poetry','','[]','和羹梅傍小春榮，堯陛猶餘一莢蓂。',32,'全唐诗/poet.song.209000.json','["和羹梅傍小春榮，堯陛猶餘一莢蓂。", "萬里雲收天鏡浄，三台星畔老人星。"]'),
('03dc0211-0f3f-4306-a62c-9fec32d63fb0','賀鄭丞相  其三','厲寺正','宋','宋诗','song-poetry','','[]','瑞應金穰均禹甸，三邊洗甲誰言戰。',32,'全唐诗/poet.song.209000.json','["瑞應金穰均禹甸，三邊洗甲誰言戰。", "關河豈但犬羊奔，郊藪殆將麟鳳見。"]'),
('a499afa1-bcad-47ea-aca9-437bc2577534','賀鄭丞相  其四','厲寺正','宋','宋诗','song-poetry','','[]','大學道惟一能靜，國勢尊安如九鼎。',32,'全唐诗/poet.song.209000.json','["大學道惟一能靜，國勢尊安如九鼎。", "致君事業比臯夔，不羨蕭曹并魏丙。"]'),
('925c026e-5ad7-431c-aafb-746a1f57bbd8','賀鄭丞相  其五','厲寺正','宋','宋诗','song-poetry','','[]','人才誰不出陶鎔，耆舊皆歸聘召中。',32,'全唐诗/poet.song.209000.json','["人才誰不出陶鎔，耆舊皆歸聘召中。", "周室中興由任使，頌聲今可繼周崧。"]'),
('10c0f740-fb66-4daa-8b73-84aafed37e5f','賀鄭丞相  其六','厲寺正','宋','宋诗','song-poetry','','[]','耆艾何須比龜鶴，高深豈止如川嶽。',32,'全唐诗/poet.song.209000.json','["耆艾何須比龜鶴，高深豈止如川嶽。", "但祈公永輒蘿圖，常誦緝熙比帝學。"]'),
('991680bd-4a48-4e49-9de1-7ad7efe18aeb','賀鄭丞相  其七','厲寺正','宋','宋诗','song-poetry','','[]','貴極台衡世莫京，依然璧水一儒生。',32,'全唐诗/poet.song.209000.json','["貴極台衡世莫京，依然璧水一儒生。", "只將無限寬洪意，上爲皇家致太平。"]'),
('e9887972-36b4-49c3-83d7-1ac766b6fd41','賀鄭丞相  其八','厲寺正','宋','宋诗','song-poetry','','[]','遥想翹材集賀賓，未饒珠履壽春申。',32,'全唐诗/poet.song.209000.json','["遥想翹材集賀賓，未饒珠履壽春申。", "原嗟老守師門士，獨望黄扉種大椿。"]'),
('d0157a6d-232b-4eab-8af0-654d5f942df6','塞馬歌答楊侍郎','蕭元之','宋','宋诗','song-poetry','','[]','侍郎贈我六尺騟，矯矯龍性天骨殊。',240,'全唐诗/poet.song.209000.json','["侍郎贈我六尺騟，矯矯龍性天骨殊。", "四蹄鐵立目電閃，此其壯志畏長驅。", "牽來細觀問廝養，何物有此權奇狀。", "爲言此是古孫龍，往往得之沙塞上。", "森張霧鬣碨礌鬉，蕭稍駿尾摇朔風。", "冰河蹙裂蹄甲銳，竹批兩耳雙方瞳。", "向時淮西屢戰勝，曾馱猛士敲金鐙。", "帳前欲得不敢言，空懸寶珠光照乘。", "我有百發落雁鈚，前年引滿射赤眉。", "功成萬死不見賞，歸騎馿子吟楚詞。", "浮沈不作飛騰夢，感公贈我意勤重。", "旋蒙臯比作鞍韉，更染青絲結韁鞚。", "祗今中原狐兔鳴，黄沙莽莽白骨腥。", "願公急起掃欃槍，百萬勳業一旦成。", "我當乘此載前旌，男兒報義要輕生。"]'),
('6aa1fa93-3f44-4ab1-9d73-5ea7c6b143fe','送郡守張宗丞  其一','蕭元之','宋','宋诗','song-poetry','','[]','淮漢秋風起，邊聲不可聽。',48,'全唐诗/poet.song.209000.json','["淮漢秋風起，邊聲不可聽。", "九重選良牧，內地著郎星。", "土沃桑麻長，城荒草樹青。", "民居多近水，一一是江亭。"]'),
('ee00a114-904a-4ee4-953b-8fd8f603ba02','送郡守張宗丞  其二','蕭元之','宋','宋诗','song-poetry','','[]','淚落鄉邦事，民痍久未瘳。',48,'全唐诗/poet.song.209000.json','["淚落鄉邦事，民痍久未瘳。", "官收隨畝券，人上運糧舟。", "寇起征方急，年饑糴未休。", "更聞來取楮，何以應需求。"]'),
('32ede162-de82-44a6-b99c-8aa6334e1094','送郡守張宗丞  其三','蕭元之','宋','宋诗','song-poetry','','[]','本是詩書種，躬耕寂寞濱。',48,'全唐诗/poet.song.209000.json','["本是詩書種，躬耕寂寞濱。", "傾家市鞍馬，捐命犯風塵。", "幕府差功級，京華困旅貧。", "不如歸去好，依舊號詩人。"]'),
('b07cab07-5212-4a4f-ab60-4b1b459af2e7','送季庸奉祠歸里','蕭元之','宋','宋诗','song-poetry','','[]','昭代昌文化，無人歎陸沈。',48,'全唐诗/poet.song.209000.json','["昭代昌文化，無人歎陸沈。", "諸公自才傑，吾道正山林。", "紫蓋三年綠，滄波萬里心。", "長安豈無路，塵起汙瑶簪。"]'),
('ac07ab20-bf8d-4570-944c-1e8b7252f2b2','別趙李曹  其一','蕭元之','宋','宋诗','song-poetry','','[]','蓮幕皆佳士，如君淡素何。',48,'全唐诗/poet.song.209000.json','["蓮幕皆佳士，如君淡素何。", "圄空公事少，官滿薦書多。", "憂國關豐歉，籌邊定戰和。", "艱難別知己，吾道欲滄波。"]'),
('7d48da28-bd4e-4225-9dfe-fcdd6e7cfa13','別趙李曹  其二','蕭元之','宋','宋诗','song-poetry','','[]','相別日雖淺，相期意獨深。',48,'全唐诗/poet.song.209000.json','["相別日雖淺，相期意獨深。", "那知成遠別，何以慰孤吟。", "旅鴈蘆花浦，啼猿楓樹林。", "明朝應此念，把酒亦愁心。"]'),
('2e1c7971-e0cf-46bb-81ee-ab2fa0676da8','聞德音入蜀','蕭元之','宋','宋诗','song-poetry','','[]','蜀山萬里外，聖主得遥聞。',48,'全唐诗/poet.song.209000.json','["蜀山萬里外，聖主得遥聞。", "歸使愁無路，遺黎泣見君。", "千年文物郡，百戰虎狼羣。", "才退慚司馬，無因寫檄文。"]'),
('f36bfdf0-8623-4a42-b263-2024256eed3f','行子','蕭元之','宋','宋诗','song-poetry','','[]','行子家何處，征帆楚岸開。',48,'全唐诗/poet.song.209000.json','["行子家何處，征帆楚岸開。", "滄江還幾曲，白鳥忽雙來。", "別酒寒衝醒，輕舟浪打回。", "孤懷正牢落，更聽暮猿哀。"]'),
('f244839d-405f-4f51-9ab9-c529d8eabcb5','立春日大雪作代簡招友','蕭元之','宋','宋诗','song-poetry','','[]','山意久辭臘，林根凍未消。',48,'全唐诗/poet.song.209000.json','["山意久辭臘，林根凍未消。", "清尊如有待，白髮正無聊。", "歲去梅花在，春初柳絮飄。", "同吟二三子，折簡可能招。"]'),
('b6427e33-c176-4527-bdf7-0105338968f8','西山道中','蕭元之','宋','宋诗','song-poetry','','[]','省得離家日，秋風吹我衣。',48,'全唐诗/poet.song.209000.json','["省得離家日，秋風吹我衣。", "客吟詩句贈，兒問幾時歸。", "獨宿孤村館，長懷舊竹扉。", "羈愁不堪觸，山雨暗斜暉。"]'),
('78bc3f5f-c38c-4113-bbc2-b9020c8f5b0e','清明省掃歸舟陸相半','蕭元之','宋','宋诗','song-poetry','','[]','一徑險仍修，沿溪去未休。',48,'全唐诗/poet.song.209000.json','["一徑險仍修，沿溪去未休。", "薜蘿春暗樹，楊柳暮遮樓。", "蕩槳漁舟駛，寒鐘僧寺幽。", "倚篷賒濁酒，猶可洗詩愁。"]'),
('76f2831a-c692-4bb1-97a3-c97413ab7f03','傷盧長史居','蕭元之','宋','宋诗','song-poetry','','[]','昔年傳得文標集，每對青燈一起予。',32,'全唐诗/poet.song.209000.json','["昔年傳得文標集，每對青燈一起予。", "偶訪袁人尋古事，舊時居處已民居。"]'),
('a16d9224-20cd-439e-9c7c-8402f5e8253b','還西里所居  其一','蕭元之','宋','宋诗','song-poetry','','[]','長恐山林計未成，可能俯仰羨公卿。',32,'全唐诗/poet.song.209000.json','["長恐山林計未成，可能俯仰羨公卿。", "鶴閑不受雲拘束，梅冷惟堪雪主盟。"]'),
('c64a3bf0-90e4-4fbd-8971-59fea8f06c16','還西里所居  其二','蕭元之','宋','宋诗','song-poetry','','[]','北闕無書休悔出，東皋有秫可歸耕。',32,'全唐诗/poet.song.209000.json','["北闕無書休悔出，東皋有秫可歸耕。", "鏡容漸改驚非昔，猶喜傍人喚後生。"]'),
('4ac17792-360b-4e6b-9e29-35f287950765','南浦泊舟','蕭元之','宋','宋诗','song-poetry','','[]','重來江閣俯滄流，一带西山萬古愁。',32,'全唐诗/poet.song.209000.json','["重來江閣俯滄流，一带西山萬古愁。", "漁叟不知來客意，徑移船過北沙頭。"]'),
('3dd95250-33aa-48d3-bd56-35bf4e4abce6','與程右史論詩道','蕭元之','宋','宋诗','song-poetry','','[]','我嘗論詩始，其道最希夷。',288,'全唐诗/poet.song.209000.json','["我嘗論詩始，其道最希夷。", "神工裂渾沌，聲音相雄雌。", "物理何鉅細，人性無妍媸。", "當其天真發，各鳴志所之。", "斯民樸未散，粹如玉不疵。", "老穉壤衢日，君臣賡歌時。", "下逮雅頌作，間列民風熙。", "怡愉且密勿，和厚無澆漓。", "固經聖人擇，要匪古義虧。", "屈宋變賦體，蘇李五字詩。", "七字追迅電，陶謝縈寒漪。", "雖各騁逸思，猶如觀尊彜。", "但有奇古意，了非斧鑿姿。", "傷心玉臺後，巧麗爭紛披。", "雕鎪以爲工，叫噪以爲奇。", "詩乃一技爾，那復古道爲。", "有唐李與杜，切切哀其衰。", "稍欲復古作，便覺騷些遺。", "後人好異論，鹹酸各行私。", "白以詭見斥，甫以樸見嗤。", "那知托奧妙，中有真趣怡。", "昧昧作者流，行行信且疑。", "我嘗任胸臆，謂自唐無詩。", "山川或登覽，朋友或聚離。"]'),
('8f2c1a55-9e81-4f19-add2-69ffa966d5e3','偶成  其一','蕭元之','宋','宋诗','song-poetry','','[]','拋却滄江事遠遊，獨携弓劍上邊頭。',32,'全唐诗/poet.song.209000.json','["拋却滄江事遠遊，獨携弓劍上邊頭。", "群胡忽遁陰山北，欲渡河冰不自由。"]'),
('5d5b8a4f-7aa5-4c9c-b93c-aff3e67889aa','偶成  其二','蕭元之','宋','宋诗','song-poetry','','[]','少年鞍馬疾如飛，賣盡儒衣買戰衣。',32,'全唐诗/poet.song.209000.json','["少年鞍馬疾如飛，賣盡儒衣買戰衣。", "老去不知筋力減，夜闌猶夢解重圍。"]'),
('66bbbac6-b649-4b7b-9524-4826ef8e5cb8','它山堰和應煟韻','魏洽','宋','宋诗','song-poetry','','[]','幾何水作四時雷，試去尋源櫂懶迴。',32,'全唐诗/poet.song.209000.json','["幾何水作四時雷，試去尋源櫂懶迴。", "欲看澤民千古樣，我來不是等閑來。"]'),
('a7463d63-ed0a-4ed0-bab0-fd5cfe7ee8bf','謁善政祠','魏{氵雩}','宋','宋诗','song-poetry','','[]','携家再謁長官祠，桂子風吹遊子衣。',64,'全唐诗/poet.song.209000.json','["携家再謁長官祠，桂子風吹遊子衣。", "惠澤至今猶瀚漫，官楹雖古自光輝。", "梅梁偃蹇蒼龍伏，石級參差白雪飛。", "此地本非供玩賞，騷人到此自忘歸。"]'),
('ee3a8e77-2631-4a44-8789-8d0da3551214','茅山','陳塤','宋','宋诗','song-poetry','','[]','三茅高出七山巔，頓隔塵沙道路千。',64,'全唐诗/poet.song.209000.json','["三茅高出七山巔，頓隔塵沙道路千。", "靈籟蕭蕭風笛弄，奇形奕奕隴牛眠。", "人間已有嘉平帝，地下誰通句曲天。", "幸喜吾廬居在此，時從寄傲任悠然。"]'),
('ec8407f6-fc94-4130-872c-801828d3fcef','遊虎丘  其一','陳塤','宋','宋诗','song-poetry','','[]','老龍拖雨過平川，曉影初開樹色鮮。',32,'全唐诗/poet.song.209000.json','["老龍拖雨過平川，曉影初開樹色鮮。", "有片白雲收不盡，日高猶在講堂邊。"]'),
('388a367f-b47e-4fc6-87ce-81bb03607001','遊虎丘  其二','陳塤','宋','宋诗','song-poetry','','[]','碧玉千尋劍影寒，夜深光怪逼危闌。',32,'全唐诗/poet.song.209000.json','["碧玉千尋劍影寒，夜深光怪逼危闌。", "句吳霸略成塵土，空有青山覆石壇。"]'),
('028252d8-06a9-434b-9ec8-b9b9b9ddd7bf','句','陳塤','宋','宋诗','song-poetry','','[]','只教人種菜，莫誤客看花。',12,'全唐诗/poet.song.209000.json','["只教人種菜，莫誤客看花。"]'),
('5e640d28-9033-433c-a705-9ac0d9261bab','使閩過延平','劉震孫','宋','宋诗','song-poetry','','[]','川媚山輝寶氣鍾，尊堯而後幾儒宗。',32,'全唐诗/poet.song.209000.json','["川媚山輝寶氣鍾，尊堯而後幾儒宗。", "往來但指龍津說，不道人中自有龍。"]'),
('5faa21e5-9505-42dd-9586-8eec42eaa6f2','當陽勝處','趙夷夫','宋','宋诗','song-poetry','','[]','當陽勝處好溪山，翠滴溫公寶墨斑。',32,'全唐诗/poet.song.209000.json','["當陽勝處好溪山，翠滴溫公寶墨斑。", "線溜一泓凉意足，須臾膚寸遍人間。"]'),
('f14c29b5-3ac3-4a37-8e86-525b6114364a','懷友','陳柏','宋','宋诗','song-poetry','','[]','携書入空山，幾若與世絕。',48,'全唐诗/poet.song.209000.json','["携書入空山，幾若與世絕。", "俯仰一室間，頗見古人別。", "良朋令人思，思君意彌切。", "食芹差自甘，那得共君啜。"]'),
('d1df2e4f-928e-4adc-b855-58297fbd1ad8','盛雪巢','陳柏','宋','宋诗','song-poetry','','[]','皋夔不著書，周召不决科。',48,'全唐诗/poet.song.209000.json','["皋夔不著書，周召不决科。", "端坐廟堂上，四海臻泰和。", "吾道固如是，後來文藝多。", "嗒然空山中，獨抱明良歌。"]'),
('c5a465d6-d5d4-4bb4-8911-a8eedaa99a3c','白鶴巖','孫汝勉','宋','宋诗','song-poetry','','[]','梵宇深深小徑回，兩崖如削立崔嵬。',64,'全唐诗/poet.song.209000.json','["梵宇深深小徑回，兩崖如削立崔嵬。", "直疑隠客曾吹裂，或是山靈爲劈開。", "林靜烟空時透日，溪喧石老半侵苔。", "凉生佛骨雲生缽，閣住紅塵不入來。"]'),
('01e65b1d-e821-463e-8130-9090f1049373','藥市','陳應斗','宋','宋诗','song-poetry','','[]','肘後應難一一傳，多將靈藥種仙山。',32,'全唐诗/poet.song.209000.json','["肘後應難一一傳，多將靈藥種仙山。", "仙禽搗就仙翁賣，挑杖懸壺走世間。"]'),
('e1b9dfe3-0297-43a8-b746-442cf6e6196a','橫舟','盧會龍','宋','宋诗','song-poetry','','[]','漫浪江湖萬里天，蘋花蘆葉飽風烟。',32,'全唐诗/poet.song.209000.json','["漫浪江湖萬里天，蘋花蘆葉飽風烟。", "五更驚覺家山夢，撇棹歸來月底眠。"]'),
('309ff7f0-8bbf-40c2-a69b-aaaf5ca2577b','冰玉堂','林庚','宋','宋诗','song-poetry','','[]','柳凹放出一山來，堂闖秋壺恰剪裁。',64,'全唐诗/poet.song.209000.json','["柳凹放出一山來，堂闖秋壺恰剪裁。", "門冷和他公事少，吟清添我宦情灰。", "非無景物皆天與，只許梅花带雪開。", "泉石相輝忻自賞，不知省得幾塵埃。"]'),
('97a16378-f8a8-4efe-9fa0-8090e0563b72','游蒼玉洞','錢元忠','宋','宋诗','song-poetry','','["\u592a\u6e56"]','峭嶸亂石滿陵岡，顔色蒼潤如琳琅。',96,'全唐诗/poet.song.209000.json','["峭嶸亂石滿陵岡，顔色蒼潤如琳琅。", "神惻鬼□□□慘，牛眠虎跳深伏藏。", "太湖靈壁不足數，涪水□麥熟可方。", "剝苔剔蘚驗古刻，諸賢□□騰光茫。", "如此至寶豈易得，宜檄山靈護□□。", "□□□□□□□，却恐六丁下取將。"]'),
('295343fa-c749-4064-9770-3f06294bb070','玉樹謠','劉垕','宋','宋诗','song-poetry','','[]','臨春閣下花蒙茸，雕闌玉樹沉香風。',96,'全唐诗/poet.song.209000.json','["臨春閣下花蒙茸，雕闌玉樹沉香風。", "君王酣醉眠未起，滿床明月鮫綃紅。", "羅襦學士文章女，碧葉黄鸝呈好語。", "可憐日暮秋雨來，驚散一庭金翠羽。", "朱門流水自徘徊，井桐花落無人知。", "江南夢斷雁不飛，空城夜夜烏鴉啼。"]'),
('9426e7f4-4499-42d4-9a1a-64f480e484f7','疇依  其一','王柏','宋','宋诗','song-poetry','','[]','元會開物，風氣渾龐。',40,'全唐诗/poet.song.209000.json','["元會開物，風氣渾龐。", "聿生神聖，惟包羲皇。", "始畫八卦，人文炳煌。", "大道之書，誰云已亡。"]'),
('3192cd3a-b601-450b-892b-16bf60b1cab0','疇依  其二','王柏','宋','宋诗','song-poetry','','[]','巍乎大哉，堯之爲君。',40,'全唐诗/poet.song.209000.json','["巍乎大哉，堯之爲君。", "其仁如天，其知如神。", "鑿井耕田，出作入息。", "擊壤而歌，不知帝力。"]'),
('0ea89f28-b316-4d35-ab21-5d01822938a3','疇依  其三','王柏','宋','宋诗','song-poetry','','[]','虞舜側微，重華協帝。',40,'全唐诗/poet.song.209000.json','["虞舜側微，重華協帝。", "父頑母嚚，烝烝以乂。", "天理之極，人倫之至。", "恭己當天，雲行雨施。"]'),
('f0f9e4b5-e3be-459a-82d3-dad97217d852','疇依  其四','王柏','宋','宋诗','song-poetry','','[]','禹乃嗣興，載平水土。',40,'全唐诗/poet.song.209000.json','["禹乃嗣興，載平水土。", "天錫九疇，彝倫攸敘。", "克儉克勤，不伐不矜。", "有典有則，貽厥子孫。"]'),
('ac83631b-ff9d-463e-8f5b-e12d9b1997c0','疇依  其五','王柏','宋','宋诗','song-poetry','','[]','昔在帝堯，咨舜一語。',40,'全唐诗/poet.song.209000.json','["昔在帝堯，咨舜一語。", "允執厥中，舜亦命禹。", "危微精一，義復兼舉。", "三聖授受，獨盛前古。"]'),
('294c644f-5920-40aa-bf16-83e0477ef7e8','疇依  其六','王柏','宋','宋诗','song-poetry','','[]','湯聘莘尹，五進就桀。',40,'全唐诗/poet.song.209000.json','["湯聘莘尹，五進就桀。", "天命人歸，鳴條自葛。", "以義制事，以禮制心。", "日新厥德，鑒此盤銘。"]'),
('f69169e2-0d0f-455a-9de9-6715610e7cb2','疇依  其七','王柏','宋','宋诗','song-poetry','','[]','於穆文王，順帝之則。',40,'全唐诗/poet.song.209000.json','["於穆文王，順帝之則。", "身蒙大難，小心翼翼。", "三分有二，以服事殷。", "可謂至德，萬邦儀刑。"]'),
('6cf9279e-abb9-4603-8cd2-e251f83cffdb','疇依  其八','王柏','宋','宋诗','song-poetry','','[]','武王達孝，善繼善述。',40,'全唐诗/poet.song.209000.json','["武王達孝，善繼善述。", "盟津既誓，干戈載戢。", "訪于箕子，洪範以陳。", "惟皇建極，反覆丁寧。"]'),
('5ba55fb1-efe0-462a-a5bd-09412d5c031d','疇依  其九','王柏','宋','宋诗','song-poetry','','[]','於皇周公，勤勞王家。',40,'全唐诗/poet.song.209000.json','["於皇周公，勤勞王家。", "赤舄几几，德音不瑕。", "思兼三王，以施四事。", "坐以待日，制作大備。"]'),
('f9a46479-e46d-4c92-9da4-2b11d7ea5adb','疇依  其一○','王柏','宋','宋诗','song-poetry','','[]','生民以來，未有孔子。',40,'全唐诗/poet.song.209000.json','["生民以來，未有孔子。", "金聲玉振，始終條理。", "五經之道，天地同流。", "立此人極，萬世東周。"]'),
('a513e32e-cd70-4c18-9c0c-9fae25086e6a','疇依  其一一','王柏','宋','宋诗','song-poetry','','[]','賢哉顔子，好學獨稱。',40,'全唐诗/poet.song.209000.json','["賢哉顔子，好學獨稱。", "既竭吾才，欲罷不能。", "不貳不遷，庶乎亞聖。", "一簞一瓢，不幸短命。"]'),
('2a779636-fead-46ab-aae6-00bfede11d9b','疇依  其一二','王柏','宋','宋诗','song-poetry','','[]','曾子雖魯，纖悉不遺。',40,'全唐诗/poet.song.209000.json','["曾子雖魯，纖悉不遺。", "吾道一貫，以魯得之。", "易簀得正，手足斯啟。", "仁爲己任，死而後已。"]'),
('24cce694-b0a6-4d83-ae09-a582f01fae01','疇依  其一三','王柏','宋','宋诗','song-poetry','','[]','至哉子思，憂道失傳。',40,'全唐诗/poet.song.209000.json','["至哉子思，憂道失傳。", "推本遺訓，中庸一編。", "提挈綱維，開示藴奧。", "無聲無臭，孰窺其妙。"]'),
('54b06231-5201-409e-842d-e8e775fc1e55','疇依  其一四','王柏','宋','宋诗','song-poetry','','[]','惟孟軻氏，雄士絕識。',40,'全唐诗/poet.song.209000.json','["惟孟軻氏，雄士絕識。", "伯仲禹功，力距揚墨。", "性善養氣，前所未聞。", "歷選諸子，實醇乎醇。"]'),
('648dae28-b036-40ee-99e6-ba3b6a337f95','疇依  其一五','王柏','宋','宋诗','song-poetry','','[]','聖道不行，自周公歿。',40,'全唐诗/poet.song.209000.json','["聖道不行，自周公歿。", "聖學不傳，由孟子卒。", "上無善治，下無真儒。", "章句訓詁，煨燼之餘。"]'),
('c0d151a6-d849-43aa-859a-d92822247c3a','疇依  其一六','王柏','宋','宋诗','song-poetry','','[]','皇宋文明，周子天畀。',40,'全唐诗/poet.song.209000.json','["皇宋文明，周子天畀。", "不由師傳，道體默契。", "建圖屬書，以覺後覺。", "上接洙泗，下開河洛。"]'),
('f09d516c-6483-4d77-aace-355184077088','疇依  其一七','王柏','宋','宋诗','song-poetry','','[]','曆紀明道，祥應兩程。',40,'全唐诗/poet.song.209000.json','["曆紀明道，祥應兩程。", "吟風弄月，有的其承。", "體用一原，顯微無間。", "惠我光明，如夜復旦。"]'),
('e42fa594-c529-415d-a3c3-8afb591ee55e','疇依  其一八','王柏','宋','宋诗','song-poetry','','[]','于時張子，崛起關中。',40,'全唐诗/poet.song.209000.json','["于時張子，崛起關中。", "虎皮端坐，多士景從。", "瞻彼洛矣，道淳所宗。", "訂頑揭牖，表表正蒙。"]'),
('c566019b-a4ec-4a03-8663-e50de17dab74','疇依  其一九','王柏','宋','宋诗','song-poetry','','[]','恭惟道統，一絕千載。',40,'全唐诗/poet.song.209000.json','["恭惟道統，一絕千載。", "何絕之久，何續之易。", "師友之盛，東南洋洋。", "曰尹曰謝，曰游曰楊。"]'),
('d2dd397f-26b9-4b98-9519-57a9ed16ae2c','疇依  其二○','王柏','宋','宋诗','song-poetry','','[]','迪予朱子，理一分殊。',40,'全唐诗/poet.song.209000.json','["迪予朱子，理一分殊。", "汛掃淫詖，煌煌四書。", "有析其精，一字萬鈞。", "有會于極，萬古作程。"]'),
('073cae73-8eb5-46a2-a38f-a2f95d916da6','疇依  其二一','王柏','宋','宋诗','song-poetry','','[]','流澤未遠，口耳復迷。',40,'全唐诗/poet.song.209000.json','["流澤未遠，口耳復迷。", "纂組斷碎，倚託媚時。", "大本斲喪，擾擾胡爲。", "淵源微矣，予將疇依。"]'),
('7d55eace-f8b9-448f-b525-1166b9aec5ef','冽井  其一','王柏','宋','宋诗','song-poetry','','[]','冽彼井泉，蓮華斯名。',40,'全唐诗/poet.song.209000.json','["冽彼井泉，蓮華斯名。", "有美一人，於焉載沈。", "夫也不二，昊天曰明。", "父之我愛，曷慰我心。"]'),
('6b698223-6c54-42b9-af05-2ffc64ecb414','冽井  其二','王柏','宋','宋诗','song-poetry','','[]','冽彼井泉，蓮華其號。',40,'全唐诗/poet.song.209000.json','["冽彼井泉，蓮華其號。", "有美一人，於焉是蹈。", "琴瑟既合，載言載笑。", "父母不允，中心悼悼。"]'),
('dc1d9260-eedd-4cf2-83bc-54a0bd330879','冽井  其三','王柏','宋','宋诗','song-poetry','','[]','有冽彼泉，弦歌之東。',40,'全唐诗/poet.song.209000.json','["有冽彼泉，弦歌之東。", "所謂伊人，宛在其中。", "我心既得，皇恤我躬。", "匪一死之，義之從容。"]'),
('2c8762ab-73dc-4841-a442-c8b3604cac74','冽井  其四','王柏','宋','宋诗','song-poetry','','[]','有冽彼泉，在弦歌內。',40,'全唐诗/poet.song.209000.json','["有冽彼泉，在弦歌內。", "所謂伊人，之死靡悔。", "人孰不死，我無昧昧。", "是心之存，炯千萬載。"]'),
('6bc2895f-9928-47ce-91d8-4447a6ec6587','和立齋對菊二歌  其一','王柏','宋','宋诗','song-poetry','','[]','秋至百芳歇，籬邊佳色團。',96,'全唐诗/poet.song.209000.json','["秋至百芳歇，籬邊佳色團。", "遥思古節士，愛此黄華蕃。", "我生千載下，恨不相同看。", "叢叢夜氣厚，曉葉千珠漙。", "中表自芳潤，對花發長歎。", "真固非素積，動色形豆簞。", "悠然露真意，猶云欲忘言。", "淵明一寸心，細嚼供晨餐。"]'),
('b32b0dca-2fdd-48b1-af43-dce9f046754a','和立齋對菊二歌  其二','王柏','宋','宋诗','song-poetry','','[]','之子歌遠遊，征車事奔逸。',120,'全唐诗/poet.song.209000.json','["之子歌遠遊，征車事奔逸。", "歸來東籬下，一洗四方色。", "靜觀草木蕃，若不與人力。", "苟無浸灌功，造化庸有忒。", "今年秋苦旱，五穀廢嘉殖。", "梅仆竹亦焦，枯芝槁蘭茁。", "一朝去酷吏，甘雨解衆惑。", "天人本無間，喜氣滿城集。", "奈何倉廩虛，一飽竟難得。", "不如菊花乾，醫方賸稱述。"]'),
('f791b22f-c17f-48c5-bcb1-517cc5934222','和暘谷春郊韻','王柏','宋','宋诗','song-poetry','','[]','一春風雨多，連日幸開霽。',108,'全唐诗/poet.song.209000.json','["一春風雨多，連日幸開霽。", "清尊酹芳菲，嘉約起予意。", "邁邁溪南國，樂只羣英萃。", "徘徊曲徑迂，老踁尚堪企。", "竹脩君子容，花向少年媚。", "俯挹百草香，尚友萬山翠。", "往事動深感，高譚出中祕。", "暮色排空來，一笑散襟袂。", "不有短長吟，寂寞此風致。"]'),
('75812853-9656-4430-afd0-175e2e687e5e','用玉成韻題秋臺詩卷','王柏','宋','宋诗','song-poetry','','[]','杳杳南風琴，洋洋大雅音。',60,'全唐诗/poet.song.209000.json','["杳杳南風琴，洋洋大雅音。", "復古心未古，難以筆力任。", "秋臺千古調，淵乎樂不淫。", "天然絕琱飾，無非情性吟。", "掩卷三歎息，式如玉與金。"]'),
('229b3912-604b-4e8e-9a17-cf9ee5913453','夜觀野舟浩歌有感','王柏','宋','宋诗','song-poetry','','[]','康衢久寂寞，擊壤音微茫。',192,'全唐诗/poet.song.209000.json','["康衢久寂寞，擊壤音微茫。", "南風啟簫韶，拜手賡明良。", "周衰二雅廢，鳳兮歌楚狂。", "楚狂已再變，三閭竟哀傷。", "俯仰千載後，嗟嗟情性荒。", "梁選尚遠思，淵明粹而莊。", "開元生李杜，我宋推蘇黄。", "宗派亦淪墜，紛紛師晚唐。", "吟骨不淳古，記魄不自强。", "雕鏤心肺苦，何曾徵宮商。", "濂翁著和澹，感興開紫陽。", "紫陽尚六義，六義興已亡。", "鄭衛日盈耳，冰炭攪我腸。", "章貢有奇士，野舟刊名章。", "古城夜酌句，正義尤洋洋。", "游談到巍蕩，百世流遺芳。"]'),
('a1f66025-8b92-4d77-ac5a-4cbd201314be','贈仙山剛公新創香林','王柏','宋','宋诗','song-poetry','','[]','佛說菩提泉，其性本澄澈。',168,'全唐诗/poet.song.209000.json','["佛說菩提泉，其性本澄澈。", "人乃無蕪穢，誰能還瑩潔。", "我觀浸碧泉，泓渟貯芳冽。", "恰如老師心，風止雲跡滅。", "憶昔著詩句，無乃太疎拙。", "彈指二十年，相看頭已雪。", "老師闢新軒，眼方頗虛徹。", "得得穴山竇，一脈引幽絕。", "清泚貫花徑，冷暖資衆啜。", "一動一以靜，誰盈復誰竭。", "水性本不殊，地勢差有別。", "即此兩水間，盡是廣長舌。", "學子來問話，當以無說說。", "但見香林香，薰蒸千萬葉。"]'),
('2626b38c-6fd7-48f8-a8d6-44bf45f651ee','宿寶峰呈玉澗','王柏','宋','宋诗','song-poetry','','[]','默成已仙去，北山久寂寞。',180,'全唐诗/poet.song.209000.json','["默成已仙去，北山久寂寞。", "豈無愛山人，時時訪林薄。", "心境不相當，丘壑自丘壑。", "誰知百年後，秀氣纔有託。", "的的盤溪孫，精光發河洛。", "神龍躍天津，鞭霆駕飛雹。", "相逢玉澗翁，筆底銀潢落。", "江湖四十年，萬象恣描摸。", "從游八九子，天才皆卓犖。", "漲起十八灘，曹溪源一勺。", "媿我局陋巷，瓢簞粗知樂。", "遥望詩壇高，勢與芙蓉角。", "掩旗仆金鼓，不敢事攻略。", "弔古得名勝，盟府定虛爵。", "派長竟先歸，白雲冒南岳。"]'),
('db2efca5-5ad0-4e5a-bdbb-fcf87164d5bf','牧歌寄謙牧翁','王柏','宋','宋诗','song-poetry','','[]','山前羣羊兒，羣羊化爲石。',156,'全唐诗/poet.song.209000.json','["山前羣羊兒，羣羊化爲石。", "山後謙牧翁，雙牛挂虛壁。", "仙佛道不同，妙處各自得。", "我來牧坡上，牧翁已牧出。", "風行麥浪高，日暖柳陰直。", "沙平草正軟，隔林數聲笛。", "試問翁牧意，著鞭還用力。", "牽起鼻撩天，蹋地四蹄實。", "渴飲菩提泉，饑來噍芻苾。", "步行顛倒騎，神光背上射。", "因悟角前後，通身白的皪。", "勿使蹊人田，毋乃失其職。", "舍策脫簑歸，人牛兩無跡。"]'),
('1228049c-0b88-42fc-9975-7634f638a878','天基節雨有感','王柏','宋','宋诗','song-poetry','','[]','歲歲天基節，晴和萬國歡。',192,'全唐诗/poet.song.209000.json','["歲歲天基節，晴和萬國歡。", "今年侯國宴，疎雨忽潸潸。", "允矣天人際，機緘妙已宣。", "聖心方感慕，雲意慘天顔。", "誰識天倫重，端爲萬化原。", "一時名未正，事事盡拘攣。", "父母惟生繼，昭昭大義存。", "節文斯二者，此外豈容干。", "在昔權臣繆，區區欲怙恩。", "私心崇義斷，强抑所當尊。", "近日劬勞報，猶形厚薄嫌。", "一言誰誤主，孝道未純全。", "此事書青史，千年不可刊。", "勿云今既往，熟視所難言。", "父母人皆有，何稱考叔賢。", "只將誠意感，各盡此心天。"]'),
('314c08fe-38e7-4e12-9dce-a824cbc60745','壽潘介岩','王柏','宋','宋诗','song-poetry','','[]','寶祐重頒曆，祥開甲子三。',192,'全唐诗/poet.song.209000.json','["寶祐重頒曆，祥開甲子三。", "一分春色滿，喜溢壽巵寬。", "去歲霑餘慶，連宵飫豆籩。", "今年東望處，紫氣護天關。", "正阻松椿祝，難忘契誼覃。", "只將生硬語，便作瓣香看。", "天不生賢數，人培厚德難。", "幾年涵養力，方到介而安。", "出處隨時義，從容最可觀。", "青雲平進步，中立了無偏。", "一解星屏紱，扁舟歸故山。", "修門無一字，已决此身閒。", "卜築遷新宇，除書動笋班。", "勤渠朱邸講，公論藹朝端。", "善類頻回首，爭先傒奏篇。", "忠嘉當有力，聖德本天涵。"]'),
('e76a46f1-39e3-4b76-b27f-def8c32e6ce6','和立齋書懷二首  其一','王柏','宋','宋诗','song-poetry','','[]','病暑已成痼，塵埃凝簡竹。',108,'全唐诗/poet.song.209000.json','["病暑已成痼，塵埃凝簡竹。", "蕭蕭北窗下，閉門惠煢獨。", "曜靈欲西邁，風露涕心目。", "仰觀牛女星，相望明河曲。", "誰能却鳳皇，共此鶩雞逐。", "美人天一方，郵音空往復。", "寥寥明月懷，翳翳談間玉。", "歡喜聞歸期，縶彼白駒谷。", "幸自有長林，尚可停鸞鵠。"]'),
('4648c975-fef2-461c-97a6-6ca3984628bf','和立齋書懷二首  其二','王柏','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','平生景風操，慷慨懷賦竹。',108,'全唐诗/poet.song.209000.json','["平生景風操，慷慨懷賦竹。", "恨無百畝地，相與種黄獨。", "只有滿架書，可寄千古目。", "何敢偭規矩，周容競追曲。", "彼不見泰山，政以鹿斯逐。", "子酌芝山泉，天運兩回復。", "應感鶴鳴章，聊以石攻玉。", "遷喬豈不佳，歲寒須入谷。", "天地何方圓，吾將叩歸鵠。"]'),
('4f416774-2081-41ea-85b1-dac9113b2940','小酌敬岩梅下和立齋韻  其一','王柏','宋','宋诗','song-poetry','','[]','化工忘慘舒，但起姑息念。',120,'全唐诗/poet.song.209000.json','["化工忘慘舒，但起姑息念。", "一冬漏陽和，未識六花片。", "屈指不十日，冉冉歲華禪。", "我聞敬岩下，梅英照清淺。", "尊酒酌嘉友，薄批明月薦。", "披圖論人物，行子戲角戰。", "回首九君詠，清賞恨疎遠。", "從今蒞新盟，談笑恣雄辨。", "多藉冰雪章，細澡塵埃面。", "歲歲臘殘時，檢舉舊公案。"]'),
('54b7ed6e-faaf-4702-9519-ce8cee490545','小酌敬岩梅下和立齋韻  其二','王柏','宋','宋诗','song-poetry','','[]','平生手種梅，不作和羹念。',120,'全唐诗/poet.song.209000.json','["平生手種梅，不作和羹念。", "其所起予者，歲寒心一片。", "孤芳以氣傳，萬物自形禪。", "暗香疎影句，知心亦已淺。", "雖以乾䕩餘，亦可清廟薦。", "今年花最蚤，思之心膽戰。", "花蚤豈不佳，當開時尚遠。", "陰陽貴順序，難與俗人辨。", "我豈事遠觀，急欲識春面。", "此意與誰論，珠璣謾堆案。"]'),
('1acd3bc3-e975-4dfe-81e9-b0c01889ff50','書隠和韻謝再答之','王柏','宋','宋诗','song-poetry','','[]','我已百念灰，只有敬賢念。',120,'全唐诗/poet.song.209000.json','["我已百念灰，只有敬賢念。", "事之云乎哉，敢分席半片。", "不思笙鶴隨，猶望衣鉢禪。", "舉杯邀杖履，同問春深淺。", "徘徊梅月下，不嗔蘋藻薦。", "公詩太過情，置我冰而炭。", "年來從心遊，琴瑟幸非遠。", "一謙生萬和，一默屈大辨。", "今日知公心，它日識公面。", "朝夕願趨隅，稽首侍香案。"]'),
('191c8a87-0f08-4462-842f-11b90a1abb3c','和立齋芙蓉觀三十韻','王柏','宋','宋诗','song-poetry','','[]','我觀神仙傳，詭幻何紛紜。',288,'全唐诗/poet.song.209000.json','["我觀神仙傳，詭幻何紛紜。", "或生歆慕意，方士爭愚君。", "政徹既多欲，仙材隔幾塵。", "澄神黜黜穢，有時繙黄庭。", "年少不我待，日月斯邁征。", "含霞飲沆瀣，聊助神氣清。", "何須超大壑，濯髮晞崑崙。", "天道有常運，過化續者新。", "長生非受命，莫使邪念興。", "澹然養至德，自可康頹齡。", "古今共一理，萬法同一心。", "世事互起滅，反覆如碁枰。", "赤松事黄帝，至今何不泯。", "安期干楚羽，對奕非邪真。", "徐公何爲者，得得捫蘿尋。", "惝怳紀一夢，浩不知涯津。", "馳神上無極，竭思下無垠。", "長吟追去古，抗論貽來今。", "於我政無益，默計空辛勤。", "不如素心友，相與尊舊聞。", "聖道無隠顯，人心有晦明。", "正論歎剝蝕，危如絲一綸。", "舉世闖月窟，何人開天根。", "浮華正焰焰，元氣方堙淪。"]'),
('a32663aa-7071-4a61-87cf-1ba5be716a7e','和伯兄新竹韻','王柏','宋','宋诗','song-poetry','','[]','叢竹太踠跧，一鞭忽伸脚。',120,'全唐诗/poet.song.209000.json','["叢竹太踠跧，一鞭忽伸脚。", "穿石作斜勢，朝宗意穆若。", "片綠吐新梢，員粉露殘籜。", "今年造化深，稚子六七作。", "羣居不嫌密，獨步豈疎略。", "是爲石笋瑞，不負歲寒約。", "清標凜三世，有倡不予酢。", "誰與共栽培，莫至風聲落。", "懷古不成寐，傷今政作惡。", "縱有題詩人，人面定非昨。"]'),
('a6237e4f-835b-4a8b-a512-e495044b9f34','和立齋荔子樓韻','王柏','宋','宋诗','song-poetry','','[]','我久抱離索，加子憂患薰。',168,'全唐诗/poet.song.209000.json','["我久抱離索，加子憂患薰。", "血氣日以耗，話別難爲情。", "之子行邁邁，征車從仁兄。", "閩嶺在何處，目斷遮行雲。", "素□播芳郁，丹荔嘗鮮新。", "重樓一以眺，千古乘桴心。", "海風駕空來，徘徊振書襟。", "遥知意軒豁，塵袂何由親。", "惟有清夜夢，栩栩踰南岑。", "曜靈倏西邁，剝啄來嘉音。", "見書如見面，瑰詞襲魚鱗。", "朋友正歡慰，喜氣騰家林。", "呼童烹露芽，蟹眼時一斟。", "是中有雋永，透入肝腸深。"]'),
('853a7c1d-2315-4e07-8df8-80a47ef325eb','和敬巖韻迓其歸','王柏','宋','宋诗','song-poetry','','[]','生涯魚上竿，世事鼠入角。',228,'全唐诗/poet.song.209000.json','["生涯魚上竿，世事鼠入角。", "民膏既煎熬，民髓復椎剝。", "上下急交征，絕口政與學。", "孔明痛桓靈，厥德修罔覺。", "自古辱與疎，其機在一數。", "歸來有嘉士，尚可理商榷。", "駕言一寸膠，救彼千丈濁。", "精義有入神，端可鼻端斲。", "趙孟自貴賤，玉女皆天渥。", "如彼角斯磋，如彼玉斯琢。", "不患公不淺，所患志不恪。", "秋陽日以暴，江漢日以濯。", "真積而力久，自見所立卓。", "庭前梅粲粲，梅下石确确。", "雲飛川泳間，俯仰自不惡。", "獨立萬物表，誰能伍齪齪。", "雨露懋蕭艾，霜風妬荃葯。", "天意孰云遠，鑒此歸意確。", "寄言順應人，大公一以廓。"]'),
('644f515d-9c1c-44f1-9bf6-1bea2fffe727','效希夷和陳北溪韻  其一','王柏','宋','宋诗','song-poetry','','[]','北溪真有道，出語涵芳鮮。',48,'全唐诗/poet.song.209000.json','["北溪真有道，出語涵芳鮮。", "覺彼羣迷句，真與梅爭妍。", "一花一太極，獨立形氣先。", "逋仙名浪得，未必知其然。"]'),
('bbd118bd-65b6-49c5-b69a-d0f827abf70b','效希夷和陳北溪韻  其二','王柏','宋','宋诗','song-poetry','','[]','甚矣天地閉，獨放一花鮮。',48,'全唐诗/poet.song.209000.json','["甚矣天地閉，獨放一花鮮。", "未論色之潔，未論香之妍。", "只於冰雪中，誰占生意先。", "萬物心自服，敢問何能然。"]'),
('b4fc5390-6631-43d1-a94c-4f3b115a7010','和立齋宿友韻','王柏','宋','宋诗','song-poetry','','[]','吾儕有何樂，同志味自長。',120,'全唐诗/poet.song.209000.json','["吾儕有何樂，同志味自長。", "天高與地下，參我人中央。", "痛掃物欲蔽，放出元明光。", "力學日不足，遊宦那可常。", "山人暌間久，歲晚歸南荒。", "會友魚貫卧，屐轉幾巽床。", "老我失此快，獨卧風雨窗。", "回思少壯時，此味曾親嘗。", "白髮真可媿，觸事方面牆。", "喚醒舊時夢，吐哺歌新章。"]'),
('5a719e56-85a7-4189-a1fc-0ee225f9fe72','高風行懷本齋','王柏','宋','宋诗','song-poetry','','[]','人皆喜君出，我獨喜君歸。',288,'全唐诗/poet.song.209000.json','["人皆喜君出，我獨喜君歸。", "君出豈不媺，事業生光輝。", "君歸亦不惡，風味高一時。", "人才有消長，世運有盛衰。", "公論不可泯，隠顯觀妍媸。", "隠者未必是，顯者豈皆非。", "遁世媿無悶，貧賤不可移。", "得時必行志，斯世相綱維。", "無悶是在我，行志未可期。", "一處特易易，一出真難持。", "利欲政滔天，四海皆瘡痍。", "世俗所榮者，君子方鄙之。", "君開青雲步，要津夫何疑。", "手揮體國略，口訥阿世詞。", "長揖羣玉府，拔足逃阱機。", "黄鵠已高舉，甕盎喧醯雞。", "苕霅有清泚，一洗京塵緇。", "故舊述間闊，松楸慰時思。", "蘭茁濯庭下，菊蕊黄東籬。", "酒熟蟹螯健，橙香鱸膾肥。", "至哉天下樂，何須卿相爲。", "解我橐中書，極深更研幾。", "聖門八字開，廣大涵精微。", "或參華山席，先天探包羲。"]'),
('e378200d-0e16-45f8-accf-265aa9137e6b','和立齋橘花韻','王柏','宋','宋诗','song-poetry','','[]','梅花已仙去，草木同蕕薰。',72,'全唐诗/poet.song.209000.json','["梅花已仙去，草木同蕕薰。", "萬物競妖冶，二氣勞氤氳。", "南服有橘隠，春風罔知聞。", "濃露浥清曉，落月籠夜分。", "玉圓太極判，蚌合開天真。", "芬芳滿宇宙，那肯媒東君。"]'),
('c2ebd0b5-e150-4ce8-aeb9-d1732fd55939','再和適莊韻','王柏','宋','宋诗','song-poetry','','[]','客從東方來，喜甚屐折齒。',120,'全唐诗/poet.song.209000.json','["客從東方來，喜甚屐折齒。", "鼎烹石乳精，談笑秋月裏。", "中有八十翁，宴坐維摩椅。", "遁澤瑚璉器，玉瓚間罍洗。", "立齋持修綆，汲汲古井水。", "參也魯依然，商聲從曳屣。", "翹首諸俊游，霹靂燒蛇尾。", "雙鸞輝九苞，翩翩奪棲枳。", "桐陽有卧龍，共蹋風雲起。", "翁當沽美酒，炰鼈膾錦鯉。"]'),
('9b97e5d1-e1a7-42cf-ab36-762d4d5eea2b','送立齋入閩哭久軒','王柏','宋','宋诗','song-poetry','','[]','雙溪秋氣深，送子臨古道。',60,'全唐诗/poet.song.209000.json','["雙溪秋氣深，送子臨古道。", "古道如掌平，四顧行人少。", "行行復行行，何日度南嶠。", "故人今已矣，未必死非好。", "世事浩無涯，愁雲黯江表。"]'),
('9b96d2e3-00f7-4d21-9c43-39f2d650b7dd','壽秋壑','王柏','宋','宋诗','song-poetry','','[]','皇天分四序，春生而秋成。',240,'全唐诗/poet.song.209000.json','["皇天分四序，春生而秋成。", "春風煥九野，秋氣呈清明。", "萬物一以實，物物含生生。", "我公秉元化，全體涵金晶。", "義概抱宇宙，智略吞羣英。", "五行互相制，自昔誰去兵。", "狂酋干帝紀，赤舄司專征。", "神謀運玉帳，靈旗繞氈營。", "韅靷鞅靽備，廣距甄角精。", "殘醜肝膽破，束手祈受盟。", "肅肅荆楚浄，湯湯江漢清。", "東西亙萬里，齊民競春耕。", "歸來輔皇極，一稔舒羣情。", "翼翼周鼎重，亹亹宸慮輕。", "前星燿垣象，德星萃神京。", "旂常偉實紀，前史辭虛聲。", "當此秋正中，角亢迎長庚。", "於赫衮繡瑞，緜緜綵綬榮。", "玉露滴鳷鵲，珥貂宣寶觥。", "陛下千萬歲，與公同太平。"]'),
('830ed264-5ae4-4a69-85f9-82af9045ee6d','送希夷之江西','王柏','宋','宋诗','song-poetry','','[]','小雨歛輕塵，秋聲壯亭驛。',108,'全唐诗/poet.song.209000.json','["小雨歛輕塵，秋聲壯亭驛。", "驅車過南浦，別懷徒襞積。", "世道一以壞，爲善不自力。", "一朝魯兩生，爲人作行色。", "后山薄命篇，竟不待它日。", "送子行復行，一步一歎息。", "誰知離索悲，有甚萬鍾失。", "此事已忘言，此情未能釋。", "有時誦吾句，或爲千里益。"]'),
('00e98884-5231-4543-acb1-0aca151e8f5c','秋熱','王柏','宋','宋诗','song-poetry','','[]','西風不力征，老火未甘退。',48,'全唐诗/poet.song.209000.json','["西風不力征，老火未甘退。", "蟬聲亂耳繁，癡蚊健姑嘬。", "一雨洗天來，不復有故態。", "天序自分明，人心其少耐。"]'),
('42643da8-bd44-4ba6-9f28-e39719873810','和立齋蹋月韻','王柏','宋','宋诗','song-poetry','','[]','我觀天壤間，何處無此月。',72,'全唐诗/poet.song.209000.json','["我觀天壤間，何處無此月。", "對月兩心同，正自欠此客。", "月清人更清，心景兩相迎。", "平生負此約，鬢影今星星。", "我有一句話，願與月同盟。", "清光無晦蝕，與德時時新。"]'),
('1ae840f3-240a-4f54-a388-c1c2024599c1','和叔崇禽聲放言','王柏','宋','宋诗','song-poetry','','[]','天以鳥鳴春，鳥聲不敢止。',132,'全唐诗/poet.song.209000.json','["天以鳥鳴春，鳥聲不敢止。", "天以人鳴道，斯人其可已。", "爾鳥固無知，喧啾亦何利。", "鼓弄枝頭晴，瀾翻林外起。", "不學九臯鳴，聲聞可止此。", "不學千仞翔，一鳴來瑞世。", "古以鳥名官，列職有理致。", "只有歸去兮，陶公不爾愧。", "人豈不如鳥，鳴則震天地。", "不鳴千聖傳，則鳴千古事。", "詩翁莫浪鳴，文武道未墜。"]'),
('b7d22a50-3c74-4734-8858-9aa0b056136a','和寬居見懷韻  其一','王柏','宋','宋诗','song-poetry','','[]','北望戲馬臺，荆榛滿中路。',84,'全唐诗/poet.song.209000.json','["北望戲馬臺，荆榛滿中路。", "英氣一何多，懷古渺難泝。", "山河腥日月，虎豹沐雨露。", "纍纍楚猴冠，異哉天所賦。", "豈無濟川才，淹留秋又莫。", "清風從何來，灑灑定吾故。", "贈我金琅玕，鑿落雙魚素。"]'),
('c2c3b47c-a433-457f-b0cb-5de61ce87c7d','和寬居見懷韻  其二','王柏','宋','宋诗','song-poetry','','[]','佳菊何青青，寂寞籬之東。',84,'全唐诗/poet.song.209000.json','["佳菊何青青，寂寞籬之東。", "濁醪二三友，一醉涵鴻濛。", "緬懷陶靖節，邁邁無遺蹤。", "誰知千載下，譜入處士宗。", "我生亦已晚，百拙勞化工。", "上無學古心，下無適俗容。", "聊自樂其樂，君子固有窮。"]'),
('38c59720-0d19-426b-976d-9f97c983791a','赤松即景','王柏','宋','宋诗','song-poetry','','[]','平生百慮懶，尚有丘壑心。',156,'全唐诗/poet.song.209000.json','["平生百慮懶，尚有丘壑心。", "佳哉二三友，歃盟同幽尋。", "壯懷豁虛曠，玄宮窮邃深。", "時方釀薄暑，萬綠張雲岑。", "新篁凝粉翠，日影篩碎金。", "瘦筇扶野步，羽扇摇清吟。", "潄齒掬清泚，雪瀑開風襟。", "脫巾挂琪樹，露頂涵重陰。", "山禽自在語，山醪隨意斟。", "物外轉栖碧，石險蒼苔侵。", "路窮不可去，半山聞語音。", "山路未爲險，世路尤𡼭嶔。", "何時侶麋鹿，結茅入深林。"]'),
('e750372d-1ea7-4870-974f-f585938309c7','和葉聖予山中韻','王柏','宋','宋诗','song-poetry','','[]','赤脚忙晨炊，掉臂會清招。',144,'全唐诗/poet.song.209000.json','["赤脚忙晨炊，掉臂會清招。", "相如僮御盛，浩然韁轡調。", "遥指白雲邊，乘興尋夷巢。", "古殿金碧悄，玄冠綵翠銷。", "怪石壯熊卧，老樹蟠龍腰。", "清陰團野色，習習生凉飆。", "懸崖斜斷處，槎木成飛橋。", "刺膚起霞暈，小小飛蚊驕。", "日長詩思渴，香冽供山瓢。", "清狂驚四座，浩氣摩丹霄。", "書岩苔礙筆，題葉攀柔條。", "語默任人意，無庸發輕嘲。"]'),
('5e1ff37d-a715-45cb-a0ef-2fc3dde23c9b','和前人小桃源韻','王柏','宋','宋诗','song-poetry','','[]','二初何如人，夫豈古隠士。',132,'全唐诗/poet.song.209000.json','["二初何如人，夫豈古隠士。", "道成遡泬寥，羊卧不再起。", "鸞鶴舞松聲，蕭騷快心耳。", "金竈清塵生，餘丹不輕委。", "我來桃源遊，直窮路所止。", "飛蘿摇春煙，素雪噴清泚。", "了無一根桃，此名安可紀。", "豈是牧羊兒，即劉阮二子。", "不然命名者，亦別有深旨。", "何時架草堂，深入此山裏。", "翛然逃世慮，鍊魄繼遐軌。"]'),
('25e47a3a-f75d-4bd6-85f6-3717591b051d','題砥齋','王柏','宋','宋诗','song-poetry','','[]','古劍蟠雙蛟，瑞景騰豐城。',144,'全唐诗/poet.song.209000.json','["古劍蟠雙蛟，瑞景騰豐城。", "耿耿涵義氣，凜凜無俗情。", "塵世三十載，世事嗟冥冥。", "當道舞狐鼠，白晝嘷山精。", "秋風清夜發，匣內鏗然鳴。", "故人耿介士，有砥靜且平。", "寄語善持保，功用真難輕。", "莫授刀錐銛，耗蝕徒欹傾。", "許我礪英芒，一抹霜花明。", "北掃京洛暗，南擊猩鼯腥。", "彈鋏倚霄漢，掌上風雲驚。", "物莫不有用，時兮非人能。"]'),
('75823ff1-248e-474f-9d13-6d6998e1423c','代壽忠王','王柏','宋','宋诗','song-poetry','','[]','天眷中興業，丁年拱慶基。',48,'全唐诗/poet.song.209000.json','["天眷中興業，丁年拱慶基。", "皇圖開一子，寶曆出三奇。", "象奏前星瑞，光依太極儀。", "一巵眉壽祝，敬和益公詩。"]'),
('63508b69-827f-41f3-83f7-f959bbc56974','立齋遊山不能偕次遁澤韻二首  其一','王柏','宋','宋诗','song-poetry','','[]','色動山行約，令人憶舊遊。',48,'全唐诗/poet.song.209000.json','["色動山行約，令人憶舊遊。", "地形雖險易，坤道自剛柔。", "路遶岩頭石，煙橫洞口舟。", "十年塵土夢，此志幾時醻。"]'),
('a3bc88cc-b884-4083-be57-d7af511cb7bb','立齋遊山不能偕次遁澤韻二首  其二','王柏','宋','宋诗','song-poetry','','[]','山人真漫浪，隨處得清遊。',48,'全唐诗/poet.song.209000.json','["山人真漫浪，隨處得清遊。", "雪瀑方爭勢，風雷不肯柔。", "詩光浮玉板，酒灩瀉瓊舟。", "一枕斜陽裏，清歡各自醻。"]'),
('0b70e768-6130-45fc-8ca5-4ced18537eab','題屏岩詩卷','王柏','宋','宋诗','song-poetry','','[]','有偉屏岩稿，溫淳擷衆芳。',48,'全唐诗/poet.song.209000.json','["有偉屏岩稿，溫淳擷衆芳。", "波瀾雖未闊，骨骼已先張。", "盡掃江湖氣，且無蔬笋香。", "若參詩本旨，却恐費商量。"]'),
('c874f80d-a9a8-4e39-bd9c-c96733ba9303','台山周詠道別五年因詩寄借韻以謝二首  其一','王柏','宋','宋诗','song-poetry','','[]','解后松齋日，曾知學共程。',48,'全唐诗/poet.song.209000.json','["解后松齋日，曾知學共程。", "心期千古遠，世味一毛輕。", "孰謂暌離久，猶垂故舊情。", "何時風月夜，得共插文盟。"]'),
('3e80bbfa-b8dc-4b75-9f1e-2534820ebc51','台山周詠道別五年因詩寄借韻以謝二首  其二','王柏','宋','宋诗','song-poetry','','[]','中處乾坤大，同時總弟兄。',48,'全唐诗/poet.song.209000.json','["中處乾坤大，同時總弟兄。", "行藏雖有間，道誼豈無情。", "欲向忙中定，先須靜處精。", "光陰如電走，慎勿騖虛名。"]'),
('805cf044-4cdf-4a3d-aaa1-a09652a3b7cd','題徐觀之字說','王柏','宋','宋诗','song-poetry','','[]','堂空一鑑懸，萬古光瀲灩。',48,'全唐诗/poet.song.209000.json','["堂空一鑑懸，萬古光瀲灩。", "彼自有盈虛，我要無虧欠。", "陰祲不能蝕，塵埃不能掩。", "只於事上觀，足爲操舍驗。"]'),
('b4bf1409-3a3d-469e-8aff-c0aaf3c9f07a','舟中和葉聖予三首  其一','王柏','宋','宋诗','song-poetry','','[]','雲欲回風勢，先埋逼曉山。',48,'全唐诗/poet.song.209000.json','["雲欲回風勢，先埋逼曉山。", "催程推路險，破冷覺杯慳。", "帆腹欣初飽，篙師相對閑。", "卧聞嚴子瀨，只在片時間。"]'),
('06e3577a-1ec6-420b-a61b-ee530326789b','舟中和葉聖予三首  其二','王柏','宋','宋诗','song-poetry','','[]','桐江波漸滑，霽色午方開。',48,'全唐诗/poet.song.209000.json','["桐江波漸滑，霽色午方開。", "香火嚴蘭若，煙霞老釣臺。", "崖高微徑險，水轉萬山回。", "欲訪先生裔，相從買一杯。"]'),
('9168d09b-8b08-494a-ac43-712fe8241c3c','舟中和葉聖予三首  其三','王柏','宋','宋诗','song-poetry','','[]','江闊風帆急，潮回沙露痕。',48,'全唐诗/poet.song.209000.json','["江闊風帆急，潮回沙露痕。", "寒林無剩葉，茅舍各成村。", "雁落煙波渺，鴉歸野色昏。", "未知孤客棹，今夜泊誰門。"]'),
('d466802a-8343-4721-9f1f-64fc4fd23635','野興','王柏','宋','宋诗','song-poetry','','[]','文字饑難煮，爲農策最良。',48,'全唐诗/poet.song.209000.json','["文字饑難煮，爲農策最良。", "興來鋤曉月，倦後卧斜陽。", "秋稼連千頃，春花醉幾場。", "任他名利客，車馬閙康莊。"]'),
('59f5fcbf-21ba-4e22-9486-486fa75fa44b','題效奇','王柏','宋','宋诗','song-poetry','','[]','未識效奇處，得於詩卷間。',48,'全唐诗/poet.song.209000.json','["未識效奇處，得於詩卷間。", "屋邊環翠竹，窗外即青山。", "月向女牆過，煙凝老樹閑。", "不緣心匠巧，何以發天慳。"]'),
('adf4ad60-287a-40da-bdb9-0af3fa0415f3','題適莊茅亭','王柏','宋','宋诗','song-poetry','','[]','屋角園雖小，幽深隔市塵。',48,'全唐诗/poet.song.209000.json','["屋角園雖小，幽深隔市塵。", "杖藜時自適，杯酒樂天真。", "松磴規模古，茅簷日月新。", "閑花三十種，相對四時春。"]'),
('439e90b5-f5d9-41d0-8b26-56457c917709','和趙師日韻二首  其一','王柏','宋','宋诗','song-poetry','','[]','佳士溫其玉，相親意豁如。',48,'全唐诗/poet.song.209000.json','["佳士溫其玉，相親意豁如。", "窗前千箇竹，燈下一編書。", "交道無窮達，人情自密疎。", "清風明月夜，或可訪吾廬。"]'),
('96616c5a-e15e-47f1-8c89-991c11f92b32','和趙師日韻二首  其二','王柏','宋','宋诗','song-poetry','','[]','我生無燕頷，四壁笑相如。',48,'全唐诗/poet.song.209000.json','["我生無燕頷，四壁笑相如。", "門巷堪羅雀，燈窗且讀書。", "老來心事懶，貧後故人疎。", "尚有多情月，時時到子廬。"]'),
('26e17161-a9bf-4431-afea-ba75913806fb','水仙','王柏','宋','宋诗','song-poetry','','[]','翦葉葱偷巧，冰蕤獨耐寒。',48,'全唐诗/poet.song.209000.json','["翦葉葱偷巧，冰蕤獨耐寒。", "梅兄雖有伴，礬弟不同看。", "山谷詩猶在，逋仙影不單。", "玉纖捧金𧣴，誰遣慰儒酸。"]'),
('ed567df8-bf4c-4c1f-bc11-22652d2e959e','瑞香','王柏','宋','宋诗','song-poetry','','[]','呈外來香國，瓊敷四出葩。',48,'全唐诗/poet.song.209000.json','["呈外來香國，瓊敷四出葩。", "嬌姿不受暑，睡思却便茶。", "心裏藏金粟，枝頭簇紫芽。", "長安厭歌舞，還肯到儂家。"]'),
('f0cf86cc-d5a0-498c-9907-28cbb8c75871','蘭','王柏','宋','宋诗','song-poetry','','[]','早受樵人貢，春蘭訪舊盟。',48,'全唐诗/poet.song.209000.json','["早受樵人貢，春蘭訪舊盟。", "謝庭誇瑞物，楚澤擷芳名。", "蒼玉裁圭影，紫檀含露英。", "奚奴培護巧，苔蘚綠菁菁。"]'),
('b6eeb410-45b4-4c32-a2a4-5e21a2345322','梅影','王柏','宋','宋诗','song-poetry','','[]','梅花已清絕，明月忽橫窗。',48,'全唐诗/poet.song.209000.json','["梅花已清絕，明月忽橫窗。", "孤影知難並，羣花已豎降。", "淡痕開畫帳，皓色掩書缸。", "寂寞素娥冷，須臾擁去幢。"]'),
('4ba79b99-b7c2-47fd-be36-d7e9456f5ed6','自述','王柏','宋','宋诗','song-poetry','','[]','身坐衆香國，蒲團詩思新。',48,'全唐诗/poet.song.209000.json','["身坐衆香國，蒲團詩思新。", "一貧雖累我，此興未輸人。", "陋巷誰爲侶，寒窗不染塵。", "五言盟四友，筆下頓生春。"]'),
('df50a88e-e846-4a96-958c-de061db4f5e6','過故家有感','王柏','宋','宋诗','song-poetry','','[]','衣冠零落久，今日事堪傷。',48,'全唐诗/poet.song.209000.json','["衣冠零落久，今日事堪傷。", "厨起青煙薄，門關白日長。", "殘梅欹古道，枯柳卧頹牆。", "山色依然好，興衰未可量。"]'),
('9031611e-aed4-4837-98c1-7f6da1f981d3','過白鶴寺','王柏','宋','宋诗','song-poetry','','[]','小泊古蘭若，雙櫧發舊柯。',48,'全唐诗/poet.song.209000.json','["小泊古蘭若，雙櫧發舊柯。", "山光浮夜氣，柳色媚春波。", "僧類胡孫瘦，農師盜伯多。", "野人時問我，新守政如何。"]'),
('ae32249e-12b9-49d8-8015-ae171c1d5f1e','晚興','王柏','宋','宋诗','song-poetry','','[]','散髮風簷下，沈沈日漸曛。',48,'全唐诗/poet.song.209000.json','["散髮風簷下，沈沈日漸曛。", "鷹拳擒野雀，蛛網獵飛蚊。", "羣動能爲計，吾生亦謾勤。", "塵緣難著眼，晚興寄青雲。"]'),
('5e9a8275-a259-4b38-b2ff-2090a93c44c8','新愁','王柏','宋','宋诗','song-poetry','','[]','愁逐西風動，伶俜祗自憐。',48,'全唐诗/poet.song.209000.json','["愁逐西風動，伶俜祗自憐。", "家貧緣累重，學陋欠師傳。", "白髮還生矣，青氈尚杳然。", "高山流水調，何日奏朱絃。"]'),
('e1f615de-5bc3-44ae-82f6-fc005f536b00','題蟄庵','王柏','宋','宋诗','song-poetry','','[]','一蟄了千悞，心安境自寬。',48,'全唐诗/poet.song.209000.json','["一蟄了千悞，心安境自寬。", "軒昂就收歛，自在覓艱難。", "龍怕烏臺勘，人疑蕙帳寒。", "欲知舒卷意，編簡靜中看。"]'),
('a2808738-f145-44f9-9700-2284e2d59d8d','題寧庵','王柏','宋','宋诗','song-poetry','','[]','寂寂鐘魚冷，松楸蔽杳冥。',48,'全唐诗/poet.song.209000.json','["寂寂鐘魚冷，松楸蔽杳冥。", "雲侵晴路濕，衣染晚嵐青。", "天未生人物，山應銷地靈。", "何祠香一瓣，遺恨滿空庭。"]'),
('5ed1e1f1-3e02-4da9-970d-2f0368656d1a','宿倍儡店感舊','王柏','宋','宋诗','song-poetry','','[]','諸老皆仙去，遺蹤歲月深。',48,'全唐诗/poet.song.209000.json','["諸老皆仙去，遺蹤歲月深。", "主人今易姓，客子亦傷心。", "來燕傳新話，羣蛙試閙音。", "欲將興廢事，歷歷問雲岑。"]'),
('33765b5a-3c07-40d2-af9f-adb25062b33e','宿仙山浸碧軒二首  其一','王柏','宋','宋诗','song-poetry','','[]','冒黑投精剎，呼燈讀舊詩。',48,'全唐诗/poet.song.209000.json','["冒黑投精剎，呼燈讀舊詩。", "平分禪榻穩，共聽雨聲馳。", "魚鼓催行色，溪山挽故知。", "人生萍聚散，後會復何時。"]'),
('8098ca56-8e91-47f6-8278-c84b341d3466','宿仙山浸碧軒二首  其二','王柏','宋','宋诗','song-poetry','','[]','浸碧去崖谷，琅然話夙緣。',48,'全唐诗/poet.song.209000.json','["浸碧去崖谷，琅然話夙緣。", "水雲藏定力，霜雪護華巔。", "漸喜虛形槁，祗求實行全。", "曾隨癡鈍失，當已得心傳。"]'),
('3044b320-f401-4ab9-8a72-a3a3fe51dd96','遣興','王柏','宋','宋诗','song-poetry','','[]','初向坡頭下，風霜入鬢毛。',48,'全唐诗/poet.song.209000.json','["初向坡頭下，風霜入鬢毛。", "味長濡竹簡，焰短沃蘭膏。", "家與人俱瘦，年隨氣轉高。", "朱顔無藥駐，窗下勿徒勞。"]'),
('01db9031-3423-4f31-9b28-9fd7c1d538da','催雨','王柏','宋','宋诗','song-poetry','','[]','人世如居甑，驕陽不可鉏。',48,'全唐诗/poet.song.209000.json','["人世如居甑，驕陽不可鉏。", "未聞芻作狗，安得夢維魚。", "賦歛民生槁，干戈國計虛。", "安危關一飽，雨意莫躊躇。"]'),
('174d3a0c-e8c9-4643-8622-88a5f4846b2c','喜雨','王柏','宋','宋诗','song-poetry','','[]','滃鬰雙雲合，霶霶一雨通。',48,'全唐诗/poet.song.209000.json','["滃鬰雙雲合，霶霶一雨通。", "新凉驅積暑，喜氣薄高穹。", "點點含生意，聲聲起死功。", "田家雖少歉，尚可及年豐。"]'),
('fa04205f-8388-426d-a197-1f827b644d40','和汪元思喜雨韻','王柏','宋','宋诗','song-poetry','','[]','龍蟄金瓶小，神驅雨陣斜。',48,'全唐诗/poet.song.209000.json','["龍蟄金瓶小，神驅雨陣斜。", "建瓴飛素練，走澗舞生蛇。", "風使開雲磨，雷香隠砲車。", "農人有驕色，一飽不須賒。"]'),
('88777b52-2cf3-4943-8119-0af63118f75d','題抱膝庵','王柏','宋','宋诗','song-poetry','','[]','一室方方丈，名標抱膝新。',48,'全唐诗/poet.song.209000.json','["一室方方丈，名標抱膝新。", "有書宜勘古，無學可留賓。", "靜坐神明固，清談滋味真。", "傳家名刻在，長對草廬人。"]'),
('8d2f244b-66de-4b35-a162-bc8c8cd42270','冬至和適莊即事韻','王柏','宋','宋诗','song-poetry','','[]','跛躄廢人事，來投大士家。',48,'全唐诗/poet.song.209000.json','["跛躄廢人事，來投大士家。", "清談半窗月，澹坐一杯茶。", "燕豆來霜果，鴝瓶浸臘花。", "葭浮纔一日，芳思已無涯。"]'),
('b3776c6b-95ed-4271-a47e-92f6edd51b7b','汪功父聘石友','王柏','宋','宋诗','song-poetry','','[]','一片寒姿蒼玉質，久作歙江秋水骨。',244,'全唐诗/poet.song.209000.json','["一片寒姿蒼玉質，久作歙江秋水骨。", "磨瑕礱垢飽風霜，袖手南遊來楚國。", "我曾研破青煙痕，露華半勺拖玄雲。", "文理細密溫而淳，伯樂一顧空馬羣。", "癯癯好古子汪子，雅有半面如舊情。", "巧取豪奪俱不敢，聘以厚禮强委禽。", "吉日良辰新勸駕，絳帳交歡相慰藉。", "斟酌洙泗闖紫陽，大義發越添聲價。", "紫陽是渠桑梓賢，久矣驂隨輯墜編。", "會心不惜時磨研，至理神授珠瑩圓。", "我今贈君明堂一柱金書墨，霜毫冠带來蟾窟。", "楮先生者白而腴，即日相邀來覽德。", "弦歌聲裏春光半，浄几明窗風日暖。", "四友參前無間斷，俛首循循而勉勉。", "萬里一鞭塗甚坦，太極門開初未遠。"]'),
('5de09e13-8628-47ad-9168-dbb4da6e729f','和叔崇橘花韻二首  其一','王柏','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','清和景氣已非春，午陰濃處延詩人。',96,'全唐诗/poet.song.209000.json','["清和景氣已非春，午陰濃處延詩人。", "一杯佳茗沃嘉話，粲然三禮羞蘩蘋。", "洞庭手植清香發，金粟銀須照膚雪。", "薰風十里漾芳思，萬斛明珠剖胎月。", "素華綠葉騷頌中，光生南國德橫空。", "朗吟受命不遷句，對花不飲無慚紅。"]'),
('a09ec314-606c-417f-9807-6fb9e5e09958','和叔崇橘花韻二首  其二','王柏','宋','宋诗','song-poetry','','[]','厥包錫貢三千春，爲花著句曾無人。',96,'全唐诗/poet.song.209000.json','["厥包錫貢三千春，爲花著句曾無人。", "顆顆珠璣香萬斛，薰蒸天地句風蘋。", "充實先生詩興發，韻嚴不數陽春雪。", "龍蛇一紙開天荒，琅然吟破夜光月。", "炯炯后皇嘉樹中，精白任道言非空。", "秉心高潔寄清賞，世人只解歌春紅。"]'),
('16a1a099-1847-49dc-98d3-7a7c0ed57c2f','贈葉綠澗','王柏','宋','宋诗','song-poetry','','[]','有客有客訥而腴，手携數冊堯夫書。',192,'全唐诗/poet.song.209000.json','["有客有客訥而腴，手携數冊堯夫書。", "八八從而之八八，四千九十六無餘。", "小游軌革何足算，大游九戹相乘除。", "太玄洞極亦無法，更有司馬推潜虛。", "茫茫古今四海闊，動靜禍福無能踰。", "玉芪金鑰竊元命，自合抱道山林居。", "堯夫堯夫初不死，精神炯炯先天圖。", "元會運世未爲密，一畫未畫元非疎。", "自從漏泄加倍語，便覺造化無工夫。", "吾儒更欲窮造化，造化尤解窮吾儒。", "且將餘法供劇戲，君識此意廉其需。", "世人逐逐不知止，誦詩還肯安心無。"]'),
('2f0fbfde-f375-4833-9bf9-e0fcdacdaee9','和立齋番君吟','王柏','宋','宋诗','song-poetry','','[]','日月星辰天之精，山川草木地之文。',224,'全唐诗/poet.song.209000.json','["日月星辰天之精，山川草木地之文。", "本乎天者既圓象，下者何不皆方形。", "此疑千古不能决，讀盡六經無異說。", "依稀子夏微有言，譬諸草木區以別。", "草木之中操孰堅，僉曰此君耐歲寒。", "虛心直節表真勁，窮冬大雪青琅玕。", "平生正坐一圓累，未堪全德君子比。", "內圓猶是智之餘，外圓無乃德之恥。", "我聞楚東有雲仍，生來氣骨清稜稜。", "觚哉觚哉出乎類，長大益覺廉隅分。", "自從大學悟絜矩，四面正直各得所。", "獨秉重坤六二爻，斯可以爲民父母。", "厥初受命莫不然，世衰俗弊失其傳。", "商周之際斯爲盛，孤竹二子何曾圓。"]'),
('e9463ede-5cd4-428a-93fb-9a9d3622d8bf','再咏番昜方節士','王柏','宋','宋诗','song-poetry','','[]','博物君子識鑒精，包羅錯綜能成文。',224,'全唐诗/poet.song.209000.json','["博物君子識鑒精，包羅錯綜能成文。", "夫何吳興戴慶豫，慨然譜竹擬諸形。", "非草非木言甚決，品類繁夥難盡說。", "九江五嶺多逸遺，維此方君更無別。", "隠彩韜名志行堅，萬里臨邛族最寒。", "文饒携來甘露寺，聲價壓倒萬琅玕。", "眼節鬚牙如積累，四面對出莫與比。", "不有芝田紀錄詳，後世莫知深可恥。", "我聞此說亦相仍，未嘗親得見觚稜。", "江東使者返行部，招徠節士番中分。", "个个折旋皆中矩，什什來歸敬岩所。", "有匪良朋保歲寒，凜然如對齊充父。", "后山居士知其然，心事曾將詩句傳。", "老來不復人間事，寄語山翁莫削圓。"]'),
('30cf912a-8a83-4b87-8652-b482585a9aa8','和立齋蠟梅韻','王柏','宋','宋诗','song-poetry','','[]','蠟花檀暈香如梅，攛號入譜名京垓。',144,'全唐诗/poet.song.209000.json','["蠟花檀暈香如梅，攛號入譜名京垓。", "立齋形容消息大，濃芳不受霜雪埋。", "疎影橫枝雖未足，淡淡中色攙先開。", "薰然不待詩料理，詩人無奈清香催。", "詩清香韻兩奇絕，詩香相感從何來。", "只緣人與花相似，心香灑灑俱無埃。", "坡公衣鉢何敢睨，簡齋香酒非吾裁。", "有時靜聽羣兒讀，繞樹日走數百迴。", "仰頭生意已如此，俯視百草方枯荄。"]'),
('4f2049bf-f43f-4bab-ab85-ff50ac37957b','和立齋喜雪韻','王柏','宋','宋诗','song-poetry','','[]','生意原原如襞積，陰闔陽開有繩尺。',160,'全唐诗/poet.song.209000.json','["生意原原如襞積，陰闔陽開有繩尺。", "風霜冰雪豈少思，到此自宜天地塞。", "凜然帝則亙古今，此外不知還不識。", "連年冬令太傷遲，君子憂時長皺眉。", "萬物驕矜不自持，落盡窗前年後梅。", "深山芽茁無空枝，更疑麥隴青離離。", "一夜風號陽氣服，玄冥奮威正當局。", "翦水裁花兩日飛，更撒珠璣三萬斛。", "攬柄收權應恨晚，明朝已迫東方木。", "却恐春風未肯和，顛倒天時難善俗。"]'),
('f31004d8-54d1-4937-9dd9-88db70d9620d','寄敬巖','王柏','宋','宋诗','song-poetry','','[]','泳飛堂前橘柚香，田田荷葉浮波光。',368,'全唐诗/poet.song.209000.json','["泳飛堂前橘柚香，田田荷葉浮波光。", "主人攬轡度閩嶠，驅馳端爲蒼生忙。", "天生人才不虛出，必使事與才相當。", "爾才綽綽有餘力，豈容袖手窺其旁。", "平生正坐嚴冷相，不解嫵媚相頡頏。", "前時固亦與國論，莫肯默默安周行。", "老子九百何自苦，艱難險阻須甘嘗。", "玉溪饑民昔嘯聚，至煩禁旅來張皇。", "繡衣彈壓甫三日，猩鬼屏迹消叢篁。", "露布一語不自伐，猶有忘者羞回韁。", "今年玉節蓮峰下，約束海若無驚艎。", "剽聞屬郡微有警，往往鹽子多陸梁。", "此輩未易以柔服，必至腥血膏鋒鋩。", "由來受病非一證，莫將已效誇良方。", "規模貴闊謀貴密，當以虛心來衆長。", "局面布置要合節，自有勇士爭激昂。", "堂堂元老熟戎事，幸甚赤舄歸故鄉。", "豈無惕然桑梓念，囊底餘智應恢張。", "同心相濟一堂上，誰兵誰將誰千糧。", "不然牋天啟壇鉞，老熊當道驅羣狼。", "甲兵錢穀亦分內，事機捷出真難量。", "豈予所至輒多事，老天驅入功名場。", "橘柚黄時聽好語，綠綈四輩催歸裝。"]'),
('a9faf4d7-6bd7-4b66-baad-f33756920f2b','題魁星','王柏','宋','宋诗','song-poetry','','[]','天樞之宿爲貪狼，引領三台朝帝旁。',48,'全唐诗/poet.song.209000.json','["天樞之宿爲貪狼，引領三台朝帝旁。", "典司多士擅文場，名在第一聲播揚。", "因此冰炭癡兒腸，彷彿肖象祈流光。"]'),
('d63a68be-3155-4741-bbeb-d6cc96c46620','題定武蘭亭副本','王柏','宋','宋诗','song-poetry','','[]','玉華末命昭陵土，蘭亭神蹟埋千古。',160,'全唐诗/poet.song.209000.json','["玉華末命昭陵土，蘭亭神蹟埋千古。", "率更搨本入堅珉，鹽帝歸裝投定武。", "薛家翻刻愚貴游，舊石宣和龕御府。", "胡塵橫空飛渡河，中原荆棘穴豺虎。", "維揚蒼茫駕南轅，百年文物不堪補。", "紛紛好事競新模，傾欹醜俗亡遺矩。", "如今薛本亦罕見，彷彿典刑猶媚嫵。", "清歡盛會何足傳，右軍它帖以千數。", "託言此筆不可再，慨然陳迹興懷語。", "今昔相視無已時，手掩塵編對秋雨。"]'),
('c3fbd5e6-f60f-4414-9c4f-2b4458abd3ef','和易巖兄芙蓉吟','王柏','宋','宋诗','song-poetry','','[]','大專肫肫分四氣，曜靈西征駕新霽。',208,'全唐诗/poet.song.209000.json','["大專肫肫分四氣，曜靈西征駕新霽。", "人間萬寶告成時，白帝疇功有良貴。", "后皇嘉惠放一頭，蜺旌鸞轂恣晨游。", "蜀錦步帳數千里，爛然一抹眼波流。", "玉容沐露月梳曉，翠袖蹁蹮舞微笑。", "雲舒霞卷競芳穠，照水迎風爲誰好。", "水中木末眩騷人，拒霜宜霜名字新。", "平生不識春宵暖，甘隨青女嫁花神。", "易巖胸中五千卷，景物驅歸句中鍊。", "賞花不是少年心，見花依舊少年面。", "石丁作主事難憑，子高那是夢仙瀛。", "何如醉鄉自廣大，幕天席地山爲屏。", "詩魂醒處風光轉，梅花已築受降城。"]'),
('eee5658f-14b0-4ffb-8895-9ee4d2f327c3','用易巖韻壽易巖','王柏','宋','宋诗','song-poetry','','[]','天地之氣秋惟清，清之極者爲聖人。',160,'全唐诗/poet.song.209000.json','["天地之氣秋惟清，清之極者爲聖人。", "惟皇降衷本均平，賢愚美惡氣質成。", "有偉易巖萬人英，聖涯涵泳心即經。", "人心道心惟一精，怡然融液萬理明。", "榘度迥出風塵表，視履元吉祥素考。", "義利兩關路分曉，富貴功名何足道。", "一枝綠玉暢幽聲，殷勤拜捧壽吾兄。", "明朝西現長庚星，芒寒色正占千齡。", "老而有子希世珍，一念種出無邊春。", "它年頭角昂俊聲，安車迎養雙朱輪。"]'),
('3adc315b-a2dd-46f2-81cd-6b9e7f236b28','用適莊賜韻回祝','王柏','宋','宋诗','song-poetry','','[]','大椿蟠根雙幹矗，秀色各分元氣足。',224,'全唐诗/poet.song.209000.json','["大椿蟠根雙幹矗，秀色各分元氣足。", "共占百五十二年，八千春秋從此卜。", "西方無量不可思，南華寓言不須讀。", "造化發育自無已，天根月窟互相逐。", "霜挾獰風夜推戶，日碾晴空曉烘屋。", "冰輪載魄將再弦，寶律浮葭欲飛玉。", "天公作意表弧瑞，學子分題剡牋軸。", "揆予受教自髧髦，歲月十分今已六。", "我翁早出名利塵，我翁天縱清閒福。", "眼明猶足察秋豪，脚健不肯支筇竹。", "友善堂前高揭扁，懿德道心新萬目。", "人言腕力健於虎，更需萬兔供豪禿。", "不買駝峰換清供，不買蛾眉歌壽曲。", "歲寒兄弟歲寒心，敬和長篇侑醽醁。"]'),
('c4610e2a-2d98-41e4-bce9-34460f3cc246','和遁澤武夷石乳吟','王柏','宋','宋诗','song-poetry','','[]','遁翁聲價爲時重，幾年勤學方繇統。',192,'全唐诗/poet.song.209000.json','["遁翁聲價爲時重，幾年勤學方繇統。", "麗澤門人已寂寥，衣冠奕奕皆遺種。", "當日詩編誰尚存，遜齋今幸傳聞孫。", "平生工作風刺體，近來琢句如春溫。", "靈芽來自幔亭里，貯以紗囊紅與紫。", "一掬槍旗分雅供，七碗盧仝爲驚起。", "贔屭古鼎親烹嘗，清風習習生詩腸。", "雲根不受塵土污，舌本豈带臺閣薌。", "學海茫茫了無際，一覺回頭有餘地。", "世味醲鮮多螫毒，無味之中要精嚌。", "燕閒消息已潜通，滿閣遺書須細窮。", "淡而不厭真雋永，不在松風蟹眼中。"]'),
('c86b9aeb-8b7c-41a7-bf41-1b1edeb3aef0','薰風歌代壽節齋','王柏','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','玉麟堂上歌薰風，周公分陝方居東。',288,'全唐诗/poet.song.209000.json','["玉麟堂上歌薰風，周公分陝方居東。", "蜺旌龍節更號令，長江萬里消狼烽。", "櫜鞬帕首多名將，夙興拜舞占乾象。", "紫氣浮浮軫翼間，宗星炯炯銀潢上。", "甫申飛下鼎湖山，汝陽天人未足言。", "八紘納納入經濟，一柱巖巖久具瞻。", "岧嶤陪京新命尹，虎踞龍蟠壯根本。", "關中鎮撫必蕭何，北門筦鑰須寇準。", "運量恢恢妙轉旋，一念體國心通天。", "璽書錫勞下閶闔，珥貂十輩來傳宣。", "天子令聞洽四國，令儀令色山甫德。", "江漢湯湯告厥成，衮衣歸兮式百辟。", "薰風薰風自南來，解民慍兮阜民財。", "不賡殿閣微凉句，拜手喜起明良哉。", "菁菁葑菲公猶采，世沐恩波深似海。", "春風一鶚又橫空，敝帚蕭騷價千倍。", "翹材油幙羅羣英，壽觴瀲灧難同斟。", "客星灘頭頻矯首，夜夜遥瞻南極明。"]'),
('9e0763a7-3747-40eb-960c-dc3bd0f183f1','和遁澤惠豆粟韻  其一','王柏','宋','宋诗','song-poetry','','[]','民曰同胞豈異根，萬殊皆自一本分。',64,'全唐诗/poet.song.209000.json','["民曰同胞豈異根，萬殊皆自一本分。", "燒萁舂粟不忍聽，詩翁感慨何憂勤。", "我有兒拳蓮實中，共房𧥄𧥄笑秋風。", "平鋪春色殷勤種，終鮮它年又怨公。"]'),
('e8236523-4394-4348-97d2-3ebab046c6f9','和遁澤惠豆粟韻  其二','王柏','宋','宋诗','song-poetry','','[]','秋深萬物盡歸根，五穀從來不解分。',64,'全唐诗/poet.song.209000.json','["秋深萬物盡歸根，五穀從來不解分。", "以長而食了無事，南山有種何曾勤。", "遁澤真情在句中，薄俗三歎曹劉風。", "識得異形同一氣，應無管蔡怨周公。"]'),
('837ec025-5dc3-4c2b-8e57-ad34a353ca7f','題平心堂','王柏','宋','宋诗','song-poetry','','[]','洛龜圓文錫神禹，箕子陳範畀周武。',128,'全唐诗/poet.song.209000.json','["洛龜圓文錫神禹，箕子陳範畀周武。", "九疇自天倫既敘，嚮用一以壽爲主。", "人生富貴何足數，最要康甯安厥處。", "爾其好德全付予，惟皇之極必福汝。", "君侯有德存此心，居官居家堂兩銘。", "强弱人己無留情，湛然方寸如砥平。", "藹藹庭鯉雙趨庭，指此良方垂後昆。", "信受奉行不敢輕，宜爾子孫皆千齡。"]'),
('169098c7-2caf-4b70-8861-d34008b9c5f0','和叔崇春寒韻','王柏','宋','宋诗','song-poetry','','[]','知和而和當有節，節貴得中忌超越。',80,'全唐诗/poet.song.209000.json','["知和而和當有節，節貴得中忌超越。", "造化神機豈易窺，天上不知誰理燮。", "東皇面目似非真，我聞四時皆有春。", "春來天地已交泰，肅肅羣陰豈可伸。", "金谷笙歌未嘗冷，莫張威勢嚇詩人。"]'),
('3c5b6882-560b-4bbc-8d6c-cafbffe5432b','題東邨所藏宮錦圖','王柏','宋','宋诗','song-poetry','','[]','后德相成帝業昌，不耽歌舞誇新妝。',160,'全唐诗/poet.song.209000.json','["后德相成帝業昌，不耽歌舞誇新妝。", "六宮婦式頒蠶事，職雅心耑清晝長。", "忽見雙娥理絲把，寬急對牽身勢强。", "輻輪飛轉一縷細，文茵獨坐迎微凉。", "高捲翠簾三四侶，織就五采成龍章。", "獻功不須出宮壼，手授縫人裁帝衮。", "端拱明堂萬國朝，文物聲明光四境。", "何人遇此一段奇，追記丹青描不盡。", "器用鋪張規制精，默寓經綸合繩準。", "世間畫手無此圖，疑是當年閻立本。"]'),
('320622d5-b45d-4a6f-ae3c-b62f18ca473d','賦雙松堂','王柏','宋','宋诗','song-poetry','','[]','和平堂前列四皓，雙松爲主雙檜賓。',160,'全唐诗/poet.song.209000.json','["和平堂前列四皓，雙松爲主雙檜賓。", "深山大澤不肯住，鞭霆駕雨來重闉。", "蒼髯梳風音瑟瑟，霜皮凝雪冰粼粼。", "靜有精神觀世變，悄無顔色阿緌紳。", "朱幡皂蓋幾來去，丹楹藻梲方更新。", "魏武子孫敦宿好，十八公子忻相親。", "世間靈物妙難測，一氣長存天地仁。", "巍巍堂下萬休戚，左右冷眼時笑顰。", "或然一念私欲勝，垂垂二老能相嗔。", "起居出入知所敬，願言共保千千春。"]'),
('cd43adb5-85c7-441a-93b8-7c7f4d44f3b4','侍伯兄宿履庵即事呈本老','王柏','宋','宋诗','song-poetry','','[]','朔風蕭騷霜正濃，追隨雁影來城東。',128,'全唐诗/poet.song.209000.json','["朔風蕭騷霜正濃，追隨雁影來城東。", "樓閣寶門八字啟，一超徑入青蓮宮。", "老師槌拂活潑潑，臨機一喝開盲聾。", "舌根拖地無死句，何曾一字粘虛空。", "管带忘懷聞妙義，豁然暗與吾道通。", "諸方善人忽聚散，黄昏方打齋時鐘。", "明極堂前吞箇棗，畫灰爐畔捉條龍。", "須臾八萬四千偈，盡在蒲團默坐中。"]'),
('b12cbe1c-e069-4f50-9ed4-95736f98e520','拍手行','王柏','宋','宋诗','song-poetry','','[]','五雲縹緲護天關，轝金輦寶來如山。',240,'全唐诗/poet.song.209000.json','["五雲縹緲護天關，轝金輦寶來如山。", "上有封題三道印，多是中朝清要官。", "一膏一縷盡民命，荆箠新痕蝕舊瘢。", "東麾西節步霄漢，公私赤立生意慳。", "年穀豐時無蓋藏，那禁水旱相摧殘。", "黄馘槁項卧溝壑，獾奴狼子生狂貪。", "輟耕太息鴻鵠志，乘牛讀史需時艱。", "忽如妖禽嘯清曉，泥丸初不勞驚彈。", "何人把玩張聲勢，直令聚蚋奔醯酸。", "竹兵烏合本兒戲，伍籍久蠹心先寒。", "吁嗟身世狹於掌，北望神京雙淚潸。", "國家有紀誰敢犯，濟彼德惠防民姦。", "何曾假借污暴手，病入心膂何時安。", "堂堂正氣不久熄，自古東南多造端。", "誰出華山拍手笑，袖中三尺山河寬。"]'),
('65cbe746-f913-41f1-b43b-2fd57444d249','和碩夫兄五松韻','王柏','宋','宋诗','song-poetry','','[]','重開甲子舊年華，莫問行程差不差。',64,'全唐诗/poet.song.209000.json','["重開甲子舊年華，莫問行程差不差。", "幸有數杯澆舌本，不須一筆鏤心花。", "歲無臘雪非人福，時到春風不我賒。", "兩手托天緣有氣，簞瓢陋巷也爲家。"]'),
('c437a2a5-17e6-4086-8242-b0397c27cc7e','蜀葵韻','王柏','宋','宋诗','song-poetry','','[]','亭亭弱幹裊新凉，露浥精神導太陽。',64,'全唐诗/poet.song.209000.json','["亭亭弱幹裊新凉，露浥精神導太陽。", "紫粟綠房醫士寶，黄裳紫袂道家妝。", "宗華衣錦趨炎晝，蜀本鎔金耐素傷。", "千古無人歌實德，騷人只解逐餘香。"]'),
('84820b12-9f64-425e-b944-a9c58b7ada45','和秋澗惠蘭韻','王柏','宋','宋诗','song-poetry','','[]','竹蘭臭味古來同，同處元非造化工。',64,'全唐诗/poet.song.209000.json','["竹蘭臭味古來同，同處元非造化工。", "墨竹方生秋澗上，紫蘭已到魯齋中。", "築臺移玉尊清惠，運筆揮金尚古風。", "却似高人來伴我，幽芬日日透簾櫳。"]'),
('f04023de-6b11-4e92-98ca-a4abc7f68940','和得全喜雪韻  其一','王柏','宋','宋诗','song-poetry','','[]','天道流行自有經，一冬常燠大無倫。',64,'全唐诗/poet.song.209000.json','["天道流行自有經，一冬常燠大無倫。", "臨期飛雪粗成冷，只隔明朝便是春。", "窗外曉山高積玉，夢回夜月更鋪銀。", "玄冥恰似輪臺悔，改過雖新已悞人。"]'),
('7680e8a8-8f79-403c-88c7-ff075266af65','和得全喜雪韻  其二','王柏','宋','宋诗','song-poetry','','[]','瞻彼西山紫翠間，百年遺族備艱難。',64,'全唐诗/poet.song.209000.json','["瞻彼西山紫翠間，百年遺族備艱難。", "一區濟濟雖孤立，萬物原原得靜觀。", "舉世莫知黄髮貴，何人肯伴白雲寒。", "相將共折長亭柳，况是殘梅已著酸。"]'),
('c9c6f004-b698-4e91-81a5-5c162fe5b475','贈吳晠','王柏','宋','宋诗','song-poetry','','[]','襟佩青青白面郎，未成佔畢已飛揚。',64,'全唐诗/poet.song.209000.json','["襟佩青青白面郎，未成佔畢已飛揚。", "深嫌實學規模拙，只把時文日夜忙。", "志氣崢嶸謀富貴，身心荒落敗綱常。", "他年窮達皆無據，却笑儒冠誤可傷。"]'),
('a4829477-44bc-4123-beb9-0ee7715e4ef4','和遁澤喜雨韻二首  其一','王柏','宋','宋诗','song-poetry','','[]','久欲飛山試笋車，避炎情緒未能嘉。',64,'全唐诗/poet.song.209000.json','["久欲飛山試笋車，避炎情緒未能嘉。", "讀書求道調心馬，製藥無方遣睡蛇。", "天地秋來催祭鳥，池塘雨過閙私蛙。", "病夫推枕幡然起，骨健神清眼不華。"]'),
('710b5d94-f1fe-42f4-b4df-9108d6912239','和遁澤喜雨韻二首  其二','王柏','宋','宋诗','song-poetry','','[]','葉下亭臯半月秋，風飛雷厲起雲頭。',64,'全唐诗/poet.song.209000.json','["葉下亭臯半月秋，風飛雷厲起雲頭。", "一奩返照收林樾，萬派飛泉響澮溝。", "放鄭賢侯初下令，乞靈拙士未能瘳。", "吾儕且說維魚夢，那問驅車相國愁。"]'),
('87ed5035-1fbd-4401-a4b0-c9d6bcf38584','和易巖蘭菊韻','王柏','宋','宋诗','song-poetry','','[]','小春天氣未和平，冷暖於人孰重輕。',64,'全唐诗/poet.song.209000.json','["小春天氣未和平，冷暖於人孰重輕。", "幽菊瘦蘭皆有味，凄風楚雨自無情。", "披來破衲便身穩，寫到新詩徹骨清。", "箇裏不知誰得失，薰蕕境界要分明。"]'),
('64893dd9-8608-4bc0-bf85-f958de0784a4','和易巖雪','王柏','宋','宋诗','song-poetry','','[]','豐年嘉瑞有根原，碎翦銀河倒底懸。',64,'全唐诗/poet.song.209000.json','["豐年嘉瑞有根原，碎翦銀河倒底懸。", "古有諸侯延辨孟，今無令尹訪饑袁。", "狺狺吠犬思騷楚，茂茂貞松記漆園。", "險韻忽拈真寡和，茶煙起處屈高軒。"]'),
('135f4e6c-9821-4934-a95b-0c32ab419c17','八詠新樓','王柏','宋','宋诗','song-poetry','','[]','翬飛高插女星光，可是溪山屬沈郎。',64,'全唐诗/poet.song.209000.json','["翬飛高插女星光，可是溪山屬沈郎。", "眼力拓開千里遠，樓身擡起一尋强。", "爭觀王謝新題壯，不數齊梁舊事荒。", "誰識倚闌真樂處，清風明月浪篇章。"]'),
('63fb6dea-6cb2-4a3b-82dd-3d1fc7727250','和易巖首夏韻','王柏','宋','宋诗','song-poetry','','[]','垂老東君戀舊寒，惜春情緒正孤單。',64,'全唐诗/poet.song.209000.json','["垂老東君戀舊寒，惜春情緒正孤單。", "笑它功業傳千古，還我詩書博一安。", "芍藥階前風味淺，酴醾架上典刑殘。", "勒回春色憑詩句，生意津津上筆端。"]'),
('1eda6539-9e50-4eb1-8c7d-710d140a18f8','次前人韻','王柏','宋','宋诗','song-poetry','','[]','彈冠事業耳邊新，我夢何因到紫宸。',64,'全唐诗/poet.song.209000.json','["彈冠事業耳邊新，我夢何因到紫宸。", "自古爲仁知不富，如今學道豈憂貧。", "與其鞭扑朘民髓，孰若簞瓢樂此身。", "志士不忘在溝壑，不應後世便無人。"]'),
('1841ab1e-e977-4ff0-80ef-eb95f7a9ffec','題康湖偉觀','王柏','宋','宋诗','song-poetry','','[]','蒼翠雄盤一古村，新樓面面納乾坤。',64,'全唐诗/poet.song.209000.json','["蒼翠雄盤一古村，新樓面面納乾坤。", "陰晴朝暮天容變，開闔榮枯春意存。", "萬壑精神融寶鑑，千峰氣勢拱端門。", "松楸冉冉白雲下，一醆寒泉罔極恩。"]'),
('154a7fd3-32be-447d-a270-4dfebae4dca8','寄立齋','王柏','宋','宋诗','song-poetry','','[]','團欒未久又分襟，踽踽嬛嬛老不禁。',64,'全唐诗/poet.song.209000.json','["團欒未久又分襟，踽踽嬛嬛老不禁。", "陋巷更無佳客語，殘編幸得古人心。", "熙熙農夫含生意，濟濟官僚喜德音。", "欲共功名須好漢，微陽何以勝重陰。"]'),
('bec0a8a8-7048-4485-a779-ead993c1cd87','春歸','王柏','宋','宋诗','song-poetry','','[]','春來春去果何心，靜坐焚香細細評。',64,'全唐诗/poet.song.209000.json','["春來春去果何心，靜坐焚香細細評。", "太極流行千古事，一元發育四時情。", "黄堆稼穡誰勳業，綠到桑麻已老成。", "舒慘榮枯人自異，此中生意本分明。"]'),
('d8070d24-368b-413e-aa9f-5d0110fed7aa','舉業有感','王柏','宋','宋诗','song-poetry','','[]','後世求才術太疎，三年三日判榮枯。',64,'全唐诗/poet.song.209000.json','["後世求才術太疎，三年三日判榮枯。", "消磨歲月莫知老，奔走英雄不覺愚。", "與死爲鄰猶未已，雖生在世却如無。", "聖門反在揶揄內，何敢忠言請改圖。"]'),
('916bc18b-a909-458d-b877-085fa5ad2267','和遁澤初夏韻二首  其一','王柏','宋','宋诗','song-poetry','','[]','萬古南薰與舜同，何時吹入五弦中。',64,'全唐诗/poet.song.209000.json','["萬古南薰與舜同，何時吹入五弦中。", "百年喬木支秋哨，一旦新萌長露叢。", "世事漸如宣子日，詩情猶有大王風。", "來牟絲枲新勳業，更有何人詠大東。"]'),
('f6e0d08f-f03e-48a1-b709-62fc581d1cc0','和遁澤初夏韻二首  其二','王柏','宋','宋诗','song-poetry','','[]','深深陋巷更深藏，襪線曾無一寸長。',64,'全唐诗/poet.song.209000.json','["深深陋巷更深藏，襪線曾無一寸長。", "學問不宜隨苟且，傳聞何敢喜張皇。", "一池科斗書千古，滿徑風騷竹萬章。", "此意寂寥誰與共，美人只在水之陽。"]'),
('19c2eb43-4dad-4207-921d-01dcbf6055a3','重題八詠','王柏','宋','宋诗','song-poetry','','[]','樓壓重城萬井低，星從天闕下分輝。',64,'全唐诗/poet.song.209000.json','["樓壓重城萬井低，星從天闕下分輝。", "傷心風月詩應瘦，滿眼桑麻春又肥。", "山到東南皆屹立，水流西北竟同歸。", "倚闌莫問齊梁事，斷石淒涼卧落暉。"]'),
('2a59e2a4-db1e-4152-a6b4-dffb590c2860','和易巖喜雨韻  其一','王柏','宋','宋诗','song-poetry','','[]','轉移劇暑若艱難，誰謂炎凉反掌間。',64,'全唐诗/poet.song.209000.json','["轉移劇暑若艱難，誰謂炎凉反掌間。", "狐鼠就擒元憤鬰，旄倪相慶便清閒。", "雨聲恰似政聲好，天意翻嗤詩意慳。", "一飽所關誠大矣，吾儕安得不開顔。"]'),
('407c8292-e1a8-44c0-ba5d-30b58282abf7','和易巖喜雨韻  其二','王柏','宋','宋诗','song-poetry','','[]','歊煩一轉亦何難，只在邦君念慮間。',64,'全唐诗/poet.song.209000.json','["歊煩一轉亦何難，只在邦君念慮間。", "社鼠城狐纔就縶，土龍芻狗便投閑。", "平時真見天人密，順處不疑霖雨慳。", "夢裏忽聞風力猛，定知千里破愁顔。"]'),
('41322779-d95f-48be-97b0-53bda964d80a','送馬秋山寄友人','王柏','宋','宋诗','song-poetry','','[]','赤城千古一東湖，誰肯重開太極圖。',64,'全唐诗/poet.song.209000.json','["赤城千古一東湖，誰肯重開太極圖。", "要得斯文傳氣脈，定須吾黨立規模。", "聖賢不盡七分易，天地長存三字符。", "念念服行方是學，莫將枝葉費工夫。"]'),
('297957c1-faed-4096-821e-47c745da87fc','用前韻答車玉峰','王柏','宋','宋诗','song-poetry','','[]','人物如君屹鼎湖，高山仰止我儀圖。',64,'全唐诗/poet.song.209000.json','["人物如君屹鼎湖，高山仰止我儀圖。", "講篇損益開新式，略紀刪修有定模。", "目斷交情殊恨闊，心涵古道若相符。", "去年不客東湖上，幾失人間大丈夫。"]'),
('c1fd41e4-70da-43e1-85e3-e1987330baf7','題涵古  其一','王柏','宋','宋诗','song-poetry','','[]','梅花之外竹扶疎，矮屋明窗著此癯。',64,'全唐诗/poet.song.209000.json','["梅花之外竹扶疎，矮屋明窗著此癯。", "生意多從閒處見，天機却向語中枯。", "通身總是先天易，開眼無非太極圖。", "點點若知河洛意，庖犧豈有古今殊。"]'),
('cb6e45d5-c37d-46ef-b74f-7f8f5d397f7c','題涵古  其二','王柏','宋','宋诗','song-poetry','','[]','平生意廣奈才疎，學未成時家已癯。',64,'全唐诗/poet.song.209000.json','["平生意廣奈才疎，學未成時家已癯。", "蚤慕滄洲窮廣大，晚依麗澤沃焦枯。", "先儒凜凜今如在，聖道洋洋孰與圖。", "兩字高題時仰止，千江一月幾曾殊。"]'),
('f0a06aa4-929a-450a-9033-b6685aaf0d77','和遁澤雨中韻  其一','王柏','宋','宋诗','song-poetry','','[]','梅霖博得遁翁憐，磊磊詩郵忽到前。',64,'全唐诗/poet.song.209000.json','["梅霖博得遁翁憐，磊磊詩郵忽到前。", "噀霧掃清塵外馬，瀑泉呼起耳中蟬。", "妨它種事并芒事，知是豐年或歉年。", "陋巷一瓢應易足，更無思慮且安眠。"]'),
('417f28c7-567b-48a0-abfd-51b462dbf927','和遁澤雨中韻  其二','王柏','宋','宋诗','song-poetry','','[]','一雨踰旬勢未休，微寒猶欲衣輕裘。',64,'全唐诗/poet.song.209000.json','["一雨踰旬勢未休，微寒猶欲衣輕裘。", "水精顆顆留蛛網，土脈層層起蟻樓。", "正免客車頻倒屣，莫將詩句苦埋頭。", "書生事業浩如海，鞭辟尤思友誼稠。"]'),
('e1489c98-bfda-4d52-9e7e-f0786224a9e4','和易巖韻','王柏','宋','宋诗','song-poetry','','[]','一身之外總虛名，未必虛名果有情。',64,'全唐诗/poet.song.209000.json','["一身之外總虛名，未必虛名果有情。", "詡詡交游何足恃，區區世味本來輕。", "三春已過猶無雨，四海將枯只是晴。", "利害所關天樣大，一豪得失豈難平。"]'),
('4b62d462-4a69-4412-ae97-9b0c5ab8c2b2','寄東湖諸友','王柏','宋','宋诗','song-poetry','','[]','東湖又是一年期，雅好綢繆豈不思。',64,'全唐诗/poet.song.209000.json','["東湖又是一年期，雅好綢繆豈不思。", "耳聵臂疼衰甚矣，山高水闊欲何之。", "工夫只在潜心處，端的何須對面時。", "堠子分明書八到，康莊穩步復奚疑。"]'),
('eb929ff3-87ad-475b-82dd-e2ad262d5299','和通齋密窩韻二首  其一','王柏','宋','宋诗','song-poetry','','[]','密密窩中養妙倪，恐因題扁被人知。',64,'全唐诗/poet.song.209000.json','["密密窩中養妙倪，恐因題扁被人知。", "了無聲臭誰能測，縱有神明豈足窺。", "此外不憂還不懼，於中何慮更何思。", "浩然一氣充天地，誰道吾儕老未衰。"]'),
('c101e101-9322-47f9-957e-b16402a14cb9','和通齋密窩韻二首  其二','王柏','宋','宋诗','song-poetry','','[]','密密窩中克己私，人心纔動最惟危。',64,'全唐诗/poet.song.209000.json','["密密窩中克己私，人心纔動最惟危。", "誠身有道須明善，暗室之中莫自欺。", "凜凜知風知顯處，兢兢不睹不聞時。", "聖師欲到無言地，子貢當年也未知。"]'),
('a1046edd-80dc-46f9-a757-e772fa482592','和易巖梅下韻','王柏','宋','宋诗','song-poetry','','[]','梅送清香到酒邊，東君伎倆已先傳。',64,'全唐诗/poet.song.209000.json','["梅送清香到酒邊，東君伎倆已先傳。", "稜稜梢外殊無冷，點點花中各有天。", "霜潔冰清時未正，風和日暖老相便。", "一杯適意毋空度，添一年時減一年。"]'),
('90cd0f24-2122-4652-aacd-e5b3daad15de','送趙書記二首  其一','王柏','宋','宋诗','song-poetry','','[]','相逢雖晚意無加，滿腹經綸肯浪誇。',64,'全唐诗/poet.song.209000.json','["相逢雖晚意無加，滿腹經綸肯浪誇。", "雅興屢陪郊外樂，清譚不尚酒邊譁。", "忍於柳驛攀金縷，記取梅坡嚼玉花。", "木落山空平野闊，浩然別思滿天涯。"]'),
('20771d2e-43e5-4c71-97be-b9282cad6582','送趙書記二首  其二','王柏','宋','宋诗','song-poetry','','[]','只將精識作生涯，評古論今吐粲花。',64,'全唐诗/poet.song.209000.json','["只將精識作生涯，評古論今吐粲花。", "玉潔冰清官自大，雲飛川泳吏無譁。", "偉人落落難重見，餘子紛紛未足誇。", "老我不能歌頌語，杯中須減飯須加。"]'),
('a102a4d8-5e92-40d0-b692-ce6eac2819e8','題秋臺詩卷','王柏','宋','宋诗','song-poetry','','[]','騷雅馳聲歷幾霜，駕言拙嬾擅詞場。',64,'全唐诗/poet.song.209000.json','["騷雅馳聲歷幾霜，駕言拙嬾擅詞場。", "登臺甚矣秋容澹，得句依然風骨香。", "卷盡辭窮餘古韻，筆精墨妙發潛光。", "此中境界真堪樂，枕上休貪南面王。"]'),
('8383c73b-6013-4d2b-bba1-96e64a7779c3','用希古韻送天台金吉父','王柏','宋','宋诗','song-poetry','','[]','行李西來又欲東，無情雲雨鎖長空。',64,'全唐诗/poet.song.209000.json','["行李西來又欲東，無情雲雨鎖長空。", "窗前細嚼書中味，膝上虛傳瑟外風。", "老去苦無佳客語，新來忽有賞心同。", "錢唐江上雲霄路，相對無因話月篷。"]'),
('1b8d7dc5-fa2f-406a-a541-19bbfcbb7e75','次前韻寄鄭悅齋','王柏','宋','宋诗','song-poetry','','[]','單騎衝寒發路東，只緣歸計太疎空。',64,'全唐诗/poet.song.209000.json','["單騎衝寒發路東，只緣歸計太疎空。", "三年事外多閑日，一別花間幾信風。", "出處莫期當世合，功名要與古人同。", "憑君試問真消息，應已西興喚短篷。"]'),
('366ab9a2-393f-49ee-9834-3cde0098dd37','和楊石溪璚花詩韻','王柏','宋','宋诗','song-poetry','','[]','點檢春光綠打圍，未應造化委蕪蘼。',64,'全唐诗/poet.song.209000.json','["點檢春光綠打圍，未應造化委蕪蘼。", "雖無紅紫呈新面，尚有瓊瑶戀舊枝。", "后土歸根辭帝寵，番昜名圃少人知。", "長篇寡和憑花報，豈料因花又得詩。"]'),
('ee31631f-83b8-4df8-b02c-f7a250799a6c','孟冬朔旦修翁誕辰韋軒府判寺簿同宴與三姪孫忝陪於僎介之間以紀其事','王柏','宋','宋诗','song-poetry','','[]','招徠二老冠耆英，寶鼎氤氳俎豆珍。',64,'全唐诗/poet.song.209000.json','["招徠二老冠耆英，寶鼎氤氳俎豆珍。", "南極玉繩浮列宿，西屏綵袖祝千春。", "親親同醉杯中淥，老老深推膝下仁。", "看取來年宣勸處，松椿桃李轉鴻鈞。"]'),
('4807a868-ec92-458a-89fe-a33486da09df','新堤行借山長韻呈韋軒','王柏','宋','宋诗','song-poetry','','[]','幾年麗澤道方亨，別駕重來路竟成。',64,'全唐诗/poet.song.209000.json','["幾年麗澤道方亨，別駕重來路竟成。", "由是之焉知所止，安而行處坦然平。", "疾徐先後將觀禮，作屏經營豈爲名。", "萬里修程今放步，胸中堠子自分明。"]'),
('f7973824-5eec-46e4-9dbc-f95df70ac861','仲夏游赤松有感','王柏','宋','宋诗','song-poetry','','[]','堆堆書冊畧抽頭，决意茲行不暇籌。',64,'全唐诗/poet.song.209000.json','["堆堆書冊畧抽頭，决意茲行不暇籌。", "雨觀風臺淩絕景，雲巒雪瀑壯清游。", "二皇羣石應難覓，南澗雙羊已莫求。", "訪我舊題無復有，姓名方媿倚人留。"]'),
('7fadb27b-271e-4c19-b388-c82be363aeb6','和曹西溆明月樓韻  其一','王柏','宋','宋诗','song-poetry','','[]','宣和棟宇鎮東城，平野蒼然一眺明。',64,'全唐诗/poet.song.209000.json','["宣和棟宇鎮東城，平野蒼然一眺明。", "疊嶂有情宜晚對，兩溪無奈向西傾。", "招邀風月標嚴句，麾斥雲烟醒魯楹。", "誰倚闌干來點檢，渡頭終日有舟橫。"]'),
('79d7e38a-b9b8-4505-acd8-cd71f0dd8dca','和曹西溆明月樓韻  其二','王柏','宋','宋诗','song-poetry','','[]','政聲藹藹拱和平，士悅民安訟自清。',64,'全唐诗/poet.song.209000.json','["政聲藹藹拱和平，士悅民安訟自清。", "末俗規模多簡陋，偉人事業必恢宏。", "一新庭宇蠲餘力，三肅溪山訂舊盟。", "休道人生行樂耳，詩壇融盡古今情。"]'),
('bab3f539-4528-4c3f-868c-28cc05315208','再次前韻  其一','王柏','宋','宋诗','song-poetry','','[]','一簇樓臺表郡城，月於此處最光明。',64,'全唐诗/poet.song.209000.json','["一簇樓臺表郡城，月於此處最光明。", "山摇玉彩東南上，水决金波西北傾。", "老木修容賓畫棟，女牆嚴陳護丹楹。", "西風屈指何時到，來慶黄雲萬畝橫。"]'),
('a2fa430e-bbb8-4a36-97b1-61e1b5d84d41','再次前韻  其二','王柏','宋','宋诗','song-poetry','','[]','月指山間頗不平，何須江上有風清。',64,'全唐诗/poet.song.209000.json','["月指山間頗不平，何須江上有風清。", "用之不竭詞雖侈，却道平分意未宏。", "嚴子五言終耐久，隠侯千載已寒盟。", "肯於明月相料理，定有清風不世情。"]'),
('fea0dc16-a18c-4565-b64c-a049242352ab','和喜雨韻','王柏','宋','宋诗','song-poetry','','[]','體天生物以爲心，喜讀箕疇好雨星。',64,'全唐诗/poet.song.209000.json','["體天生物以爲心，喜讀箕疇好雨星。", "我已不疑豐見斗，君今何慮井羸瓶。", "只緣報國推心赤，自是憂民感帝青。", "若旱作霖人望久，雄風那數快哉亭。"]'),
('f0118d6d-ad6c-4bc5-aae9-64c063b93b22','和無適四時賦雪梅  其一','王柏','宋','宋诗','song-poetry','','[]','蕙歇蘭消菊已乾，橫枝疎影到癯仙。',64,'全唐诗/poet.song.209000.json','["蕙歇蘭消菊已乾，橫枝疎影到癯仙。", "向來買種恨無地，我輩鍾情亦有年。", "最是愛他風骨峻，如何只喜玉姿妍。", "小園應怪無佳句，未放幽香到酒邊。"]'),
('945a017b-c32b-4049-8e77-d40b07a48098','和無適四時賦雪梅  其二','王柏','宋','宋诗','song-poetry','','[]','九人清賞尚堪誇，記得歸時月未斜。',64,'全唐诗/poet.song.209000.json','["九人清賞尚堪誇，記得歸時月未斜。", "詩卷寂寥今歲客，虬枝依舊去年花。", "仙宗屢欲編爲譜，句法深慚不著家。", "多藉孤芳相點綴，採歸筆下便光華。"]'),
('d586888e-db9b-4ec0-be46-0a8655aedd31','和無適四時賦雪梅  其三','王柏','宋','宋诗','song-poetry','','[]','滕六驅車夜叩關，起來四面失煙寰。',64,'全唐诗/poet.song.209000.json','["滕六驅車夜叩關，起來四面失煙寰。", "映書冷豔便窮巷，琢句高情動北山。", "侍立政思伊水上，風流不到灞橋間。", "須臾月上梅花冷，人與梅花相對閑。"]'),
('fe2299e3-014e-4716-b7e6-913d6c562573','和無適四時賦雪梅  其四','王柏','宋','宋诗','song-poetry','','[]','寄言青女莫來賓，聞道長安凍殺人。',64,'全唐诗/poet.song.209000.json','["寄言青女莫來賓，聞道長安凍殺人。", "應瑞豐年占尚遠，憂時君子慮方新。", "幸聞北境無他警，更喜東皇已問津。", "有客方携詩到手，天才端的是祥麟。"]'),
('dd154d8f-891b-419a-a9df-0f3dc31b7bfb','送耐翁住天柱延恩','王柏','宋','宋诗','song-poetry','','[]','換却鉗鎚過赤城，先聲知已沸騰騰。',64,'全唐诗/poet.song.209000.json','["換却鉗鎚過赤城，先聲知已沸騰騰。", "當機棒喝須端的，護法神通莫盡憑。", "脚底湧泉同瑩潔，脊梁天柱共崚嶒。", "果符鼓棹滄溟句，海角元來欠一燈。"]'),
('8de11c9b-a517-4947-95ac-74829b808eeb','南省有感','王柏','宋','宋诗','song-poetry','','[]','魁文不過欲趨新，從此相疎有幾人。',64,'全唐诗/poet.song.209000.json','["魁文不過欲趨新，從此相疎有幾人。", "箇裏未知全是命，平時無用苦勞神。", "後先難必三年事，得失同歸萬古塵。", "堪笑近來狂士計，求榮就辱太迷津。"]'),
('765378ab-da39-47d8-bf10-1466ed6ac4eb','送碩夫兄之武昌','王柏','宋','宋诗','song-poetry','','[]','年年征袖拂孤篷，飽歷風霜似有功。',64,'全唐诗/poet.song.209000.json','["年年征袖拂孤篷，飽歷風霜似有功。", "行李又謀千里外，別情多在數聯中。", "騷騷荻岸飄新白，索索楓江落冷紅。", "若遇雁音頻寄字，寒窗時欲對清風。"]'),
('4776b0d9-6082-486d-a5ca-93835698b2c6','舟中和陳子東  其一','王柏','宋','宋诗','song-poetry','','[]','幾年不蹋玉京埃，今日因何走一回。',64,'全唐诗/poet.song.209000.json','["幾年不蹋玉京埃，今日因何走一回。", "怪石怒吞寒瀨急，短篷衝破暮煙開。", "頼他清笑千餘度，否則浩歌三四杯。", "寄語逋仙詩侶至，攙先開著數枝梅。"]'),
('7fb81c67-99ee-442c-8f63-458947fa5875','舟中和陳子東  其二','王柏','宋','宋诗','song-poetry','','[]','低垂紙帳絕纖埃，冷透孤衾夢易回。',64,'全唐诗/poet.song.209000.json','["低垂紙帳絕纖埃，冷透孤衾夢易回。", "宿霧未收沙瀨黑，大江纔近水程開。", "細搜景物歸詩句，盡逐羈愁入酒杯。", "最是推篷頻問訊，岸傍未見一枝梅。"]'),
('f26e77a1-57bd-41d5-bf14-7d15fc1c334a','和曹盤齋積雨韻','王柏','宋','宋诗','song-poetry','','[]','無端淫雨挾愁來，極目丹烏安在哉。',64,'全唐诗/poet.song.209000.json','["無端淫雨挾愁來，極目丹烏安在哉。", "雲雨未闌癡不去，天容何事苦難開。", "依紅宿蝶霑新粉，點綠行蝸篆老苔。", "驚喜盤齋橫槊句，此心暫作復然灰。"]'),
('ac50f261-2722-451d-bfa2-bf1ebad8d3ae','題伯兄新樓','王柏','宋','宋诗','song-poetry','','[]','步轉層樓四望寬，了無一面欠雲山。',64,'全唐诗/poet.song.209000.json','["步轉層樓四望寬，了無一面欠雲山。", "龍分玉脊隆隆起，溪露銀波隠隠寒。", "詩思細摩僧塔峭，壯心不下女牆閑。", "仲宣百尺登高卧，未必當時得恁安。"]'),
('135f3e0b-b309-485d-8956-d063e7af5594','夜坐呈外舅  其一','王柏','宋','宋诗','song-poetry','','[]','傷春心事正無聊，短髮蕭蕭任意搔。',64,'全唐诗/poet.song.209000.json','["傷春心事正無聊，短髮蕭蕭任意搔。", "旋買茶芽清睡思，不須酒力助詩豪。", "生涯狹處飯多味，世路險時才忌高。", "我爲獨醒愁不奈，羨君萬事赴陶陶。"]'),
('25d50005-7d90-4ea2-b396-de11ba940ee5','夜坐呈外舅  其二','王柏','宋','宋诗','song-poetry','','[]','略無家具可經營，有子頑冥祕錮深。',64,'全唐诗/poet.song.209000.json','["略無家具可經營，有子頑冥祕錮深。", "歲月自催忙裏客，功名不著靜中心。", "詩非得意貧難遣，酒已忘情恨莫禁。", "坐對冰翁無可語，孤燈殘火伴清吟。"]'),
('cbbe4e3f-262d-42fc-8b92-7846b4b9315b','謝商守宋郎中寄到天柱山戶帖仍依元韻  其一','邵雍','宋','宋诗','song-poetry','','[]','商於飛到一符新，遂己平生分外親。',32,'全唐诗/poet.song.21000.json','["商於飛到一符新，遂己平生分外親。", "尤喜紫芝先入手，西南天柱與天鄰。"]'),
('92be26a5-8dc4-4736-9b50-c5dd89365ee3','謝商守宋郎中寄到天柱山戶帖仍依元韻  其二','邵雍','宋','宋诗','song-poetry','','[]','初心本欲踐臣鄰，帝里司回斗柄春。',32,'全唐诗/poet.song.21000.json','["初心本欲踐臣鄰，帝里司回斗柄春。", "今日得居天柱下，不憂先有夜行人。"]'),
('a60eff43-ef0c-409b-a501-2749f71d23c3','謝商守宋郎中寄到天柱山戶帖仍依元韻  其三','邵雍','宋','宋诗','song-poetry','','[]','不將生殺奏嚴宸，却抱煙嵐學隠淪。',32,'全唐诗/poet.song.21000.json','["不將生殺奏嚴宸，却抱煙嵐學隠淪。", "多謝史君虛右席，重延天柱一山人。"]'),
('2c7066b2-4baa-4b55-b85e-f1debdf83d2b','謝商守宋郎中寄到天柱山戶帖仍依元韻  其四','邵雍','宋','宋诗','song-poetry','','[]','一簇煙嵐鏁亂雲，孤高天柱好棲真。',32,'全唐诗/poet.song.21000.json','["一簇煙嵐鏁亂雲，孤高天柱好棲真。", "從今便作西歸計，免向人間更問津。"]'),
('5ac09b6b-eb6d-4869-81d9-020905e9db94','謝商守宋郎中寄到天柱山戶帖仍依元韻  其五','邵雍','宋','宋诗','song-poetry','','[]','無成麋鹿久同群，占籍恩深荷史君。',32,'全唐诗/poet.song.21000.json','["無成麋鹿久同群，占籍恩深荷史君。", "萬古千今名與姓，得隨天柱數峯存。"]'),
('5415f918-72fe-4ca2-b65a-7ff9b8dc6fa2','寄商守宋郎中','邵雍','宋','宋诗','song-poetry','','[]','初返洛城無限事，閑人體分似相違。',32,'全唐诗/poet.song.21000.json','["初返洛城無限事，閑人體分似相違。", "如今一向覺優逸，却類商顔嘯傲時。"]'),
('83790221-d84c-4110-b1d0-190c1e549ace','小圃睡起','邵雍','宋','宋诗','song-poetry','','[]','門外似深山，天真信可還。',48,'全唐诗/poet.song.21000.json','["門外似深山，天真信可還。", "軒裳奔走外，日月往來間。", "有水園亭活，無風草木閑。", "春禽破幽夢，枝上語綿蠻。"]'),
('83198b11-d5a0-416a-8f8d-df150793a7ac','遊山三首  其一','邵雍','宋','宋诗','song-poetry','','[]','城邑久居心自倦，闉闍纔出眼先明。',64,'全唐诗/poet.song.21000.json','["城邑久居心自倦，闉闍纔出眼先明。", "龍門看盡伊川景，女几聽殘洛水聲。", "太室觀餘紅日旭，天壇望罷白雲生。", "此身已許陪真侶，不爲錙銖起重輕。"]'),
('9467e0a1-43ff-467f-b108-254be5a4cb06','遊山三首  其二','邵雍','宋','宋诗','song-poetry','','[]','春盡登臨正得宜，人情天氣兩融怡。',64,'全唐诗/poet.song.21000.json','["春盡登臨正得宜，人情天氣兩融怡。", "泛舟伊水風迴夜，垂釣溪門月上時。", "逸興劇憑詩放肆，病軀唯仰酒扶持。", "浮生日月無多子，忍向其間更斂眉。"]'),
('4f26d6df-442b-47eb-ad05-a53b9ba65a9f','遊山三首  其三','邵雍','宋','宋诗','song-poetry','','[]','樂則行之憂則違，大都知命是男兒。',64,'全唐诗/poet.song.21000.json','["樂則行之憂則違，大都知命是男兒。", "至微功業人難必，儘好雲山我自怡。", "休憚煙嵐雖遠處，且乘筋力未衰時。", "平生足外更何樂，富貴榮華過則悲。"]'),
('d846beb4-c0fd-4143-a576-9b17ce03abe2','二色桃','邵雍','宋','宋诗','song-poetry','','[]','施朱施粉色俱好，傾國傾城艷不同。',32,'全唐诗/poet.song.21000.json','["施朱施粉色俱好，傾國傾城艷不同。", "疑是蕊宮雙姊妹，一是俱肯嫁春風。"]'),
('1cd2a494-d56d-4d03-a80a-61a65a5623de','登山臨水吟','邵雍','宋','宋诗','song-poetry','','[]','山有喬峯水有濤，未能容屐豈容舠。',64,'全唐诗/poet.song.21000.json','["山有喬峯水有濤，未能容屐豈容舠。", "非無仁智斯爲樂，少有登臨不憚勞。", "言味止知甘膾炙，語真誰是識瓊瑶。", "自慙不盡人才處，長恨今人論太高。"]'),
('8aa6898b-8791-4fa2-b0d3-8c11357a005f','謝富丞相招出仕二首','邵雍','宋','宋诗','song-poetry','','[]','相招多謝不相遺，將謂胸中有所施。',128,'全唐诗/poet.song.21000.json','["相招多謝不相遺，將謂胸中有所施。", "若進豈能禁吏責，既閑安用更名爲。", "願同巢許稱臣日，甘老唐虞比屋時。", "滿眼清賢在朝列，病夫無以繫安危。", "欲遂終焉老閑計，未知天意果如何。", "幾重軒冕酬身貴，得似雲山到眼多。", "好景未嘗無興詠，壯心都已入消磨。", "鵷鴻自有江湖樂，安用區區設網羅。"]'),
('176ae720-fb20-4c40-90ea-c11159982af8','答人語名教','邵雍','宋','宋诗','song-poetry','','[]','開闢而來世教敷，其間雄者號真儒。',64,'全唐诗/poet.song.21000.json','["開闢而來世教敷，其間雄者號真儒。", "修身有道名先覺，何代無人達奧區。", "煥若丹青經史義，明如日月聖人途。", "鯫生涵泳雖云久，天下英才敢厚誣。"]'),
('4eca7cd6-bc4b-4ec3-8b66-73f7042aa276','送王伯初學士赴北京機宜','邵雍','宋','宋诗','song-poetry','','[]','丈夫志氣蓋棺定，自有雄圖繫重輕。',64,'全唐诗/poet.song.21000.json','["丈夫志氣蓋棺定，自有雄圖繫重輕。", "去路不能無感舊，到官爭忍便忘情。", "閑時語話貴精密，先事經營在太平。", "誰謂禦戎無上策，伐人謀處不須兵。"]');
